-- Poems batch 341
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('af596647-0de7-47d8-a74b-f4c5c4453213','和縉雲守關彥遠浮山作','晁補之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','廣陵形勝昔所聞，崑岡作軸江爲門。',263,'全唐诗/poet.song.63000.json','["廣陵形勝昔所聞，崑岡作軸江爲門。", "西來蜀道從萬里，伏堆藏阜爭崩奔。", "盤挐蹙踏得江住，精鐵一畝巋然存。", "半潛屋牖半出戶，鼉龜見背熊羆蹲。", "我行平地是絕頂，歎息但以指爪捫。", "誰言一水限南北，壅遏勢極逾騰騫。", "不然安得江南之山踴躍出，中流浮玉猶崷崒。", "操權高視競瓜分，島夷索虜何煩述。", "木蘭水調更淒涼，延和小語尤蒼猝。", "周公卜雒貴坦平，亦言有德易以興。", "真人龍飛狐兔窘，御營周塹壓蕪城。", "大明寺中老竹在，九曲池上新荷生。", "君胡聞此不數往，地中頑礦煩嘲評。", "自言家世西湖側，慣聞洗土開南屏。", "欲空息壤發幽秘，河曲定笑勞精誠。", "君不見珊瑚玲瓏石上吐，海底有山那可睹。"]'),
('6f940951-78ba-40ec-b81d-50345518fe77','試院求李唐臣畫','晁補之','宋','宋诗','song-poetry','','[]','有客携來白團扇，看君畫出翠微峰。',64,'全唐诗/poet.song.63000.json','["有客携來白團扇，看君畫出翠微峰。", "忽然陂水變陰霧，便有松林吹晚風。", "松林陂水靜何極，何處歸舟天際識。", "韋侯直榦儻不難，杜陵東絹那能惜。"]'),
('e88bd5d9-eb2e-4969-b149-b7287f0033ee','黄河','晁補之','宋','宋诗','song-poetry','','[]','黄河齧小吳，天漢失龜鼈。',60,'全唐诗/poet.song.63000.json','["黄河齧小吳，天漢失龜鼈。", "靈原潭下藕爛死，只有菖蒲不生節。", "白馬橋邊迎送胡，冀州斷道無來車。", "新隄築得高嵽嵲，舊隄杵聲未可絕。"]'),
('c7b7091b-bb88-4af6-996b-626fa18b2dbd','酬李唐臣贈山水短軸','晁補之','宋','宋诗','song-poetry','','[]','大山宮，小山霍，欲識山高觀石脚。',250,'全唐诗/poet.song.63000.json','["大山宮，小山霍，欲識山高觀石脚。", "大波爲瀾，小波爲淪，欲知水深觀水津。", "營丘於此意獨親，杜侯所與復有人。", "不見李侯今五載，苦向營丘有餘態。", "齊紈如雪吳刀裁，小毫束筍縑囊開。", "經營初似雲煙合，揮灑忽如風雨來。", "蒼梧泱漭天無日，深巖老樹洪濤入。", "榛林闇漠猨狖寒，苔蘚侵淫螺蚌溼。", "紛紛禽散江干沙，有風北來吹蒹葭。", "前洲後渚相隨沒，行子漁人歸徑失。", "李侯此筆良已奇，我聞李侯家朔垂。", "跨河而北寧有之，曷不南遊觀禹穴。", "梅梁鏁澀萍滿皮，神物變化當若斯。", "元君畫史雖天與，我論絕藝無今古。", "張顛草書要劍舞，得意可無山水助，他日李侯人益慕。"]'),
('d171fece-4786-4bec-b38c-1506fd3eb5c4','題惠崇畫四首  其一','晁補之','宋','宋诗','song-poetry','','[]','東風回，江上渚，何處來，雙白鷺。',48,'全唐诗/poet.song.63000.json','["東風回，江上渚，何處來，雙白鷺。", "灼灼岸間桃，依稀蘭杜苗。", "一銜湍瀨鱗，一下青林梢，瀟湘綠水春迢迢。"]'),
('0a449fb3-a16d-49f0-a03f-9673d152f225','題惠崇畫四首  其二','晁補之','宋','宋诗','song-poetry','','[]','老柳無嘉色，紅蕖羞脈脈。',48,'全唐诗/poet.song.63000.json','["老柳無嘉色，紅蕖羞脈脈。", "宛在水中洲，雙鵝羽蒼白。", "何須玩引頸，顛到寫經墨。", "惟應一臨流，當暑袗絺綌。"]'),
('7e38934b-fdc7-4fca-bb7e-a0711100dace','題惠崇畫四首  其三','晁補之','宋','宋诗','song-poetry','','[]','一雁孤風乍臨渚，兩雁將飛未成舉，三雁群行依宿莽。',40,'全唐诗/poet.song.63000.json','["一雁孤風乍臨渚，兩雁將飛未成舉，三雁群行依宿莽。", "蘆花已倒江上風，雲間分飛那可同。"]'),
('3804dd2e-9fb5-470f-a99e-327ac33c57a7','題惠崇畫四首  其四','晁補之','宋','宋诗','song-poetry','','[]','天高靄靄雲昏，江闊霏霏雪繁。',56,'全唐诗/poet.song.63000.json','["天高靄靄雲昏，江闊霏霏雪繁。", "渚下鴨方遠泛，枝間雀不聞喧。", "鄙夫此志相依，生涯稊稗同微。", "欲具沙邊短艇，波濤歲晚人稀。"]'),
('754ff065-9761-43f1-aeab-5075a09f457a','擬樂府十二辰歌','晁補之','宋','宋诗','song-poetry','','[]','鼷鼠食牛牛不知，牛不願騂而願犂。',96,'全唐诗/poet.song.63000.json','["鼷鼠食牛牛不知，牛不願騂而願犂。", "虎噫來風皮見藉，兔狡宅月肩遭胹。", "欲兆幽烽二龍死，獨微晉澤一蛇悲。", "失馬吉凶方聚門，亡羊臧穀未宣分。", "沐猴冠带去始愜，木雞風雨漠何聞。", "不須皎皎吠蜀狗，阮子與豬同酒樽。"]'),
('92fe0ba5-853b-455d-a1a3-07e5f911099d','二十八舍歌','晁補之','宋','宋诗','song-poetry','','[]','戎菽有角原桑黄，客愁唧嘖聞扈亢。',208,'全唐诗/poet.song.63000.json','["戎菽有角原桑黄，客愁唧嘖聞扈亢。", "轉蓬無氐行役晚，蟋蟀在房思婦惋。", "男兒有心事弧矢，十年風光隨馬尾。", "長鬚舂米婢借箕，斗酒爲君聊解頤。", "誰憐長夜飯牛苦，安能卧泣羞兒女。", "平生未入君此室，一廬翛然四壁立。", "文章奎躔動圓天，貧有餘富黔婁賢。", "功名不羞爛羊胃，滅昴擒胡未能計。", "誰能簡畢老此生，不用諏觜招忿爭。", "世事參商君此行，桂酒椒漿石井美。", "山鬼幽篁衣薜荔，暮江老柳繫歸船。", "蛟宮涵星動深淵，張帆自慣夕風恬。", "九折摧輪鵠翼短，他年君車當軫轉。"]'),
('218b3d8e-dc45-4376-8cab-96f180746815','行路難和鮮于大夫子駿','晁補之','宋','宋诗','song-poetry','','[]','贈君珊瑚夜光之角枕，玳瑁明月之雕床。',98,'全唐诗/poet.song.63000.json','["贈君珊瑚夜光之角枕，玳瑁明月之雕床。", "一繭秋蟬之麗縠，百和更生之寶香。", "穠華紛紛白日暮，紅顔寂莫無留芳。", "人生失意十八九，君心美惡那能量。", "願君虛懷廣末照，聽我一曲關山長。", "不見班姬與陳后，寧聞衰落尚專房。"]'),
('bfb729f2-0ed9-435b-88c8-744b905cb78f','跋遮曲','晁補之','宋','宋诗','song-poetry','','[]','君不見魯中羣兒歌跋遮，跋遮跋遮何語耶。',201,'全唐诗/poet.song.63000.json','["君不見魯中羣兒歌跋遮，跋遮跋遮何語耶。", "吳歈越吟初不省，恐自塞北傳胡笳，跋遮胡爲樂中華。", "試歌河漲水漸車，河中耕泥春種麻。", "麻生三歲不開花，腰菱兩角黑如鴉。", "漁父笑且語，誰能跋遮舞。", "君不見前年大旱河草黄，草中魚子化飛蝗。", "又不見往年大雨雨决渠，渠中朽瓜生老魚。", "蝗飛食場穀，擊鼓煩趁撲。", "我家家具如筍束，今年梁山撓濁淤，兒無鋤麻姑來漁。", "荷鋤往賣鋤，買網空市無。", "丁丁斲船斲屋櫨，艇子如星喚施罛。", "夜唱跋遮曲，羣鳴起白鳬。"]'),
('b487ac8d-9e8a-48b3-be85-a38acb7ed71e','長安行贈郭法曹思聰','晁補之','宋','宋诗','song-poetry','','[]','越羅作衫烏紗幘，長安青雲少年客。',152,'全唐诗/poet.song.63000.json','["越羅作衫烏紗幘，長安青雲少年客。", "梁門門西狹斜陌，飛閣氤氳多第宅。", "南威十五桃花色，簫管哀吟動魂魄。", "銀槽壓酒傾琥珀，青絲絡頭飛赭白。", "韓狗胡鷹快多獲，少年意氣區中窄。", "金昆玉季盈十百，君獨飄翩異風格。", "十歲鉛丹事書冊，豈徒新豐困寒阨。", "能犯龍頭請恩澤，送君此行無愴惻，努力功名傳烜赫。", "它年尋我吳山側，躑躅盈山禽磔磔。"]'),
('8c0b2ce1-2e80-48f1-aeba-e33b19067470','悲來行哭石起職方','晁補之','宋','宋诗','song-poetry','','[]','悲來乎石君，吾何悲夫，斯人婉兮河之津。',312,'全唐诗/poet.song.63000.json','["悲來乎石君，吾何悲夫，斯人婉兮河之津。", "厖眉白面照青春，朱紱斯煌映路塵。", "翩翩者驥銀鞍新，東來奇意安所伸，大野既潴唯赤墳。", "穀垂穎，麻敷芬，亡逋來復瓦鱗鱗，高堂擊鮮會衆賓。", "賓起舞，君欣欣，何人末至居客右，西郭之一儒迂且貧。", "迂且貧，自隗始，能招劇辛致樂毅，四方遊士爭來奔。", "戶內光儀亦可論，大息拖縉紳。", "中息氣氤氳，小息秀眉目，天上青秋雲。", "朱旗畫舸長隄曲，去時簫鼓黄塵覆。", "無復當年子産歸，至今人作嬰兒哭。", "西郭之一儒，無事門生苔，久雨足不行官街。", "常時門前車馬客，舊雨自來新不來。", "聽我陳，張叔卿，孔巢父，皆隠淪，無人汲引長饑辛。", "日午不出開衡門，前侯後相安敢論，憂殺口間縱理紋。", "長慟吾邦對遺跡，耿耿一心誰我識。", "徐君已死劍不忘，心已許君那復惜。"]'),
('d64201d3-b8de-4189-b330-5517332a3b23','鸞車引','晁補之','宋','宋诗','song-poetry','','[]','推鸞車，伐鼉鼓。',144,'全唐诗/poet.song.63000.json','["推鸞車，伐鼉鼓。", "從帝子，迎天女。", "天女喜，立龍旂。", "馮小寶，光陸離。", "雲斑斑，覆銅山。", "新城鳴鴂如乳烏，飛來爲爾棲青梧。", "控鶴府令雲衣裾，僕射竄死令公誅。", "婦懼兒無呼，兒呼驚索胡。", "宜都內人立次且，手擎何物金唾壺，請爲大家畫長圖。", "徐公子，譁且止，卿無來，明堂屢舞覆龍盃。", "覆盃之傍戲大鼠，卿欲投之梁公懼。"]'),
('e968481e-df31-420b-95c1-f430586d9b5b','贈戴嗣良歌時罷洪府監兵過廣陵爲東坡公出所獲西夏刀劍東坡公命作','晁補之','宋','宋诗','song-poetry','','[]','三郎少日如乳虎，代父搏賊驚山東。',304,'全唐诗/poet.song.63000.json','["三郎少日如乳虎，代父搏賊驚山東。", "硬弓長箭取官職，自說九戰皆先鋒。", "將軍拳勇饋不繼，痛惜靈武奇謀空。", "城頭揶揄下俯走，壯士志屈羞填胸。", "平生山西踏霜雪，洪府下溼號兒童。", "聞名未識二十載，初見長揖東坡公。", "銳頭短後凜八尺，氣似飲井垂檐虹。", "只令不語當陣立，望見已是千夫雄。", "往年身奪五刀劍，名玉所擐犀札同。", "晨朝携來一府看，竊指私語驚庭中。", "紅粧擁坐花照酒，青萍拔鞘堂生風。", "螺旋鋩鍔波起脊，白蛟雙挾三蒼龍。", "試人一縷立褫魄，戲客三招森動容。", "東坡喜爲出好礪，洮鴨綠石如堅銅。", "收藏入匣人意定，蛾眉稍進琉璃鍾。", "太平君子尚小毖，戒懼邾小毋荓蜂。", "舞干兩階庶可睹，跳空七劍今何庸。", "我爲蘇公起揚觶，雅歌緩带聊堪同。", "從公請礪歸作硯，聞公嘗諫求邊功。"]'),
('ef928976-915a-4c8a-a9c4-d658a7e975e8','秋夜古風','晁補之','宋','宋诗','song-poetry','','[]','瑶池始波縣圃風，鄧林飛葉雲攪空。',192,'全唐诗/poet.song.63000.json','["瑶池始波縣圃風，鄧林飛葉雲攪空。", "人間櫟社幾黄落，曉窗洗黛悲青銅。", "常嗟彭祖悔杖晚，不見王母桃花紅。", "安知帝怒削龍伯，輿嶠已沒歸墟中。", "楚人方復感時節，申旦不寐同秋蟲。", "虛堂氣入枕簟肅，熟寐不復聞嗈嗈。", "大言身塞不得仰，了語無異鴻毛烘。", "天如旋磨人蟻却，更千萬日勞何功。", "漢南種柳人笑爾，江潭悽愴彫形容。", "小樓遐觀午夜闃，凉月不盡山無窮。", "一身逆旅過萬物，千古昨夢如驚蓬。", "胡床收慮暫一息，杲杲已上扶桑東。"]'),
('e90fe6a8-efcc-492b-a84b-67939581aada','苕霅行和於潛令毛國華','晁補之','宋','宋诗','song-poetry','','[]','苕溪清，霅溪綠，溪水灣環繞天目。',166,'全唐诗/poet.song.63000.json','["苕溪清，霅溪綠，溪水灣環繞天目。", "山間古邑三百家，日出隔溪聞打衙，長官長髯帽烏紗。", "不曾執板謁大尹，醉卧紫蘭花影斜。", "紫蘭花開爲誰好，年年歲歲溪南道。", "不見西陵白髮人，荆江夜雪唱陽春。", "陽春絕唱和者寡，客醉聞之雙淚灑。", "夜來魂夢海中山，縹緲雲濤煙浪間。", "雲濤煙浪不可渡，睡覺秋風落桐樹。", "秦吉了，秦吉了，言語無人會。", "無人會得奈君何，且向紫蘭花下醉。"]'),
('c9e7c1c0-7fc9-489b-8134-5a50600f28cc','冤朐路','晁補之','宋','宋诗','song-poetry','','[]','棠梨葉戰風騷騷，紙錢窸窣鳴空郊。',88,'全唐诗/poet.song.63000.json','["棠梨葉戰風騷騷，紙錢窸窣鳴空郊。", "背人獨鳥歸寒巢，予亦投村指橫橋。", "茅檐霜月照征袍，夜冷不寐聞狐嘷。", "悼我爲生良已勞，兩手如龜髀肉消。", "青樓公子燒蘭膏，雪壓屋倒飲方豪，睡覺三竿紅日高。"]'),
('f1a2d70b-c6a8-4956-8350-43a3fee10a32','芳儀怨','晁補之','宋','宋诗','song-poetry','','[]','金陵宮殿春霏微，江南花發鷓鴣飛。',323,'全唐诗/poet.song.63000.json','["金陵宮殿春霏微，江南花發鷓鴣飛。", "風流國主家千口，十五吹簫粉黛稀。", "滿堂侍酒皆詞客，拭汗爭看平叔白。", "後庭一曲時事新，揮淚臨江悲去國。", "令公獻籍朝未央，敕書築第優降王。", "魏俘曾不輸織室，供奉一官奔武彊。", "秦淮潮水鍾山樹，塞北江南易懷土。", "雙燕清秋夢柏梁，吹落天涯猶並羽。", "相隨未是斷腸悲，黄河應有却還時。", "寧知翻手明朝事，咫尺人生不可期。", "蒼黄三鼓滹沱岸，良人白馬今誰見。", "國亡家破一身存，薄命如雲信流轉。", "芳儀加我名字新，教歌遣舞不由人。", "採珠拾翠衣裳好，深紅退盡驚胡塵。", "陰山射虎邊風急，嘈雜琵琶酒闌泣。", "無言遍數天河星，只有南箕近鄉邑。", "當時千指渡江來，同苦不知身獨哀。", "中原骨肉又零落，寄詩黄鵠何當回。", "生男自有四方志，女子那知出門事。", "君不見李君椎髻泣窮年，丈夫飄泊猶堪憐。"]'),
('c1c20bc3-0edf-41d8-a974-ac9e5f2fbf2f','五丈渠','晁補之','宋','宋诗','song-poetry','','[]','五丈渠，河水齧堤三里餘。',160,'全唐诗/poet.song.63000.json','["五丈渠，河水齧堤三里餘。", "懸流下噴水渤潏，訛言相驚有怪物。", "濼東漁子浮兩舠，清晨徑流雙鬣搖。", "驚人跳起橫觸島，大鱘十尺長夭矯。", "殺之信宿不敢言，並村稍稍聞者諠。", "伐鱗封肉擔揭去，兩日一村貓犬飫。", "夜來水泛州西原，青青百頃白波翻。", "里巫推變咎漁子，豫且賊神實爲此。", "此邦一年不穀食，賣魚取錢當常職。", "聞道相家口，津人無敢憑。", "大魚死，小魚靈。"]'),
('230d1a0b-a8ce-4c4f-a996-976a986f0c55','賈碩秀才得兩圭有邸','晁補之','宋','宋诗','song-poetry','','[]','混沌既鑿元氣痡，鴻源滔天堯曰吁。',272,'全唐诗/poet.song.63000.json','["混沌既鑿元氣痡，鴻源滔天堯曰吁。", "羽淵之化三足逋，玄圭告功聞禹書。", "姚虞班器奔九區，塗山合瑞群辟趨。", "三朡肆伐夏寶俘，下逮血祭仍疈辜。", "饗有明德繄玉如，霍山屬之醫無閭。", "裂崖剖璞陳璠璵，追琢出美山爲虛。", "兩圭禮地四望俱，寸尺可識形可圖。", "緡城之西物色古，霹靂野火燒牆堵。", "大氓築室動千杵，奔泉啟鍤幽奇睹。", "陰溪埋冰剝寒土，濃氛却埽孤月吐。", "森然𥈭立疑未舉，熒熒幽光射敗筥。", "鄰人進說田父怖，張伯不敢私自取。", "初來畫地爲予語，邸圓中規圭合矩。", "瓌奇未可一二數，嬴顛劉蹶分莽鹵。", "禮嚴登降謹仰俯，牲玉不加隨豆簠。", "餼羊之存良小補，此寶豈徒周石鼓。", "酆城尺鐵尚可神，老虯躍水生雷雨。"]'),
('290d674d-2ecc-4616-8683-81a1adc93961','閻子常携琴入村','晁補之','宋','宋诗','song-poetry','','[]','閻夫子，通古今，家徒四壁猶一琴。',181,'全唐诗/poet.song.63000.json','["閻夫子，通古今，家徒四壁猶一琴。", "今年二月雨霖霪，喜君壠麥如人深。", "屋間幽默咸池音，高山流水我非聽，聽我說君辛苦吟。", "薛老村西十里地，旱日燎原無柳林。", "芒鞋曳杖逐鐮籠，當午未食饑燒心。", "芸芸麥田翻黄波，蝻蟲盤穗如蝸螺。", "麥未收打催種豆，屋下跡少田間多。", "閻夫子，時我過，我與夫子良同科。", "四體雖勤口餔衆，煮豆然萁窮奈何。", "人謂君琴語辛苦，此曲無乃傷天和，君不見夫子宋圍不糝猶弦歌。"]'),
('343353fd-fd4e-486d-8f95-5acb80f07e3b','贈余樗年試院作','晁補之','宋','宋诗','song-poetry','','[]','平生車軌周四方，結交童齔老相忘。',344,'全唐诗/poet.song.63000.json','["平生車軌周四方，結交童齔老相忘。", "異哉余子久彌芳，吳人猶記稱周郎。", "河豚入網荻芽長，宜興罨畫煙水蒼。", "風雩春服真少狂，不愧戴崇升後堂。", "橫戈筆陳倒千槍，叔鸞獨步禹出羌。", "世儒膠擾何足臧，說食不救饑求糧。", "瞥思振衣千仞岡，空林無人一繩床。", "五車純束不在旁，欲徹梯磴排空驤。", "鍾山春水繞城隍，從師不憚白笈裝。", "矢鋒相觸塵不揚，驪黄牡牝若滅亡。", "子嚴主簿志不償，厭見朱墨紛傖囊。", "西風雲日思帝鄉，東華拜敕鳬綴行，黄昏閶闔飛驌驦。", "虛堂節候變金商，閉門蟋蟀鳴我房。", "吾君仁聖周成王，屏驅虎豹開明光。", "山龍粉米雜青黄，多儒可贊至治香。", "園檀山石豈荒凉，潢汙蕰藻須豆觴。", "願君與借羽翮翔，賢書蠶列升未央。", "君如病鶻待秋霜，牛衣未可悲王章。", "公朝道闢五達莊，服襄按節緩勿忙。", "夢松生腹渠不祥，莫車上儛應循牆。", "功成歸飲沆瀣漿，發機要若黄間張。"]'),
('5045c194-31bd-4823-963b-86cf769e6b9c','次韵都尉王晉卿天駟監邂逅作兼呈坐客','晁補之','宋','宋诗','song-poetry','','[]','平生杜元凱，學問光奕世。',156,'全唐诗/poet.song.63000.json','["平生杜元凱，學問光奕世。", "戚聯帝室未要論，烜赫功高羊叔子。", "赤霄翔舞須威蕤，孔翠文章豈其累。", "崇臺作山池作湖，富貴所要聲名俱。", "酒樽詩句得過薄，小隠山城殊未疏。", "曹侯詞翰諸公客，慣聽清歌耳傾側。", "天閑兩驥看追風，晴軒忽下飲河虹。", "拳毛妙畫不可見，顔公筆精如對面。", "鄧張不醉無攬轡，燒燭林間鵲飛起。", "第語曹侯繼張燕，鄰榼如澠不憂淺。"]'),
('71a97b35-656c-4c2f-b75c-881cfc540eaf','鄧御夫秀才爲窟室戲題','晁補之','宋','宋诗','song-poetry','','[]','君不學馮驩彈鋏從薛公，貸錢燒券悅市傭。',208,'全唐诗/poet.song.63000.json','["君不學馮驩彈鋏從薛公，貸錢燒券悅市傭。", "又不學魯連約矢射聊城，笑夸田單取美名。", "何爲空郊獨坐一茅屋，深如魚潛遠蛇伏。", "荒檐野蔓幽莫矚，窺戶下投如墜谷。", "其外桑麻雜蔬菽，白水寒山秀川陸。", "秋風蕭蕭吹苜蓿，晚日牛羊依雁鶩。", "朱書細字傳老子，蠹穴蝸穿無卷軸。", "我來不暇問出處，但愛君居伯夷築。", "九月九日秋氣凉，芙蓉黄菊天未霜。", "登高能賦豈我長，從君此庵時相羊。", "不用糟丘譏腐腸，酒酣猶能歌楚狂。", "我敬先生不敢量，二三子者亦自强，潔身亂倫非所望。"]'),
('3d377e99-b453-40c9-abfb-d35f4731b14f','揚州被召著作佐郎自金山回阻冰效退之陸渾山火句法','晁補之','宋','宋诗','song-poetry','','[]','二年官揚猶一炊，丞聾毋害守不譏。',176,'全唐诗/poet.song.63000.json','["二年官揚猶一炊，丞聾毋害守不譏。", "帝知無功呼返之，具舟從江民不知。", "道傍愚叟爲涕洟，豈無愛人如爾爲。", "我謝叟歸視汝兒，風號鴻潦水涸陂。", "冰塞川船不可移，白蜺橫野光逶迤。", "寒威上射小日規，旦行一里方午維。", "十日繫野兒啼饑，中無載盜過不窺。", "官令十夫爲操椎，耶許相力哀復疲。", "我笑遣夫是安施，霜不殺草聖所欷。", "歲十一月冰固宜，逆天進亦不可幾。", "爲兒摶飯兒安嬉，寧三月暖猶流凘。"]'),
('f71568e5-0e0f-4f74-89c3-7c189521a228','澶守諫議韓璹禱雨有應','晁補之','宋','宋诗','song-poetry','','[]','長蜺飲井井欲乾，白鼉鳴窟淒風寒。',96,'全唐诗/poet.song.63000.json','["長蜺飲井井欲乾，白鼉鳴窟淒風寒。", "公馬未駕陰漫漫，公歸溼幕濡旌幡。", "霜刀不染鵝頸殷，塗龍安享雩舞閑。", "隰桑有沃柔可攀，小麥青青大麥攢。", "拜公起舞公顔歡，明日空階響夜闌。", "屋漏不復愁衣單，帡幪廣厦安如山。"]'),
('a3a2fbef-29cf-402b-a728-a945acb8e346','依韵和子充雜言','晁補之','宋','宋诗','song-poetry','','[]','君不見東方朔，避世金馬門，侏儒倡郭同陸沉。',405,'全唐诗/poet.song.63000.json','["君不見東方朔，避世金馬門，侏儒倡郭同陸沉。", "滑稽突梯意已深，不如孫登閉口逃蘇門。", "身猶孤鳳無與鄰，心知嵇生未識真。", "兒童讀書聞入孝，遭時有用可以移於君。", "孔子繫易辭，尊乾而卑坤。", "耦耕未足問禮則，鳥獸固自群荆榛。", "孟嘗聲勢，一旦消歇，冢上之牧良可悲。", "苟爲貧賤不濟物，身死泯然俱若茲。", "聞君早慕棲竹林，何忽作此悲來吟。", "嚴君肥遯業討論，少年宜自有異聞。", "窮達俱性外，學者所不陳，惟勿枉道寧屈身。", "豈欲行不由徑如滅明，不然不欲乞醯於鄰同微生。", "白駒雖潔，空谷難久將誰親，當詩一篇差可人。", "秋蘭蘼蕪亭下生亦蕃，夫人自有美子何足言，採擷但慰吾愁魂。", "吟詩作賦北窗詞更妍，萬言不直一盃何足憐，咿呦聊用窮吾年。", "能來西疇清坐一榻橫，長饑亦不轑釜云無羹。", "荀卿論義榮，逕庭大不近人情。", "是非亦置之，古人踽踽凉凉生何爲。", "揚雄擇中庸，反騷痛湘纍。", "我今不見雄，此心猶爲君子夷。", "世間趣舍不同，豈但羊棗鱠。", "陶潛自謂，結廬人世。", "無車馬喧，心遠能爾。", "安有鄭君，其門如市。"]'),
('2a1e0427-7beb-41ff-925c-ba584fdad7c5','徑山','晁補之','宋','宋诗','song-poetry','','[]','盤崖繞壑步步高，僕痡馬乏游人勞。',344,'全唐诗/poet.song.63000.json','["盤崖繞壑步步高，僕痡馬乏游人勞。", "五峰崛起干雲霄，衆山奔走爭來朝。", "我行直欲犯星杓，意徹絕頂纔山腰。", "松間鳥語如我招，仰見白塔當林梢。", "檐携上下若桔槹，路窮飛樓鬰岧嶢。", "欽翁未來蔽菅茅，山精木怪讙游傲。", "麏馳虺竄狌鼯跳，靈景晦昧何由昭。", "忽然飛錫從江皋，窮探不憚東峰遥。", "曲腰丈人白絲袍，再拜辭前風雹飄。", "三百年來響鍾鐃，閩商海賈輸金刀。", "直欄橫牖山周遭，晨參夜諷聲嘈嘈。", "碧杉紫柏羅旌旄，客來六月忘炎歊。", "明月庵前醉松醪，白雲峰頂瞰吳郊。", "鵝毛一點錢塘潮，錢王宮闕如累樵。", "臨之股慄精魄超，歸不得寐心搖搖。", "含輝孤亭立嶢崤，此地覽景尤難逃。", "五更月落禽嘲嘲，陽烏欲上海水燒。", "晦明變化不終朝，倏陰忽晴狀莫描。", "夜闌燈青雨飄蕭，偶坐兩客論幻泡。", "探玄窮妙窺寂寥，破除世事無絲毫，不奈詩思猶强豪。", "歸時日沒紅霞消，荒崖老木山蟬號。"]'),
('e0bb3501-c388-4294-9df9-009d6c7d310b','次韵太學宋學正遐叔考試小疾見寄','晁補之','宋','宋诗','song-poetry','','[]','蕭然如裴叔則，頰毛疏復長。',143,'全唐诗/poet.song.63000.json','["蕭然如裴叔則，頰毛疏復長。", "邈然如王夷甫，高致宜廟廊。", "功名四皓雲泉外，詩賦三閭草木香。", "君莫誇熙寧登科面玉雪，只今未老鬢髮蒼。", "不應彈琴酒鑪坐，消渴還有禪病縛。", "不忘相拋白社一歲長，浮我杜舉須十觴。", "結交齊東李文叔，自倚筆力窺班揚。", "談經如市費雌黄，冰炭何用置我腸。", "勝遊獨不思迎祥，漾舟荷陼水中央。"]'),
('4cd43541-dac1-492a-867a-ae1e416764c8','淮壖','晁補之','宋','宋诗','song-poetry','','[]','淮壖日沒風卷沙，黄昏飛雪如落花。',144,'全唐诗/poet.song.63000.json','["淮壖日沒風卷沙，黄昏飛雪如落花。", "孤舟有客寒不飲，欹枕關篷夜憶家。", "雪飛篷底洒我額，篷隙虛明來曉色。", "紙屏布被風颼颼，驚起開篷滿船白。", "船頭雪重折黄蘆，下有宿雁驚相呼。", "天寒四野無行客，凍卧孤舟愁盜賊。", "厭聞淮浪打船聲，原上風號天正黑。", "土膏已動春陽來，安得長風掃霧開。", "豁然天外見白日，爲君挂席凌清淮。"]'),
('70be1311-1e92-44bf-b4ce-479a0e740337','寄懷壽光主簿四叔父','晁補之','宋','宋诗','song-poetry','','[]','我初就學首未冠，叔父不以童兒看。',246,'全唐诗/poet.song.63000.json','["我初就學首未冠，叔父不以童兒看。", "我今生年二十一，叔父晚作東州官。", "側身西望不得見，淚下兩臉何汍瀾。", "青春白日不照貧士屋，使我四壁長年寒。", "六年兩歲從進士，晚學揚雄識難字。", "貸錢乞米出都門，鼓腹吹篪入吳市。", "讀書擊劍老死終，何爲古來慷慨無人知。", "上有九重之青天，下有百尺之黄泥。", "收聲藏熱等雷火，白楊蔓草秋風悲。", "生亦不可料，死亦不可量。", "荆山長號刖兩足，何如船尾歌滄浪。", "我不能鉤章抉句攀俊造，又不能赤雞白狗追年少。", "矯首翻腸無一言，歸去吳松學漁釣。", "主簿卑官何所施，秋來兩鬢應生絲。", "阿宜已冠無成事，猶憶它年冬至詩。"]'),
('120245a6-3d5b-4b99-ba66-f171949f58f3','收麥呈王松齡秀才','晁補之','宋','宋诗','song-poetry','','[]','晁莊寂莫依東山，王莊負郭容往還。',64,'全唐诗/poet.song.63000.json','["晁莊寂莫依東山，王莊負郭容往還。", "東山刺薊深一尺，負郭家近饒盤餐。", "穿鞋戴笠隨麥隴，旱日炎炎煙燎顔。", "賤貧辛苦事當爾，君屋鱗鱗三百間。"]'),
('a5a8f2e2-da07-4ee9-b3a2-95e6480c9bed','花林示楊彭年秀才','晁補之','宋','宋诗','song-poetry','','[]','花林遠望春陽浮，卒然相值東山頭。',64,'全唐诗/poet.song.63000.json','["花林遠望春陽浮，卒然相值東山頭。", "犢兒初乳毛物潤，鴉子欲哺鳴聲柔。", "一生會合盡天幸，萬事反覆非人謀。", "倒頭且擬醉千日，相如渴病乾咽喉。"]'),
('cf0fdded-6527-4db6-b32a-682d53137f13','莎雞食蝗','晁補之','宋','宋诗','song-poetry','','[]','居貧得田不百畝，天賜時雨苗氤氳。',128,'全唐诗/poet.song.63000.json','["居貧得田不百畝，天賜時雨苗氤氳。", "遲明當熟晚未刈，災蝗夜至如驚軍。", "秋風吟茅雨洗瓦，葉上穗落青紛紛。", "常嫌莎雞聒麥壠，紡車細掉喧晨昏。", "莎雞可憐爾吻利，驅蝗逐蝻群披分。", "豈惟秋蟬畏螳斧，蝗亦爲爾森跳奔。", "天下災蝗凡幾郡，安得爾輩盈千群。", "揚眉振羽如屯雲，爾雖强聒誰煩聞。"]'),
('31e70b83-c0df-4b69-9eb0-89752851be8e','題李偁推官頤齋','晁補之','宋','宋诗','song-poetry','','[]','無捨靈龜觀朵頤，自求口實君自知。',304,'全唐诗/poet.song.63000.json','["無捨靈龜觀朵頤，自求口實君自知。", "誰爲此者君名之，其說不煩求我詩。", "君家嚴君業夔伊，虎視眈眈雄四夷。", "四方是維天子毗，汶陽一室大澤陂。", "我往受業拜門垂，聞公一語洗然奇，我歸瞠若安可追。", "君才固是麒麟兒，幼讀父書壯思施。", "不卑小官乃吾師，況有內樂潛天倪。", "荒城無人誰過之，面城築室茲逶迤。", "去年秋雨河股移，百草不生苔擁基。", "蟻子緣礎蚓糞泥，夜眠不穩憂爲池。", "今年閏早春氣遲，牆根隙地稍可埤，初植防風種黄耆。", "萊州石鼎青琉璃，地罏宿火風鳴枝，對君長語清未疲。", "外輕內順生理宜，問從何得聊我治。", "眉州夫子言可規，麻田處士術安期，今之崇丘歷九疑。", "見人不語下臂馳，遁逃乎陰食蛤梨。", "君何傖囊不往隨，與訪汗漫還無時。", "還無時，我何適，北山之南南山北。"]'),
('647c3318-e7af-44c5-bc4f-4414b11a4c47','答趙滋主簿','晁補之','宋','宋诗','song-poetry','','[]','我昔尋幽徑山上，曾傍苕溪弄菱槳。',64,'全唐诗/poet.song.63000.json','["我昔尋幽徑山上，曾傍苕溪弄菱槳。", "南臨天目指掌間，隔嶺如聞笑言響。", "年來清血斷征衣，碧髮丹顔日夕非。", "便欲相期煮白石，與君晚入煙霞飛。"]'),
('599e2166-4305-47f4-bbf9-075d29bcc77a','飲城西贈金鄉宰韓宗恕','晁補之','宋','宋诗','song-poetry','','[]','大夫盤中定州盞，三舉檐花舞凌亂。',204,'全唐诗/poet.song.63000.json','["大夫盤中定州盞，三舉檐花舞凌亂。", "請君行盞且莫稽，爲君起賦飲城西。", "城西古道如澗深，東風吹沙不見林。", "虛堂更覺野原闊，榆柳浩浩波濤吟。", "雜花一園來遠道，兩株江南梅更好。", "櫻桃已晚猶爛漫，百株如雪聊可繞。", "常時東風無此寒，常時諸君無此閑。", "且看瓶口似魚貫，莫惜面文如纈斑。", "大夫工爲宋玉賦，思不能涯字無數。", "秀才酷類東野貧，白屋青山愁曲身。", "籍咸不肯羞北阮，主簿高材即仇覽。", "成詩午景已妍和，罷酒花開應更多。", "山翁歸不醉，當奈峴山何。"]'),
('e8c4949a-4a10-4cab-ba35-7e34e7c8ca71','答陳履常秀才謔贈','晁補之','宋','宋诗','song-poetry','','[]','驅車觸熱中煩滿，苦無蔗漿凍金碗。',224,'全唐诗/poet.song.63000.json','["驅車觸熱中煩滿，苦無蔗漿凍金碗。", "陳君詩卷可洗心，持作終朝晤言伴。", "男兒三十四方身，布衣不化京洛塵。", "白駒皎皎在空谷，黄鳥睍睆鳴青春。", "子桑之居十日雨，入門不復聞人語。", "形骸正是吹一吷，安用虛名齊后土。", "文章初不用意成，黼黻帝躬臨下民。", "時花俚服誚新巧，牛馬安所辭吾名。", "禹穴幽奇行可强，江北江南正相望。", "乘濤鼓枻何當往，愛惜水仙桃竹杖。", "不應越女三年留，相見還須未白頭。", "蘧生知非苦不早，巨壑夜半遺藏舟。", "達人一言嚆矢疾，相從琢磨悔去日。", "菖蒲正是可憐花，我獨聞名不曾識。"]'),
('eba74fd6-452a-44dd-a9cd-e20a9ca3024b','和王仲甫病暑','晁補之','宋','宋诗','song-poetry','','[]','吳邦憚暑如蜂蠆，河曲還遭長日曬。',160,'全唐诗/poet.song.63000.json','["吳邦憚暑如蜂蠆，河曲還遭長日曬。", "蔗漿金碗頼蠲煩，內託潛陰數爲敗。", "黄昏乍快風吹髮，驅拊蚊虻坐明發。", "青衫主簿氣如雲，茂陵無事悲消渴。", "茫洋河伯何爲者，兩涘無因辨牛馬。", "何生狂夢涸歸墟，喉舌湯湯未勞瀉。", "能來一嗽華池津，七椀清風立有神。", "更尋齒下微妙訣，遣君體適仍魂平。", "案頭白紙如堆雪，人事紛紛日將月。", "與君未遇尤四時，利害相磨生內熱。"]'),
('544fb1e6-8522-46bd-a480-c93d260ff46d','贈送澶州監酒稅劉銓殿直','晁補之','宋','宋诗','song-poetry','','[]','頓丘淇水雄朔方，官收榷算資公藏。',152,'全唐诗/poet.song.63000.json','["頓丘淇水雄朔方，官收榷算資公藏。", "晨朝百販羅庭堂，望門逆鼻聞椒漿。", "惜哉劉子氣方剛，峨冠凜凜頎而揚。", "丈夫有志固難量，短袖不足供倡佯。", "黄河七月鳴浮梁，風埃瘦馬景山長。", "劉子何之魏北鄉。", "悲歌彈鋏邀孟嘗，馮驩一語驚齊王。", "況如劉子足自强，讀書滿腹鉗爾吭。", "酆城埋寶夜則光，士惟不用久乃彰。", "不見將軍家平陽，遭時有用名焜煌。"]'),
('45d3d4bb-c436-4926-8dc2-50d489f0584f','和顔隨飲酒','晁補之','宋','宋诗','song-poetry','','[]','樊山夜漲河鳴鼓，奎火占中知溽暑。',288,'全唐诗/poet.song.63000.json','["樊山夜漲河鳴鼓，奎火占中知溽暑。", "顔闔居鄰胡子都，共喜夏麋登宴俎。", "參軍河北主簿南，騎馬相逢不相語。", "市西老屋斷人居，自覺天風生廣宇。", "青菅席坐土階溼，黄綆汲泉塼井古。", "翩翩後至王將軍，開口相投律呼呂。", "丈夫得意吐然諾，盃酒形骸安足數。", "露頂張顛且勿幘，起舞我能先衆客。", "二豪禮法空是非，一斗三盃眼方白。", "中虛嘔冷腹橫絙，汗如槁壤朝陽蒸。", "咈然煩厭暫莫遏，飲蛇不省疑吞繩。", "豨苓卷桂導停飲，兩日不咀公厨冰。", "長篇忽聽鳳皇曲，却似半嶺逢孫登。", "君家鐺勺還應洗，須我下床仍食美。", "西池何似漢江長，誰使蒲萄變新泚。", "醉捉蟹螯攣五指，吏部拍浮非在水。", "抱琴寧復待招邀，昨夜雨凉孤興起。", "金丹定有換腸藥，不用俗醫論表裏。"]'),
('de9f49ec-1f65-4302-b1af-e21550aebc03','壓沙觀梨','晁補之','宋','宋诗','song-poetry','','[]','鄴城旁缺通清溝，城南之水城中流。',208,'全唐诗/poet.song.63000.json','["鄴城旁缺通清溝，城南之水城中流。", "白沙漲陸最宜果，萬梨壓樹當高秋。", "去年花開往獨晚，不見瓊苞腸欲斷。", "隆冬騎馬傍高原，却恨枯枝寒日短。", "忽然變化何處來，一夜東風吹雪滿。", "晴川極望百畮開，三山銀闕正崔嵬。", "雜花不容一朵間，照眼冷艷雲爲堆。", "堂中置酒對己好，千葩萬蕊誰能繞。", "暖景氤氳一片忙，蝴蝶飛來落青草。", "人間浩蕩看春光，豈徒田獵心發狂。", "向人慘澹迫歸興，落日峴山催羽觴。", "故園桃李春蹊沒，惜哉拔去無奇術。", "明日重尋儻可期，暴雨流階不能出。"]'),
('0fba0185-a768-4f62-88c0-3d5d96dcaa9f','過金堤劉景文','晁補之','宋','宋诗','song-poetry','','[]','雲間高堞如雲白，草下深濠如草碧。',208,'全唐诗/poet.song.63000.json','["雲間高堞如雲白，草下深濠如草碧。", "逶迤隴斷出平堤，前見黄河如带直。", "官居乃在城西原，荒臺古木烏鳥翻。", "美人芳氣如秋菊，坐令曄曄棄中園。", "不憂泑澤豪不殺，夜識漢中龜鼈在。", "借須走馬候水曹，後時此會何由再。", "霸陵往來初避名，執賈不回人更驚。", "無心躑躅路寢養，服車安用仍一鳴。", "未若捧甖何不可，二豪螟蛉與蜾臝。", "況聞舉案良亦賢，那愛五花論酒錢。", "不然憭慄坐歲晚，風入衰柳催寒蟬。", "我論李君其趣獨，自喻愚公徙王屋。", "是中聊可外形骸，官閑方轡相與來。"]'),
('0b872b10-86e1-4b40-8fce-69ba475e8ca7','送趙燮','晁補之','宋','宋诗','song-poetry','','[]','趙侯慷慨諸公客，少日論兵今髮白。',64,'全唐诗/poet.song.63000.json','["趙侯慷慨諸公客，少日論兵今髮白。", "自言頗似韝上鷹，老得一州聊鎩翮。", "送行誰復雙眼青，斷腸紅頰傾淥醽。", "停歌自解水蒼佩，醉騎紫燕黄河冰。"]'),
('3d48bad7-b507-4a9b-ac59-8311f8c1b2d3','送石梁赴舉','晁補之','宋','宋诗','song-poetry','','[]','鶴知半夜雞知旦，歲晚淹留客心亂。',64,'全唐诗/poet.song.63000.json','["鶴知半夜雞知旦，歲晚淹留客心亂。", "功名識時貴及早，不忍飯牛衣至骭。", "家居負米有季弟，能視明星弋鳬雁。", "男兒業就可以行，桃李榮時腰綬燦。"]'),
('67aeff8a-0ca8-43c9-8b5f-c51fdd15d330','送張緡子望太常簿','晁補之','宋','宋诗','song-poetry','','[]','張侯於我丈人行，十年江湖心鄉往。',192,'全唐诗/poet.song.63000.json','["張侯於我丈人行，十年江湖心鄉往。", "平生獨立白雪曲，少時妙譽青雲上。", "胡爲四十尚飄蓬，逢衣騎馬鄴城中。", "將軍寶帳簪履肅，開府畫筵簫鼓雄。", "况復儒宮飽閑暇，堂有叢書竹萧洒。", "論文不厭夜經過，起看北斗插黄河。", "相逢安得怨寂莫，仲宣樓頭良可樂。", "何當奇計出番禺，未應長檄開邛筰。", "太常句稽亦不冗，少卿淑問清時重。", "俎豆之事則嘗聞，男兒讀書業有用。", "歸去天邊道路長，東風春草滿池塘。", "美人不來時晼晚，誰與玩此林間芳。"]'),
('9aedb871-4b38-46be-87d6-703c2c887276','鄭彥能求擬江亭詩','晁補之','宋','宋诗','song-poetry','','[]','亭下流泉三畝隘，誰擬西江晴一派。',160,'全唐诗/poet.song.63000.json','["亭下流泉三畝隘，誰擬西江晴一派。", "桃李佳名聞昔人，此言雖小可喻大。", "寧非逐楚憔悴身，當是羊裘傲漢人。", "避世牆東王君公，五經紛綸井大春。", "端然養魚廢車馬，一身環堵觀天下。", "吾人鄭子詩句新，高堂素壁開萧洒。", "何當湛湛見青楓，白蘋落日慰相逢。", "一亭兩檻更何有，波濤風雨船前後。", "莫憶乘槎犯漢津，莫憶樓船下石城。", "盡醉漁陽無好曲，短蓑銅斗平生足。"]'),
('ae601865-a2ec-49f2-b718-25a10a283380','贈楊景平','晁補之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君不見華陰楊君漢孔子，君生其後無乃似。',131,'全唐诗/poet.song.63000.json','["君不見華陰楊君漢孔子，君生其後無乃似。", "平居恐懼西北隅，力行發憤尚不媿。", "君今鳴櫓下長淮，眼明清曉三楚開。", "揚州行矣勿濡滯，江南細雨收黄梅。", "我今正是鳥折翼，肺病三年廣文直。", "昔時黄帽榜舟人，却向西湖當不識。", "寄聲關子老漁樵，小山桂樹不須招。", "乘槎東海未敢必，欲去天台觀石橋。"]'),
('59993e5c-2efa-4d46-80b4-130fd964ab28','送吳黯赴闕','晁補之','宋','宋诗','song-poetry','','[]','我初官此君未來，君今去此我未往。',96,'全唐诗/poet.song.63000.json','["我初官此君未來，君今去此我未往。", "翻飛豈不慕緬邈，留滯何能悲鞅掌。", "學道平生昧蹊徑，半世端如走榛莽。", "古人曾病田甫田，切磋安可去吾黨。", "東風消雪送鴻雁，南國連山生篠簜。", "爲當歸夢五湖中，會有高名百寮上。"]'),
('f7a8e881-7688-4b08-bcc5-696e5d8f8cc0','送陳逸之筠州','晁補之','宋','宋诗','song-poetry','','[]','居貧百草春靃靡，製作舞雩春服美。',160,'全唐诗/poet.song.63000.json','["居貧百草春靃靡，製作舞雩春服美。", "愛君欲贈華韡韡，思君何處無芳卉。", "三年眼花祇欲眠，驚夢往往音跫然。", "單金安所用吾技，術成正復遷劉累。", "不狩何由有貆特，錢鎛須勤晚方積。", "呻吟裘氏日已多，恩流三族功比河。", "告行風雨春物空，催花作果黍芃芃。", "亦從梁汴即清潁，湛湛已見江頭楓。", "嚴君被命分符虎，昔者無襦今五袴。", "未勞負米迂山川，姑弟酒中從聖賢。"]'),
('f296fc98-eec6-4afa-aa4e-139ca2d6333f','過劉季孫','晁補之','宋','宋诗','song-poetry','','[]','劉侯歲覆春堤料，居不曾閑須我勞。',96,'全唐诗/poet.song.63000.json','["劉侯歲覆春堤料，居不曾閑須我勞。", "未嫌清濁各有携，匪報瓊瑶以爲好。", "吏訶單絞自可更，兒笑接䍦從復倒。", "爲憐徒步此青袍，重憶歸來著黄帽。", "官忙未向林野疏，時清不廢詩書傲。", "梨花如雪許重尋，秋實垂牆晚方到。"]'),
('8ddfcb91-0d5a-40e5-8e72-0026ca5e5112','贈段萬頃','晁補之','宋','宋诗','song-poetry','','[]','美人窈窕家南國，可與副笄親黍稷。',256,'全唐诗/poet.song.63000.json','["美人窈窕家南國，可與副笄親黍稷。", "平生寂莫鳳將雛，慚愧木桃猶報璧。", "石城三槳爲誰催，萬里清江凌不測。", "王門酒肉傲勝詭，豈有鄒陽仍下客。", "危詞欲洗大夫冤，千載獨懷吾祖賢。", "不量腹小文籍博，頗似井蜺輕飲川。", "丈夫趣舍無南北，情親非爲牆屋連。", "子真正用卧谷口，乃有高名諠日邊。", "胸中傀磊契何所，自笑柴愚得參魯。", "借令好問忘足繭，狐腋豈堪黄犬補。", "吾身櫟社真寄耳，趣取無用安足數。", "無心俎几彘盤辱，拳曲不羞人厭睹。", "土山出火石爲融，羲和當午車隆隆。", "通渠束带過者寡，乃獨葛巾終日同。", "傾囷倒廩用餉我，我爲牙羽陳編鍾。", "蟬聲入耳廩節改，別我整驂無愧容。"]'),
('1f553ade-ce32-42f0-9dba-1e8b3b015353','次韵魯直謝李右丞送茶','晁補之','宋','宋诗','song-poetry','','[]','都城米貴斗論璧，長饑茗椀無從識。',160,'全唐诗/poet.song.63000.json','["都城米貴斗論璧，長饑茗椀無從識。", "道和何暇索檳榔，慚愧雲龍羞肉食。", "壑源萬畮不作欄，上春伐鼓驚山顔。", "題封進御官有局，夜行初不更驛宿。", "冰融太液俱未知，寒食新苞隨賜燭。", "建安一水去兩水，易較豈如涇與渭。", "右丞分送天上餘，我試比方良有似。", "月團清潤珍豢羊，葵花瑣細胃與腸。", "可憐賦罷群玉晚，寧憶睡餘雙井香。", "大勝膠西蘇太守，茶湯不美誇薄酒。"]'),
('e0853b51-92f5-4d28-ab2f-c6fb77222543','與李文叔夜談','晁補之','宋','宋诗','song-poetry','','[]','中庭老柏霜雪裏，北風烈烈偏激耳。',104,'全唐诗/poet.song.63000.json','["中庭老柏霜雪裏，北風烈烈偏激耳。", "誦詩夜半舌入喉，飲我樽中淥醽美。", "升堂辭翰愧非有，何異還家數其齒。", "文章萬古猶一魚，乙丙誰能辨腸尾。", "更慚頗似會稽康，欲語常遭士瑶柅。", "廣陵八月未足言，曾使酲醲涊然起，安得譚如子枚子。"]'),
('4fae2989-56f7-4e97-af3f-c89e1164a904','贈送張愈秀才','晁補之','宋','宋诗','song-poetry','','[]','秋水幽幽濟河道，君挂蒲帆若飛鳥。',66,'全唐诗/poet.song.63000.json','["秋水幽幽濟河道，君挂蒲帆若飛鳥。", "西風黄葉滯公車，雞黍從君懷故廬。", "男兒自有四方志，世上相期獨榮利。", "昔時馬周徒步動天子，君今有用當如此。"]'),
('a785517d-8919-4482-9f30-7ee9507901c8','魯直復以詩送茶云願君飲此勿飲酒次韵','晁補之','宋','宋诗','song-poetry','','[]','相茶真似石韞璧，至精那可皮膚識。',160,'全唐诗/poet.song.63000.json','["相茶真似石韞璧，至精那可皮膚識。", "溪芽不給萬口須，往往山毛俱入食。", "雲龍正用餉近班，乞與粗官誠靦顔。", "崇朝一碗坐官局，申旦形清不成宿。", "平生樂此臭味同，故人貽我情相燭。", "黄侯發軔日千里，天育收駒自汧渭。", "車聲出鼎細九盤，如此佳句誰能似。", "遣試齊民蟹眼湯，扶起醉頭湔腐腸。", "頗類它時玉川子，破鼻竹林風送香。", "吾儕幽事動不朽，但讀離騷可無酒。"]'),
('f73cab9d-3820-4fa8-a8d5-abdf45fae6e8','次韵蘇公翰林贈同職鄧溫伯懷舊作','晁補之','宋','宋诗','song-poetry','','[]','雪堂蜜酒花作醅，教蜂使釀花自栽。',208,'全唐诗/poet.song.63000.json','["雪堂蜜酒花作醅，教蜂使釀花自栽。", "堂前雪落蜂正蟄，恨蜂不采西山梅。", "漫浪飲處空有跡，無酒可沃胸崔嵬。", "不知幾喚樊口渡，五見新曆頒清臺。", "鄧公昔歎不可挽，素衣未化京雒埃。", "山中相邀阻筇杖，天上對直同金罍。", "只今江邊春更好，漁蓑不曬懸牆隈。", "百年變化誰得料，劍光自出豐城苔。", "老儒經濟國勢定，近臣獻納天顔開。", "蜀公亭上別公處，花柳未逐東風摧。", "尚容登堂譚落屑，不愧索米腸鳴雷。", "因知流落本天命，何必挽引須時來。", "九關沉沉虎豹靜，無復極目江楓哀。"]'),
('262d0a64-7fcf-42cc-a970-434672812948','次韵文潛館中作','晁補之','宋','宋诗','song-poetry','','[]','蓬山前臨九軌路，三日街晴案吹土。',128,'全唐诗/poet.song.63000.json','["蓬山前臨九軌路，三日街晴案吹土。", "直廬鑿牖面宮垣，青壁嶄嶄看垂雨。", "殿閣風斜碧瓦寒，翅溼蒼鳶不能乳。", "却思窮巷亦可言，一埽蚊虻通昔苦。", "鬰蒸書課未須忙，午漏傳休聽天語。", "平生豪氣對樽酒，山雞見鏡猶能舞。", "城南寺近晚堪過，笙歌凉月聞千戶。", "但憂伏日細君須，割肉無緣待歸俎。"]'),
('6a5cc065-5536-481a-95a7-21f6095b30b9','次韵太學黄博士冕仲同考試作','晁補之','宋','宋诗','song-poetry','','[]','日邊傳詔天街暮，草草西城車馬聚。',144,'全唐诗/poet.song.63000.json','["日邊傳詔天街暮，草草西城車馬聚。", "官曹一見故情親，宴語識君心志古。", "成安長孺澶淵守，昔君羈游所爲主。", "我窮亦號成安客，文采初無君一縷。", "胸中萬頃復誰同，正有君家賢叔度。", "官事留人何鞅掌，廣文楊柳花飛戶。", "好書老未置鉛槧，學經晚始羞章句。", "乘槎况自風格有，病顰那可形容慕。", "成詩莫憚繼日傳，青驄御史呼歸去。"]'),
('f06d1195-38e1-47e5-85dd-2d49c117e33f','復用前韵贈祠部陳元輿','晁補之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','行樂曾聞戒遲暮，人生波上飛鳬聚。',144,'全唐诗/poet.song.63000.json','["行樂曾聞戒遲暮，人生波上飛鳬聚。", "蘭亭往事如過雨，山陰脩竹空千古。", "陳侯揮翰少年時，三賦聲名動人主。", "可是高才棄繩矩，自然采繡非針縷。", "五十天南把一麾，猶得無襦歌叔度。", "邂逅西城築冶墟，王官繼日車連戶。", "自言春晚洞庭歸，日落江南得佳句。", "傾蓋何妨許如故，執鞭况是平生慕。", "但憂筆陳困攻堅，儻許尋盟解圍去。"]'),
('bd080607-81e0-4a65-9bdc-9c86606b091e','復用前韵呈刑部杜丈君章','晁補之','宋','宋诗','song-poetry','','[]','杜侯灑墨春雲暮，紛紛滿紙棲鴉聚。',144,'全唐诗/poet.song.63000.json','["杜侯灑墨春雲暮，紛紛滿紙棲鴉聚。", "文章不犯世故鋒，牛鬼荒虛瓦棺古。", "平生傀磊寧獨此，躋俗唐虞要遭主。", "先君諸父盡金蘭，申以婚姻况覶縷。", "勞心吏卷官有程，得意朋尊美無度。", "尚憶花妍春仲時，休沐黄昏來叩戶。", "苦憐蟾桂將十分，欲贈海棠無一句。", "巷南巷北相遇稀，而此從公慰懷慕。", "安石榴紅儻可期，公不來過我當去。"]'),
('97555d91-a1b8-49a0-be99-79e145f0e310','復用前韵再呈博士黄冕仲','晁補之','宋','宋诗','song-poetry','','[]','龍津之北雙溪騖，逶迤勢入龍津聚。',144,'全唐诗/poet.song.63000.json','["龍津之北雙溪騖，逶迤勢入龍津聚。", "龍歸何處牛斗閑，劍不可求江海古。", "慘澹猶思八百年，變化豈無神物主。", "何當旋柁入奫淪，儻可然犀照毛縷。", "登樓那有北客同，把酒但看南雁度。", "更邀桃葉遠臨水，正值荔枝紅照戶。", "入梁一曳鄒陽裾，思越屢吟莊舄句。", "竹林觴詠當日情，峴山名姓它時慕。", "一聞說盡青鞋游，令我乘風欲仙去。"]'),
('3bf73274-d930-4c02-a498-50bea36a44f6','送龍圖范丈德孺帥慶','晁補之','宋','宋诗','song-poetry','','[]','君不見先君往在康定中，奉詔經略河西戎。',227,'全唐诗/poet.song.63000.json','["君不見先君往在康定中，奉詔經略河西戎。", "大順胡蘆盡耕稼，賊書不到秦關東。", "邊人咸識侍中子，至今猶說將軍似。", "給事文武龍圖賢，大馮小馮安足言。", "齠年書傳有肝膽，二十起家車檻檻。", "蛟龍雲雨時可用，麒麟圖畫功非晚。", "况聞馳傳厭山谷，頃時河隴嚴飛輓。", "朝廷屬休蘭會兵，秦人倚慶爲長城。", "時平斥候正須遠，軍閑留田未宜輕。", "東風浩浩吹榆柳，相勸西城古原酒。", "班春曷不問遺老，先公遠謀尚多有。", "女郎山下萬貔貅，部曲肥馬身輕裘。", "比曹賞腸飽無用，談話豈得希封侯。", "趙邊今日須李牧，士無超距姑食肉。"]'),
('186977e7-8acb-414a-aed3-163b829de224','初與文潛入館魯直貽詩并茶硯次韵','晁補之','宋','宋诗','song-poetry','','[]','黄侯閱世如傳郵，自言何預風馬牛。',144,'全唐诗/poet.song.63000.json','["黄侯閱世如傳郵，自言何預風馬牛。", "草經不下天祿閣，詩入雞林海上州。", "兼陳九鼎燦玉鉉，並綴五冕森珠旒。", "後來傀磊有張子，姓名並向紫府收。", "青春一篇更奇麗，勢到屈宋何秋秋。", "洮州石貴雙趙璧，漢水鴨頭如此色。", "贈酬不鄙亦及我，刻畫無鹽譽傾國。", "月團聊試金井漪，排遣滯思無立錐。", "乘風良自興不淺，愁報孟侯無好詩。"]'),
('babe4f39-94c6-4889-bc2c-552309b7a310','用文潛館中韵贈蔡學正天啟','晁補之','宋','宋诗','song-poetry','','[]','蔡侯飽學囷千釜，濯足清江起南土。',128,'全唐诗/poet.song.63000.json','["蔡侯飽學囷千釜，濯足清江起南土。", "立談頗似燕客豪，快奪范睢如墜雨。", "東城禽羽未足言，柏直何爲口方乳。", "蔣侯山中伴香火，三年不厭長齋苦。", "平生傀落有誰同，要得張侯三日語。", "晝閑那自運甓忙，時清不用聞雞舞。", "桓榮歡喜見車馬，書冊辛勤立門戶。", "自當食肉似班超，猛虎何嘗窺案俎。"]'),
('bc5f2a83-9bd9-4172-acb0-d59fabf0de29','次韵魯直試院贈奉議李伯時畫詩','晁補之','宋','宋诗','song-poetry','','[]','東房携卷繞幕行，西房卷作墮地聲，紙山間出筆陣橫。',72,'全唐诗/poet.song.63000.json','["東房携卷繞幕行，西房卷作墮地聲，紙山間出筆陣橫。", "李侯畫若禪眼透，觀魚玄沙骨竦瘦，舟中淵明細若豆。", "歸心只愛玉花驄，不須棘針學癡翁，惱渠愁作眉鬭紅。"]'),
('5fb71ef6-a865-4a8d-a6ae-488c7727a69a','喜文潛自淮南歸招飲西岡呈坐客','晁補之','宋','宋诗','song-poetry','','[]','春回三楚冰生漪，銀臺春夢歸心馳。',184,'全唐诗/poet.song.63000.json','["春回三楚冰生漪，銀臺春夢歸心馳。", "莫言上水百丈苦，淮渚東風一月期。", "都城經春雪蔽地，百花不放須君至。", "清晨一紙國門書，走馬蓬壺下直初。", "保康橋頭燈照夜，我馬鳴嘶向君馬。", "得君豈但官局同，卜鄰况近南城下。", "文詞翊善知名久，丈人令德于公後。", "同年廖李芸省郎，吳門隠尉身姓張。", "平時花發值此客，隨分東牆有春色。", "宮壺賜酒玉流巵，請君但作留春詩，人生身外安所知。", "爲君借舞杜廷尉，對花有酒那不醉。"]'),
('489b5fb7-9c21-4acc-871c-7c070686f241','李成季得閻子常古琴作','晁補之','宋','宋诗','song-poetry','','[]','昔人流水高山手，此意寧從絃上有。',192,'全唐诗/poet.song.63000.json','["昔人流水高山手，此意寧從絃上有。", "閻侯卷舌卧閭里，意向是中留不朽。", "似聞綠綺置床頭，暑雨東城無麥秋。", "趙傳和氏齋五日，吳得湛盧當兩州。", "李侯得意誇題柱，成詩欲使邀諸路。", "自有桓山石室彈，深屋時聞繭抽緒。", "無琴尚可何獨絃，要識精微非度數。", "人生有累無非失，我欲心灰木爲質。", "懶從徽的自凝塵，老向詩書逾愛日。", "自言結習久難除，猶理斷編尋止息。", "焦城卜築近連軫，歸約閻侯亦蕭瑟。", "舊聞君祖課木奴，試買瑕丘百株栗。"]'),
('8bc28a6e-a514-4c2f-a5c2-71009efc6d3c','同魯直文潛飲刑部杜君章家次封丘杜觀仲韵','晁補之','宋','宋诗','song-poetry','','[]','廷尉風流才絕塵，最憐高髻歌陽春。',208,'全唐诗/poet.song.63000.json','["廷尉風流才絕塵，最憐高髻歌陽春。", "兩鬟亦解倚瑟語，催送花前紅袖舞。", "黄張翰墨海內名，席上生風清夏宇。", "封丘自倚筆勢豪，不怕當筵賦鸚鵡。", "對酒含情古所憐，樂事幾時如過雨。", "阮公鑪邊不擬歸，陸郎班騅無用嘶。", "長燈照出簾幙外，缺月墮落藩牆西。", "斗酒雙魚何足貴，李侯氣許山東吏。", "正須新麵雜青槐，千里紫蓴江上來。", "長船刻玉流霞動，快引不須帆櫓送。", "自作新詞碧牡丹，箸擊盃翻釵墜鳳。", "芍藥佳名聞昔人，滿插不辭歸帽重。", "倒床任作鼻鳴雷，屋上啼烏還喚夢。"]'),
('470309b2-ff59-4e4f-b95f-c6a3cd4d70f5','次韵校書孔彥常校資治通鑑作','晁補之','宋','宋诗','song-poetry','','[]','羣公愛我邀我居，平生文舉情豈疏。',96,'全唐诗/poet.song.63000.json','["羣公愛我邀我居，平生文舉情豈疏。", "鈎陳玄武在北極，上帝之府森圖書。", "趙韓魏降顯德尾，司馬蟬嫣世良史。", "其人不見其言在，青草生原歲陽止。", "吾君好學由生知，成湯得尹方有爲。", "應合它年尹躬學，書成泣像麒麟閣。"]'),
('9605040c-6c7d-47c8-a039-4f8a74f210db','次韵蘇翰林廐馬好頭赤','晁補之','宋','宋诗','song-poetry','','[]','君不見崑崙龍種非凡肉，不但蹄高耳批竹。',67,'全唐诗/poet.song.63000.json','["君不見崑崙龍種非凡肉，不但蹄高耳批竹。", "區區吳蜀有二駿，跳過斷橋飛出谷。", "萬蹄縱牧原野赤，汧隴收駒日復日。", "未須天廐驚好頭，冀北未空聊一歷。"]'),
('3f711e2c-7654-44d8-9c62-85d4171bd54d','送劉景文兩浙西路都監','晁補之','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u6d1e\u5ead\u6e56"]','劉侯八尺力如虎，遣守黄河千里堤。',224,'全唐诗/poet.song.63000.json','["劉侯八尺力如虎，遣守黄河千里堤。", "閉門寒郊似深隠，蟲響秋巷牆懸梨。", "我官北門四換歲，訪飲屢過城濠西。", "雁飛不到建章闕，欲往何異車無輗。", "詩篇驚人衆側耳，蚤有高譽無卑栖。", "詔綏兵馬吳八郡，畫船下汴光生蜺。", "西湖靈隠天下冠，幽人釋子多招提。", "松林竹塢我行地，拂拭定有塵埃題。", "山堂清酒小泥赤，吳歌白紵雙蛾低。", "少年放意入雲水，只今塊坐愁冠笄。", "君行日夜向佳景，洞庭霜落羞鰅鮧。", "莫誇能飯便鞍馬，閩琛海賮通蠻谿。", "時平游宦行樂耳，屬有佳客須頻携。", "明年我亦丐一邑，扁舟江上隨鳧鷖。"]'),
('5f88524d-fd52-4bab-9a53-5bceab438285','送直閣杜君章守齊','晁補之','宋','宋诗','song-poetry','','[]','杜公文史不讀律，平反世稱徐有功。',272,'全唐诗/poet.song.63000.json','["杜公文史不讀律，平反世稱徐有功。", "官爲列卿位亦顯，臯陶事與禮樂同。", "書生骫骳笑法令，弦歌不愧陵陂中。", "衆賢和豫治乃舉，但願主聖朝廷公。", "白頭典校漢天祿，未煩載酒如揚雄。", "自言臣老應報國，五馬便去如飛鴻。", "京東耳聞事可數，似說振貸倉儲空。", "裕民誠患力不足，措國豈與民俱窮。", "才難所要遇事了，仁厚未免無能蒙。", "囊中餐玉百未試，干越在匣光生虹。", "却嗟鉛槧坐棄日，伊我何補羞兒童。", "力能如虎安敢爾，鬢毛幸未成老翁。", "亦思一郡效尺寸，官卑未許伸喉嚨。", "飽知世事祗坐嘯，又看馬鬣吹西風。", "平生放意在雲水，落身塵土禽閉籠。", "經時無酒對佳客，借與歌舞開心胸。", "公行媌曼載雙舸，誰與客勸琉璃鍾。"]'),
('81e62701-1002-4912-92cc-d8703a37e4b7','次韵文潛瞻啟聖院旃檀像','晁補之','宋','宋诗','song-poetry','','[]','至人如幻千億身，若以色觀皆世人。',144,'全唐诗/poet.song.63000.json','["至人如幻千億身，若以色觀皆世人。", "大千初自一漚發，變化誰能知本因。", "移天宮殿著人世，斷取無異陶家輪。", "當年紫磨已殊勝，後來浮海亦有神。", "緬懷此地初啟聖，真人繼出天下春。", "莊嚴事秘理莫測，萬世鎮守無陳新。", "寶坊千柱衆八百，衣食隨念何由貧。", "天寒急景過駒隙，坐穩不去同鴟蹲。", "歸來想像發光影，一洗百慮無餘塵。"]'),
('ed481ec5-3868-478d-8983-6276380889de','送外舅杜侍御使陝西自徐州移作','晁補之','宋','宋诗','song-poetry','','[]','建隆以來論人物，得士與古相低昂。',304,'全唐诗/poet.song.63000.json','["建隆以來論人物，得士與古相低昂。", "人才歷數仁祖世，後生嵬瑣無復望。", "老成寂莫典刑在，杜公玉立映班行。", "少時學問聖賢說，松柏歲寒觀老節。", "得官烏府不須臾，正色空聞動帷闥。", "鑠金衆口未必然，天與名城慰蕭屑。", "王師頃縛山西酋，朝廷却懷西顧憂。", "凉州旄鉞何足恃，岐隴須公勤傳郵。", "平生經國有雅意，乘流得坎惟所值。", "作官施設要近民，金馬嚴徐等兒戲。", "詔書寬大人樂生，吏安爲弛威不行。", "金城那可無粟守，堯舜與民寧並耕。", "茶鹽資國何必古，俗儒徇名不知務。", "精神折衝在本强，要以雍容在蒼遽。", "知無不爲公自期，豈弟君子神所私。", "秦山渭水照車馬，屬城列縣觀威儀。", "此行屬任良不惡，金魚新佩明光墀。", "誰言直諫居內少，淮南盜鑄煩撫綏。", "時平王度日金玉，歲晚汲公還見思。"]'),
('f5d6ce32-5885-4760-851c-7ae7a5b5e6f2','次韵文潛憶楊翰林元素家淮上夜飲作','晁補之','宋','宋诗','song-poetry','','[]','老人得坐安若山，畏寒縮頸衣裘間。',128,'全唐诗/poet.song.63000.json','["老人得坐安若山，畏寒縮頸衣裘間。", "不如公子擁樽酒，詩材春亂詞濤翻。", "想見楊家美人出，玉面朱唇映琴瑟。", "冰船著炬光照淮，雪亂風筵飲方逸。", "只今愁坐私自憐，寒書凍硯塵滿前。", "人生何者非昨夢，還如歸去散花天。", "老人已復形槁木，真幻那知然不然。", "蚓鳴小鼎藜羹熟，閉眼圓蒲不是禪。"]'),
('320df2d6-3572-47e5-b7fd-49e87519572b','贈麻田山人吳子野','晁補之','宋','宋诗','song-poetry','','[]','汶陽我昔見蘇李，人言吳子歸未幾。',160,'全唐诗/poet.song.63000.json','["汶陽我昔見蘇李，人言吳子歸未幾。", "長嘯春風大澤西，却望麻田山萬里。", "不逢鄭老溪上箭，欲致朱公路傍米。", "今年窮巷絲生髮，馬尾吹風化衣袷。", "定知赤鯉驀波濤，何意黄冠驚僕妾。", "琅函萬過陰魄悲，心無丹白鑪生兒。", "山中種芝豈無侶，成都醉眠未當去。", "願從王烈或見呼，試訪孫登竟無語。", "棄家內愧非此流，此身天地一虛舟。", "未應齒豁塵埃裏，乞與青精救白頭。"]'),
('26aabdac-3ce1-439d-9c85-728da8d96941','送北京學生曹慈明秀才之京師','晁補之','宋','宋诗','song-poetry','','[]','魏武子孫今寂莫，唐來只有畫將軍。',128,'全唐诗/poet.song.63000.json','["魏武子孫今寂莫，唐來只有畫將軍。", "鄴城初見黄須面，尚喜登堂詞若雲。", "乃公白首圖籍裏，小心恐懼教其子。", "文章錦心仍繡腑，屠龍殫家安用許。", "半年繫船康海門，官忙不共持一樽。", "岡頭梨花吹欲盡，淮口汴流來正渾。", "鄙夫日欲向吳越，官滿一封飛魏闕。", "著書虎觀未敢言，蔽身蟬葉真癡絕。"]'),
('0b54be7a-4c8c-402c-98ca-2395f51a3420','東坡先生移守廣陵以詩往迎先生以淮南旱書中教虎頭祈雨法始走諸祠即得甘澤因爲賀','晁補之','宋','宋诗','song-poetry','','[]','去年使君道廣陵，吾州空市看雙旌。',192,'全唐诗/poet.song.63000.json','["去年使君道廣陵，吾州空市看雙旌。", "今年吾州歡一口，使君來爲廣陵守。", "麥如櫛髮稻立錐，使君憂民如己饑。", "似聞維舟禱靈塔，如絲氣上淮西脽。", "隨軒膏澤人所待，風伯何知亦前戒。", "虎頭未用沉滄江，龍尾先看掛清海。", "爲霖功業在傅巖，如何白首擁彤幨。", "世上讒夫亂紅紫，天教仁政滿東南。", "青袍門人老州佐，干世無成志消惰。", "封章去國人恨公，醉笑從公神許我。", "瓊花芍藥豈易逢，如淮之酒良不空。", "一釂孤鴻煙雨曲，平山堂上快哉風。"]'),
('bc800ce4-2c71-43de-ae0d-2bd976a4bab3','至日同文潛舍人飲錢京兆穆父家','晁補之','宋','宋诗','song-poetry','','[]','大尹孤標琢崑玉，舍人骨相飛食肉。',112,'全唐诗/poet.song.63000.json','["大尹孤標琢崑玉，舍人骨相飛食肉。", "弊裘羸馬愧我寒，喚飲東齋散膚粟。", "少時獨識孔文舉，不交餘子平生足。", "尹門如市立相躡，尹心如水清可掬。", "鄰無惡少歸醉卧，不遣長鬚訟騎屋。", "閉門不出三日雪，冷坐西軒花眩目。", "未妨詩句敵青春，痛飲何由髮還綠。"]'),
('7e7cbff7-7317-40cb-ab6f-c313f473f151','送李端叔從定州先生辟','晁補之','宋','宋诗','song-poetry','','[]','中山老帥巖廊姿，不用猶作諸侯師。',232,'全唐诗/poet.song.63000.json','["中山老帥巖廊姿，不用猶作諸侯師。", "毛錐變化有風雨，餘事亦足疲羣兒。", "龍門爭騖貨趨肆，求貨安知於此市。", "百年用舍我何有，一語重輕人取是。", "李君懷璞世又嗤，世人不寶公收之，乃知士固伸所知。", "黄金鑄作鍾子期，不如晏子共一時。", "時平關鍵一臂持，於何用此賓主爲。", "鞭長未可施馬腹，要以高名讋殊俗。", "應戴接䍦携葛彊，笑談過市人隘坊。", "勿憶平山如峴首，它日我名同不朽。", "有年公昔但吟詩，無事君今姑飲酒。", "只憂我似蠹書魚，無復驤首鳴鹽車。", "一麾儻許從方伯，要著韎韋親丈席。", "登臨相與看劉公，長嘯犬羊空漠北。"]'),
('4d23d032-9057-45da-a8e0-3c03c825c9d0','和文潛期飲大尹穆父家兼呈尹','晁補之','宋','宋诗','song-poetry','','[]','野人骯髒無與鄰，世人共笑子獨親。',160,'全唐诗/poet.song.63000.json','["野人骯髒無與鄰，世人共笑子獨親。", "沛然有餘不矜飾，我亦謂子誠可人。", "萬魚噞喁困復却，看子撇捩黄金鱗。", "人甘如醴飲者醉，我獨蜇口如薑辛。", "淮南歸來兩鬢雪，閉門自不羞甑塵。", "無衣可換江頭醉，有誰肯載樽中醇。", "愧慚救渴京兆尹，空缸尚可供十巡。", "放言與子一傾倒，非子畏人嫌我真。", "府中貴人玉比德，堂下和氣天回春。", "醉人多忤貴人恕，來呼莫憚衝泥頻。"]'),
('764b515e-5b75-412d-b309-322361715026','和東坡先生梅花三首  其一','晁補之','宋','宋诗','song-poetry','','[]','霜晴十月玉溪村，見梅開早客迷魂。',128,'全唐诗/poet.song.63000.json','["霜晴十月玉溪村，見梅開早客迷魂。", "山阿若有人含睇，跂望不到霜煙昏。", "東西野寺通兩徑，上下竹籬開一園。", "落身麴糵盆盎裏，晨坐對花無酒溫。", "歸來山月照玉蕊，一盃徑卧東方暾。", "羅浮幽夢入仙窟，有屨亦滿先生門。", "欣然得句荔支浦，妙絕不似人間言。", "詩成莫歎形對影，尚可邀月成三樽。"]'),
('804b9b04-aacb-4487-a923-0a63c9d3e285','和東坡先生梅花三首  其二','晁補之','宋','宋诗','song-poetry','','[]','幽閑合出昭君村，芳潔恐是三閭魂。',128,'全唐诗/poet.song.63000.json','["幽閑合出昭君村，芳潔恐是三閭魂。", "無人嶺上更儇好，不與俗花名合昏。", "蒼官森出劍珮列，甲夫密裹旗槍園。", "數株臨水欲仙去，一笑向人如玉溫。", "火維草木百名字，十月不冷常炎暾。", "同心紫蒂宜上苑，啄人虎豹司九門。", "借令驛使能遠致，要比桃李終無言。", "豈惟千里共明月，亦可千里同芳樽。"]'),
('a1e893f3-597f-4986-81ff-86f90d68f167','和東坡先生梅花三首  其三','晁補之','宋','宋诗','song-poetry','','[]','梅花落盡上饒村，腸斷子規啼月魂。',128,'全唐诗/poet.song.63000.json','["梅花落盡上饒村，腸斷子規啼月魂。", "慰人獨有白玉蕊，不到窗前只醉昏。", "坐罏環甕不舉首，浮花浪蕊空滿園。", "海山有客心似水，揮麈自散炎洲溫。", "松風亭下亦如夢，不見枝雪流初暾。", "孫登一絃百韵足，有山便足同蘇門。", "似聞對客但長嘯，獨謂此花終日言。", "一篇尚可三致志，聽人酌去如衢樽。"]'),
('91449293-5a1a-41ec-9438-eadfc3bb8a78','和王定國二首  其一','晁補之','宋','宋诗','song-poetry','','[]','可憐好月如好人，我欲招之入窗戶。',64,'全唐诗/poet.song.63000.json','["可憐好月如好人，我欲招之入窗戶。", "人言明日當大暑，君看繁星如萬炷。", "想君映月讀書時，清似列仙臞不肥。", "我正甘眠愁日出，朝騎一馬暮還歸。"]'),
('3123ed74-a976-4e85-ae24-08d419194165','和王定國二首  其二','晁補之','宋','宋诗','song-poetry','','[]','還朝便與山水疏，只有此月隨吾居。',64,'全唐诗/poet.song.63000.json','["還朝便與山水疏，只有此月隨吾居。", "莫論人隔十日面，猶勝犬傳千里書。", "清虛有物濯煩暑，藤床對月如對雨。", "賦成鴻雁入周詩，未覺宣王似吾主。"]'),
('f37b44a9-56a7-414d-b015-98a803f16e16','次韵蘇門下寄題雪浪石','晁補之','宋','宋诗','song-poetry','','[]','居庸滅烽惟留屯，時平更覺將軍尊。',160,'全唐诗/poet.song.63000.json','["居庸滅烽惟留屯，時平更覺將軍尊。", "鈴齋看雪擁衲坐，急鼓又報邊城昏。", "百壺高宴梨栗圃，千里未盡桑麻村。", "天憐公老無以樂，一星飛墮從天門。", "得無遺履穀城化，恐是喫草金華魂。", "不然荆棘霜露底，兀然奇怪來無根。", "女媧擣鍊所遺棄，奔潀尚有河漢痕。", "豈其謀國坐不用，聊以永日寧復論。", "跳梁不憂牧並塞，綏納可使魚游盆。", "公歸廊廟誰得挽，此石萬古當長存。"]'),
('07769937-516e-420c-8817-ab8efdb613fc','次韵和趙令僉防禦春日感懷','晁補之','宋','宋诗','song-poetry','','[]','春塍雪消龜兆坼，凍柳冰蒲俱好色。',224,'全唐诗/poet.song.63000.json','["春塍雪消龜兆坼，凍柳冰蒲俱好色。", "走馬城東眼乍驚，可憐前日非今日。", "結交從古天地間，百年誰見一人閒。", "王城塵土化衣袷，五鼓驅車休夜闌。", "况我崎嶇二三子，聖恩釋累從甌蠻。", "雄豪久鎩酒量窄，耎懦新長詩辭慳。", "王孫物外有高興，數携王趙兩紅顔。", "上書自去千牛衛，挂席欲過三神山。", "灰餘方烈竈下響，霧廓初見岩中斑。", "醉吟誰共可憐春，江南太守舊詩人。", "賡酬不減笙磬答，秀發更爲煙霞新。", "萬卷藏書韋杜曲，憶子陳詩一言足。", "得意鱸魚故未饜，多情桃葉應相逐。", "努力閒平盛世名，歸及春風雙鬢綠。"]'),
('08d0e0c4-ec48-4872-b5a8-cb20c75c318a','次韵和文潛暮春即事','晁補之','宋','宋诗','song-poetry','','[]','南歸見君百事足，如何一官曾不閑。',160,'全唐诗/poet.song.63000.json','["南歸見君百事足，如何一官曾不閑。", "寒衝雪泥暑鄣日，老面只今如纈斑。", "憐君與我自同調，久渫不食猶寒泉。", "功名櫟社直寄耳，顔色不同誰後先。", "黑牛白犢未渠怪，物理儻自相回旋。", "愛君此語亦不出，勝處紫芝眉宇間。", "飲中八人半寂莫，最豪焦遂今誰班。", "凝祥池上舊游處，海棠亦恐非昔年。", "春波一眼詩句好，兩腋尚覺風翩翩。", "投閑方轡政可勉，何用不飲空三歎。"]'),
('6263633c-5e32-420c-83ea-90daca09ff03','用谷字韵答提刑毅父治河橋','晁補之','宋','宋诗','song-poetry','','[]','兩堤馬頭高作山，兩津車路深成谷。',64,'全唐诗/poet.song.63000.json','["兩堤馬頭高作山，兩津車路深成谷。", "截川夭矯暮虹背，排浪參差動蚿足。", "七牛蹴河猶怒目，一牛從能往不復。", "借牛使河此聖時，强飲不須求馬玉。"]'),
('e4a3f625-7223-48e1-a5e3-495b58d7c203','次韵孔毅父種花因送海棠廳三大字求茶','晁補之','宋','宋诗','song-poetry','','[]','東園老槐春不發，舉頭只見中條雪。',64,'全唐诗/poet.song.63000.json','["東園老槐春不發，舉頭只見中條雪。", "江梅去國亦悽然，一萼聊堪映庭月。", "未信河灘宜海棠，十株立致非所望。", "爲君大字書堂榜，報我奩中越焙香。"]'),
('562f5d31-c6c9-409e-83d3-8fb5b029fbb7','再用治橋韵奉送毅夫按部將行','晁補之','宋','宋诗','song-poetry','','[]','降羌當有甲齊山，叛虜應無馬量谷。',64,'全唐诗/poet.song.63000.json','["降羌當有甲齊山，叛虜應無馬量谷。", "莫憂斗米千錢貴，自可航河一葦足。", "繡衣不但捕群偷，赦書蠲租亡者復。", "知吾勞倦神亦充，白髮何妨面如玉。"]'),
('96198cd2-f366-43ff-83c3-e10236d291f9','再用發字韵謝毅父送茶','晁補之','宋','宋诗','song-poetry','','[]','開門睹雉不敢發，滯思霾胸須澡雪。',64,'全唐诗/poet.song.63000.json','["開門睹雉不敢發，滯思霾胸須澡雪。", "煩君初試一槍旗，救我將隳半輪月。", "不應種木便甘棠，清風自是萬夫望。", "未須乘此蓬萊去，明日論詩齒頰香。"]'),
('e52e9ead-b875-4869-8237-68a82f0cfd3d','贈常州感慈邦長老','晁補之','宋','宋诗','song-poetry','','[]','君不見大通方丈空無物，亦不拈椎并豎拂。',67,'全唐诗/poet.song.63000.json','["君不見大通方丈空無物，亦不拈椎并豎拂。", "本原自性未出喉，已向頂門遭一咄。", "感慈神駿渥洼流，壁上高僧莫遣酬。", "霹靂一聲龍破柱，此中何處有裴休。"]'),
('c5f3d644-77f2-47e8-a37f-f813f3b57569','及第東歸將赴調寄李成季','晁補之','宋','宋诗','song-poetry','','[]','先輩觀濤滄海口，長嘯橫槎拂牛斗。',179,'全唐诗/poet.song.63000.json','["先輩觀濤滄海口，長嘯橫槎拂牛斗。", "野人醉著夢游天，九門歷盡驚復還。", "嘈嘈廣樂猶盈耳，出門依舊重人間。", "不知先輩今何往，仙標玉骨天應賞。", "千里東歸暮景清，桑麻暗地日銜城。", "黄金宮闕初回望，青草恩袍偶自榮。", "歸來澣濯親甘旨，却歎京塵誤遊子。", "家人飯黍慰辛勤，鄰媼壺漿佐歡喜。", "君不見馮驩一劍星闌干，短歌慷慨不堪彈。", "男兒得意貴穎脫，功名有分勞躋攀。", "折腰正爲五斗米，得飽約君尋故山。"]'),
('5ac00206-fa81-4483-bc93-45f4ff8542dc','復用前韵答明略并呈魯直','晁補之','宋','宋诗','song-poetry','','[]','廖君憤世談刺口，人言寧食葱三斗。',179,'全唐诗/poet.song.63000.json','["廖君憤世談刺口，人言寧食葱三斗。", "軒然齃鼻頤隠肩，日日醉市驅馿還。", "我初目病視彷彿，望君有異大人間。", "新豐兩行惜不上，竹林風來虛自賞。", "俯頭落筆千人驚，一戰取齊餘兩城。", "田生龍甲頼束葦，詭勝尾熱安知榮。", "盈盈府中誰憐此，爲君愧慚黄夫子。", "論功欲識非戰罪，試使喑噁走楊喜。", "君不見方朔高才良獨難，割肉要令生自彈。", "北軍給食誰致爾，羊求平昔安能攀。", "偶然捧檄忽擲板，鳥自知還雲出山。"]'),
('15f75f8f-8be1-4d39-83b7-db6ae1137ef3','復用前韵答魯直并呈明略','晁補之','宋','宋诗','song-poetry','','[]','黄子人談不容口，豈與常人計升斗。',179,'全唐诗/poet.song.63000.json','["黄子人談不容口，豈與常人計升斗。", "文章屈宋中阻艱，子欲一身追使還。", "離騷憭慄悲草木，幽音細出芒絲間。", "陽春絕句自雲上，折楊何煩嗑然賞。", "橫經高辯一室驚，乍似遠人迷廣城。", "隔河相和獨許我，枯枿亦有條之榮。", "廖君不但西南美，誰見今人如是子。", "多髯府掾正可謔，蠻語參軍寧素喜。", "君不見古來皆醉餔糟難，沐浴何須仍振彈。", "斲冰無處用蘭枻，芙蓉木末安能攀。", "只無相報青玉案，自有平子愁關山。"]'),
('657e6a19-44c8-4ae2-ada6-4ae2499a1af7','復用前韵并答魯直明略且道見招不能往','晁補之','宋','宋诗','song-poetry','','[]','銅斗承糟醉張口，口和漁陽拍銅斗。',181,'全唐诗/poet.song.63000.json','["銅斗承糟醉張口，口和漁陽拍銅斗。", "去年拋却青竹竿，女嬃嬋媛呼我還。", "我初不解世中語，淡面那久王侯間。", "未須頭出千人上，要有廖君黄子賞。", "竹林清風前日生，豫章冥冥雲擁城。", "二人不來草木長，带鋏陸離誰與榮。", "步行奪馬從此起，談笑封侯誰氏子。", "平生不識笳鼓悲，虛讀君詩舍然喜。", "君不見大賢遠抱與俗難，何須酒盤柔指鳴哀彈。", "二人高韵已寥廓，黄鵠之飛那得攀。", "繩橋可度見可喜，家貧馬骨高三山。"]'),
('e427b090-3138-4243-ac17-779ecb03a649','復用前韵答唐公唐公有一日紙貴傳都城之句且訟其不知我也并呈魯直成季明略','晁補之','宋','宋诗','song-poetry','','[]','諸公辯壯懸河口，唾落紛紛珠百斗。',179,'全唐诗/poet.song.63000.json','["諸公辯壯懸河口，唾落紛紛珠百斗。", "井陘酣戰我已慳，赤幟忽立無由還。", "唐公斷後不容北，腹背未殊秦宛間。", "明光侯印懸天上，下有死夫緣重賞。", "書生懦志安足驚，饑死索米長安城。", "獻君賜帛等優笑，覆醤未知傳紙榮。", "泮宮先生誠國士，可是同年予二子。", "雜吟未減聽匏竹，能使窮愁發孤喜。", "君不見新聲欲至舊聲難，十指勞君千萬彈。", "平生不遇感知己，過此身外誰能攀。", "它年常侍幸見訪，不因豆落悲南山。"]'),
('a764236b-9c39-4052-b246-0e458fd314b9','復答唐公并呈魯直成季明略','晁補之','宋','宋诗','song-poetry','','[]','窮邦無以餬吾口，歲歲荒山收橡斗。',179,'全唐诗/poet.song.63000.json','["窮邦無以餬吾口，歲歲荒山收橡斗。", "商歌白石不勝寒，非爲荆州三往還。", "天下無人知我意，得君相合一言間。", "三書丞相何煩上，再見客卿寧用賞。", "願聞關中季布名，何得此聲梁楚城。", "論心四子誰許我，百金一諾茲爲榮。", "唐公才非今世士，不見聖人見君子。", "我今正似逃虛空，聞人跫然已心喜。", "君不見玉川月蝕詩律難，不獨蝦蟆遭駡彈。", "憑陵百怪付公等，青天蜀道寧容攀。", "它時鄒湛名亦好，常在我知因峴山。"]'),
('f5d41650-9dbb-460b-8be4-19f8f70a76a9','復用前韵呈明略','晁補之','宋','宋诗','song-poetry','','[]','茅焦逆訐磨虎口，何似淳于飲一斗。',179,'全唐诗/poet.song.63000.json','["茅焦逆訐磨虎口，何似淳于飲一斗。", "終軍乘傳驚漢關，何似富春投組還。", "天下同心乖出處，豈徒黄白馬毛間。", "鄙夫紛紛煩觖望，負日可堪希國賞。", "竹林居士亦何營，江花無限老江城。", "那知橋上駟馬寵，能作山間蕙帳榮。", "興國寺中四月尾，海棠雪落生紅子。", "呼門日午醉不應，昨夜君恩賜聞喜。", "君不見卒然佳會高歡難，幸值野王聊一彈。", "人生歧路易南北，明發雲散何由攀。", "知君未試餐玉法，我亦欲返焦城山。"]'),
('f5a1fbc7-14cb-44bc-855a-73972f4f7df7','家池雨中二首  其一','晁補之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','小池初鑿新得雨，一部鼓吹從何來。',64,'全唐诗/poet.song.63000.json','["小池初鑿新得雨，一部鼓吹從何來。", "有蟾正碧亂草色，時出汩沒西南隈。", "井幹跳梁百不少，洞庭魚龍何有哉。", "能歌得勝莫入月，凉夜與爾俱忘回。"]'),
('8e4388f2-c31d-471e-aa4d-8fccf69651df','家池雨中二首  其二','晁補之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','不作太白夢日邊，還同樂天賦池上。',64,'全唐诗/poet.song.63000.json','["不作太白夢日邊，還同樂天賦池上。", "池上今年有荷葉，細雨游魚噞輕浪。", "教兒讀易不應舉，幽人一爻吾得尚。", "此池便可當長江，欲榜茅齋來蕩漾。"]'),
('e11fdfa9-a753-4cc5-9f3f-4620b1dbb0da','再用韵和陳伯比二首  其一','晁補之','宋','宋诗','song-poetry','','[]','田里馮生寧屑去，湖海陳卿時肯來。',64,'全唐诗/poet.song.63000.json','["田里馮生寧屑去，湖海陳卿時肯來。", "詩書好在家四壁，蒲柳蓊然城一隈。", "騎上下山益疏矣，鯈從容出何樂哉。", "市橋十步即塵土，晚雨蕭蕭殊未回。"]'),
('2d138d3b-afc9-4aef-bbc1-61a35fdee7a7','再用韵和陳伯比二首  其二','晁補之','宋','宋诗','song-poetry','','[]','築臺危可瞰坰牧，朝來小雨猶十上。',64,'全唐诗/poet.song.63000.json','["築臺危可瞰坰牧，朝來小雨猶十上。", "雖無峻嶺有脩竹，不減山陰同放浪。", "青門正爾堪邵平，雲中何必須魏尚。", "小池更廣勿近牆，畏與濁渠同滉漾。"]'),
('6b2ac69c-1f34-485e-afdc-0bba21a52beb','用寄成季韵呈魯直','晁補之','宋','宋诗','song-poetry','','[]','懷英名高長史口，獨以一人當北斗。',179,'全唐诗/poet.song.63000.json','["懷英名高長史口，獨以一人當北斗。", "黄公崛起與之班，奄有斯名唐以還。", "文章破觚頼聖世，筆墨未逃蹊徑間。", "湖州太守諸儒長，可獨進賢無上賞。", "曾語黄公四坐驚，競吟佳句汶陽城。", "飲茶未勝薄酒傾，若人所辱伊人榮。", "鳳兮德衰衆鳥恥，陳蔡不憂顔氏子。", "窮吟百軸傳未已，短髮頻搔爲君喜。", "君不見富貴及時行樂難，雖無趙女有秦彈。", "夢中自古不識路，月在雲際勞梯攀。", "何時半嶺聞清嘯，相值蘇門百尺山。"]'),
('e63a9208-3775-4dd6-b892-66161fdfa25f','復用前韵遣懷呈魯直唐公成季明略','晁補之','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','涇水爲渠食萬口，一石論功泥數斗。',179,'全唐诗/poet.song.63000.json','["涇水爲渠食萬口，一石論功泥數斗。", "嗟涇獨不似渭閑，安流赴海又西還。", "天下楩柟盡隆棟，何如櫟社不材間。", "無能飽食猶天上，巧智憂勞緣利賞。", "我無懋功突厥名，橫身爲國作長城。", "又非石堡將軍勍，带刀奪取紫袍榮。", "世上此身愚莫比，霧縠翻慚漢童子。", "壯心雖欲强自挽，鳬足元慳續非喜。", "君不見西京對策濟時難，羞死王嬙馬上彈。", "時平鳥雀須食爾，鴻羽可用高難攀。", "從今識路窘捷徑，求我莫傍終南山。"]'),
('a4553092-314c-463a-9152-4360b68879e9','復用前韵答十五叔父任城相會見和詩任城有李白舊游處錄於詩中','晁補之','宋','宋诗','song-poetry','','[]','太華玉蓮甘適口，我欲求之青壁斗。',176,'全唐诗/poet.song.63000.json','["太華玉蓮甘適口，我欲求之青壁斗。", "崑崙不睹睹大宛，何異學射中涂還。", "平生傲世予南阮，臧否未容留齒間。", "七賢遠跡冥鴻上，咸也復幸青雲賞。", "歸來濁酒厭獨傾，疲馬却走諸任城。", "紅桃白李晚寂莫，黄菊獨暴秋陽榮。", "謫仙酒樓餘舊址，明月年年飄桂子。", "不見山東故小吏，斗酒雙魚誰共喜。", "慟哭窮涂自古難，不應更待雍門彈。", "瓜田今歲初自墾，柴車後日復誰攀。", "東阿下望有歸意，且爲子建留魚山。"]'),
('d7873ed5-74cf-4e42-aac8-687404c97039','聞文潛舍人出試院約毅父考功尋春','晁補之','宋','宋诗','song-poetry','','[]','上界官府多文書，我臞猶比山澤儒。',144,'全唐诗/poet.song.63000.json','["上界官府多文書，我臞猶比山澤儒。", "閒忙態異亡羊等，一月不見霜侵鬚。", "雖無京兆白花瀝，還有太官青玉壺。", "武安曾孫我外弟，聞君得人助君喜。", "可能餠果饜兒童，不有杯槃到鄰里。", "去年南歸飲王家，把盞猶見黄梅花。", "城南尋春成歲事，忍不省顧隨泥沙。", "世事何須還刺口，輕薄論交翻覆手。", "自憐只似永州氓，歸喜蛇存視吾缶。"]'),
('8212a8fd-82d5-45be-823e-31700309781f','次韵棠美述志','晁補之','宋','宋诗','song-poetry','','[]','仲子甘心織屨避萬鍾，淵明不肯折腰爲五斗。',164,'全唐诗/poet.song.63000.json','["仲子甘心織屨避萬鍾，淵明不肯折腰爲五斗。", "一年鴻雁識來往，終日沐猴何去取。", "甥詩意慕兩君閑，讀書要在存心久。", "平生所談性命奧，長棄不憂金石朽。", "我今頗習鶖子定，猶復晨朝怖頭走。", "刳心先擬謝聲名，不作羊鄒悽峴首。", "雲梯雨矢集無方，我已心灰同墨守。", "恐甥自是禹門鱗，未可潛逃入吾藪。", "琢磨晚覺孟光賢，畏我放言時被肘。", "甥能鋤我青門瓜，正午時來休老手。"]'),
('9592a505-f523-453d-806f-542abec8dc48','湯村逢陳安性','晁補之','宋','宋诗','song-poetry','','[]','束裝清曉來江浦，瘦馬羸童犯山雨。',160,'全唐诗/poet.song.63000.json','["束裝清曉來江浦，瘦馬羸童犯山雨。", "解鞍入寺聞鐘聲，堂上僧齋日初午。", "故人聆我足音喜，紗帽相逢坐東廡。", "別來幾日頷生須，相見驚疑更問語。", "念昨與君俱隨書，貧賤不爲人比數。", "侍郎門館乏容悅，舉子文章慚莽鹵。", "瞽言强獻亦何有，君去東州我之楚。", "可憐今日江頭路，草草逢君具雞黍。", "我貧無策未容飽，君祿雖微不猶愈。", "如今未可計得失，且作新詩致醇醑。"]'),
('39037b51-7cc9-4ba5-b1a4-0f7ec519575a','過熊耳山','晁補之','宋','宋诗','song-poetry','','[]','殺一不辜神所恫，呂母何預於樊崇。',64,'全唐诗/poet.song.63000.json','["殺一不辜神所恫，呂母何預於樊崇。", "蜂螘無王求所止，一朝積甲齊熊耳。", "兩峰相向猶眈眈，千載定林餘一龕。", "我來捫石望荆杞，此山閱人亦多矣。"]'),
('e1cb3193-acd9-4754-a0f3-eeb859f02e51','送公爲之淮南','晁補之','宋','宋诗','song-poetry','','[]','負米萬里緣其親，運甓無度憂其身。',64,'全唐诗/poet.song.63000.json','["負米萬里緣其親，運甓無度憂其身。", "讀書莫學流麥士，挾策勿比亡羊人。", "乃翁辛苦到白髮，今汝强勉當青春。", "昔時管鮑以君霸，此兩士賈寧非貧。"]'),
('960068fe-2556-45b6-b3e2-6c3d90d08537','即事呈閎中順之二年兄二首  其一','晁補之','宋','宋诗','song-poetry','','[]','蠖軒屈首詩書人，自喻適志非求伸。',64,'全唐诗/poet.song.63000.json','["蠖軒屈首詩書人，自喻適志非求伸。", "聞蟬熟寐白竹簟，見客一整烏紗巾。", "語言無味窮鬼志，香火有緣居士身。", "明年得去不汲汲，種竹待筍猶須春。"]'),
('4b69d4d4-c7f3-4750-aba2-d1a6677bcdbb','即事呈閎中順之二年兄二首  其二','晁補之','宋','宋诗','song-poetry','','[]','吾兩同年俱可人，平生一爲知己伸。',64,'全唐诗/poet.song.63000.json','["吾兩同年俱可人，平生一爲知己伸。", "何由利口似虎圈，應不拭吐煩龍巾。", "卜鄰只約二三子，看山擬分千百身。", "綠鬢哦詩欲成雪，朱顔得酒尚能春。"]'),
('0f25c6d2-b91c-4244-91e5-a22938a407c5','順之將携室行而苦雨用前韵戲之','晁補之','宋','宋诗','song-poetry','','[]','十旬九雨龍淫荒，林蟬砌螾俱悲凉。',64,'全唐诗/poet.song.63000.json','["十旬九雨龍淫荒，林蟬砌螾俱悲凉。", "豐隆不閔行澤足，猶喚脂車煩阿香。", "我知此咎非風伯，憑憑幕天爾勍敵。", "王郎行李望秋晴，莫污北飛雙鳳翼。"]'),
('057fafd4-1a62-40d7-9326-0b9c14faa5c4','飲謝公輔家','晁補之','宋','宋诗','song-poetry','','[]','皇天於春自著意，安排未遣東皇家。',64,'全唐诗/poet.song.63000.json','["皇天於春自著意，安排未遣東皇家。", "朝雨已教潤壓土，曉風更將寒約花。", "詩篇驅使到老得，酒船拍浮即生涯。", "四年逢春今日好，可是芳物年年加。"]'),
('e004997b-4759-4658-b673-8692088c7821','以蒼陵谷引水記呈毅父惠詩次韵','晁補之','宋','宋诗','song-poetry','','[]','與君暮從栖岩東，有泉鏘然發深谷。',66,'全唐诗/poet.song.63000.json','["與君暮從栖岩東，有泉鏘然發深谷。", "人言祥符行幸城無水，跨野疏泉此山足。", "後來修廢吳與李，誰其記者江休復。", "我欲重銘章聖功，借君巨筆鏨寒玉。"]'),
('2b4633e8-c8a5-4135-aa97-e767328177c5','春雪監中即事二首  其一','晁補之','宋','宋诗','song-poetry','','[]','愁雲欲雪紛來族，微霰錚鏦先入竹。',64,'全唐诗/poet.song.63000.json','["愁雲欲雪紛來族，微霰錚鏦先入竹。", "舞空蛺蝶殊未下，迸瓦明珠正相逐。", "僕夫無事困薪蘇，烏鳥不鳴依室屋。", "肺病惡寒望勸酬，桔梗作湯良可沃。"]'),
('282c51d0-ff73-4467-b955-d61ab30e3d8a','春雪監中即事二首  其二','晁補之','宋','宋诗','song-poetry','','[]','白雲自非桃李族，陽春且止聽黄竹。',64,'全唐诗/poet.song.63000.json','["白雲自非桃李族，陽春且止聽黄竹。", "江風吹葦暗天地，鷗鳥紛紛起追逐。", "請看萬瓦變璠璵，平日塵寰無此屋。", "閑居幽事亦堪論，小逕苗生土增沃。"]'),
('eac0ebd2-1ad3-447a-ae94-3a83b89e19d7','晚春二首  其一','晁補之','宋','宋诗','song-poetry','','[]','春呼群艷與偕藏，殘英風勸作清狂。',32,'全唐诗/poet.song.63000.json','["春呼群艷與偕藏，殘英風勸作清狂。", "消愁賢聖酬酢寡，破睡槍旗幽興長。"]'),
('81326fd9-0083-4e08-a73f-03efe6ebba7c','晚春二首  其二','晁補之','宋','宋诗','song-poetry','','[]','春歸風雨一朝盡，晝靜園林諸趣嘉。',32,'全唐诗/poet.song.63000.json','["春歸風雨一朝盡，晝靜園林諸趣嘉。", "蜻蜓出水群掠蚋，鵯鵊衛巢雙趁鴉。"]'),
('0522f9e0-1488-45ea-b8d1-0480c5338cbe','示張仲原秀才二首  其一','晁補之','宋','宋诗','song-poetry','','[]','去年鉅野張狂瀾，黄河水不到魚山。',32,'全唐诗/poet.song.63000.json','["去年鉅野張狂瀾，黄河水不到魚山。", "焦城有屋仲子築，它日能來相往還。"]'),
('7d704119-50ae-4a8d-9cc9-b11b85d4f031','示張仲原秀才二首  其二','晁補之','宋','宋诗','song-poetry','','[]','城頭急雨昏長川，城邊清流鷗鷺閑。',32,'全唐诗/poet.song.63000.json','["城頭急雨昏長川，城邊清流鷗鷺閑。", "城西雲黑電脚落，斜日正在城東山。"]'),
('725dc062-49c3-4edc-b14c-885c97b136c2','村居即事','晁補之','宋','宋诗','song-poetry','','[]','小麥青青大麥稀，蠶娘拾繭盈筐歸。',32,'全唐诗/poet.song.63000.json','["小麥青青大麥稀，蠶娘拾繭盈筐歸。", "放牛薄暮古堤角，三四黄鶑相趁飛。"]'),
('da15751d-1b2d-414d-849c-ddd9f656abd9','夏夜雨意','晁補之','宋','宋诗','song-poetry','','[]','凝雲遮漢月不舒，微電時照東南隅。',32,'全唐诗/poet.song.63000.json','["凝雲遮漢月不舒，微電時照東南隅。", "風條不動柱礎溼，初夜深砌吟螻蛄。"]'),
('13ed808b-506f-4d26-bc00-decfa4e0737a','蒲萄','晁補之','宋','宋诗','song-poetry','','[]','蒲萄新條易扶疏，椿花鎖碎滿庭除。',32,'全唐诗/poet.song.63000.json','["蒲萄新條易扶疏，椿花鎖碎滿庭除。", "旱乾只喜雨破土，潦潤不憂河决渠。"]'),
('ac0b90a3-5e36-4fc3-b6c3-24a58b81b764','漫成呈文潛五首  其一','晁補之','宋','宋诗','song-poetry','','[]','無心看春只欲坐，偶騎馬傍春街行。',32,'全唐诗/poet.song.63000.json','["無心看春只欲坐，偶騎馬傍春街行。", "可憐愁以草得暖，一寸心從何處生。"]'),
('9159adc7-1d33-4732-8003-d21798a9f36a','漫成呈文潛五首  其二','晁補之','宋','宋诗','song-poetry','','[]','花如怨人不近眼，深院一枝春得知。',32,'全唐诗/poet.song.63000.json','["花如怨人不近眼，深院一枝春得知。", "東風不是不愛惜，剛爲花愁真是誰。"]'),
('024ddc40-24eb-4ffe-96f3-c0c209eeaf54','漫成呈文潛五首  其三','晁補之','宋','宋诗','song-poetry','','[]','十年閉戶不作舞，爲客一整紅羅裙。',32,'全唐诗/poet.song.63000.json','["十年閉戶不作舞，爲客一整紅羅裙。", "莫倚琵琶解寫怨，朱簾垂下阿誰聞。"]'),
('20ecce1f-74bb-4f93-b533-a2303530a0d9','漫成呈文潛五首  其四','晁補之','宋','宋诗','song-poetry','','[]','平時無歡苦易醉，自怪飲樂顔先酡。',32,'全唐诗/poet.song.63000.json','["平時無歡苦易醉，自怪飲樂顔先酡。", "乃知醉人不是酒，真是情多非酒多。"]'),
('bb56e650-f567-47d8-ae1e-5f77c93e70a3','漫成呈文潛五首  其五','晁補之','宋','宋诗','song-poetry','','[]','不是生情薄桃李，廣陵一株名最高。',32,'全唐诗/poet.song.63000.json','["不是生情薄桃李，廣陵一株名最高。", "俱飛蛺蝶莫猜忌，端爲蜻蜓避伯勞。"]'),
('422598c9-7e96-4419-acd0-fceffa3fd16f','試院中秋','晁補之','宋','宋诗','song-poetry','','[]','秋風吹空雁旁午，長天無雲月呈露。',32,'全唐诗/poet.song.63000.json','["秋風吹空雁旁午，長天無雲月呈露。", "爲須通曉照清樽，莫遣中宵生薄霧。"]'),
('03e11ea5-cfe4-4ddc-8805-05094aa40364','直廬聯句','晁補之','宋','宋诗','song-poetry','','[]','上閤井泉甘若醴，蓬山點茶竹陰底。',64,'全唐诗/poet.song.63000.json','["上閤井泉甘若醴，蓬山點茶竹陰底。", "庚伏恩容午課休，宮殿初凉朝雨洗。", "身閑出飲官不嗔，日長睡足長精神。", "未慚便作蠹魚老，拔毛濟世知何人。"]'),
('38e20003-fdff-460c-8f7e-30580c4094ce','北山道中示公爲','晁補之','宋','宋诗','song-poetry','','[]','吾方賣劍日，汝正抱孫歸。',144,'全唐诗/poet.song.63000.json','["吾方賣劍日，汝正抱孫歸。", "昭代無官守，平生近釣磯。", "青山上野艇，白水到林扉。", "曬棗日猶烈，鳴枝風已威。", "荒陂民事少，迂徑客行稀。", "傷雨蟬知默，違霜雁見幾。", "卜居南縣早，收課北莊微。", "行李牧兒識，生涯田叟譏。", "烝嘗了歲事，簦屩息塵機。", "反舍從爭席，行衢莫振衣。", "潛逃多落莫，放浪少歔欷。", "文字陪吾老，功名許汝非。"]'),
('6138f44c-619c-4fb1-bfeb-3f2b445d36ca','和關彥遠雪','晁補之','宋','宋诗','song-poetry','','[]','春雨翻成雪，朝罏未覺炎。',288,'全唐诗/poet.song.63000.json','["春雨翻成雪，朝罏未覺炎。", "拂檐驚乍響，綴袖喜初霑。", "庭薄寧堪跡，空繁詎可瞻。", "正憐風共起，終恨雨同漸。", "疏箔光來細，重扉氣入嚴。", "形容樗櫟隠，意象岱嵩添。", "孤潔憐牆仞，虛明快屋檐。", "棲枯偶猜蝶，穿隙暫疑蟾。", "詩案閑飄楮，粧帷誤洒奩。", "縈盈仙縷結，瑣屑女針銛。", "屐上長干足，頤間甪里髯。", "手龜良欠藥，膚粟重遭爓。", "池憶秦龍死，河懷漢馬潛。", "三章滿嘗吊，兩騎望能占。", "有德羣污化，無威衆動恬。", "堅凝我無必，皎潔爾何嫌。", "僵卧安非介，甘餐武亦廉。", "妍辭犬子簡，拙興客兒鹽。", "摶作隋珠燦，垂爲紂箸尖。", "公車貧笑跣，洹水夢憂殲。", "氅鶴清宜繞，衣狐窶莫兼。", "且當除諷渴，未暇怯樵痁。", "戒婢當遲埽，呼奴更出覘。", "攬來真可數，消去豈堪拈。"]'),
('1bd50845-256c-49f7-89f1-94753dda9850','試院次韵呈兵部葉員外端禮并呈祠部陳員外元輿太學博士黄冕仲','晁補之','宋','宋诗','song-poetry','','[]','盛世天休沓，真人寶曆開。',288,'全唐诗/poet.song.63000.json','["盛世天休沓，真人寶曆開。", "太任當政闥，元老位公槐。", "莫盛官人始，相從試士來。", "鳴珂咸俊彥，索米獨塵埃。", "未歎官曹隔，多慚賞鑑陪。", "成川須畎澮，崇厦要條枚。", "文武中銓集，丹鉛百卷堆。", "豚魚聊可辨，皮弁不應恢。", "虎出爭亡矢，蛇成屢奪盃。", "調鍾求雅濫，烈火試珉瑰。", "綠暗驚庭葉，朱明換律灰。", "得梟夸艾捷，聞鶴悼堅摧。", "繭緒談飛麈，澠波酒挹罍。", "賡酬皆絕韵，搜索病非才。", "半是仙槎客，曾隨禹浪雷。", "遭時魚奮角，失路劍生苔。", "膽氣衝星在，詞源卷漢回。", "聲名改閭里，軒冕映輿臺。", "諼草懷堂北，燈花粲婦腮。", "凉風吹枕夢，薄雨滯城隈。", "號奏天官近，臚傳御史催。", "康衢驥鳴躍，歸檐僕讙咍。", "華省深扃鑰，衡門翳草萊。", "尚懷休假遠，別語重徘徊。"]'),
('927a320f-2623-4850-8add-cb6521d4addd','吳松道中二首  其一','晁補之','宋','宋诗','song-poetry','','[]','停舟傍河滸，四顧盡荒原。',48,'全唐诗/poet.song.63000.json','["停舟傍河滸，四顧盡荒原。", "日落狐鳴冢，天寒犬吠村。", "繫帆凌震澤，搶雨入盤門。", "悵望夫差事，吳山閟楚魂。"]'),
('e50ce634-f185-49d2-958b-7fa0cc215435','吳松道中二首  其二','晁補之','宋','宋诗','song-poetry','','[]','曉路雨蕭蕭，江鄉葉正飄。',48,'全唐诗/poet.song.63000.json','["曉路雨蕭蕭，江鄉葉正飄。", "天寒雁聲急，歲晚客程遥。", "鳥避征帆却，魚驚盪槳跳。", "孤舟宿何許，霜月繫楓橋。"]'),
('5ea11151-d6f3-44e2-b358-a83a33ec783c','濟州道中寄葉勛秀才','晁補之','宋','宋诗','song-poetry','','[]','曉路入西郊，新霜著鬢毛。',48,'全唐诗/poet.song.63000.json','["曉路入西郊，新霜著鬢毛。", "貧交借羸馬，慈母授征袍。", "野靜狐狸出，天寒雁鵠高。", "艱難憶親舊，清淚漬平皋。"]'),
('ff676a53-cc70-4768-8df5-7162d68c27e0','原上','晁補之','宋','宋诗','song-poetry','','[]','閉門遺日月，原上感年華。',48,'全唐诗/poet.song.63000.json','["閉門遺日月，原上感年華。", "久旱無場藿，重陽有野花。", "蕭蕭幾家靜，脈脈一歧賒。", "向晚悠然去，秋風馬尾斜。"]'),
('9534b15d-7beb-4bce-a48d-e4eb6d4ce63f','答劉季孫','晁補之','宋','宋诗','song-poetry','','[]','高臺擷黄菊，獨上憶同登。',48,'全唐诗/poet.song.63000.json','["高臺擷黄菊，獨上憶同登。", "灌木閑相揖，寒鴉偶自朋。", "酒憐旁舍熟，賦喜故人能。", "寂莫西風裏，籃輿興可勝。"]'),
('e9cdb0b4-c411-4fe9-9e73-4222407b1a3d','病起答關景暉','晁補之','宋','宋诗','song-poetry','','[]','卧病車馬絕，初非遺世人。',48,'全唐诗/poet.song.63000.json','["卧病車馬絕，初非遺世人。", "逍遥乍形散，邂逅却情真。", "見護屏能力，相扶竹亦神。", "閑來佐歡喜，漉酒用陶巾。"]'),
('1c1ee228-4f75-426e-b2c9-8412f9c95aa6','同魯直和普安院壁上蘇公詩','晁補之','宋','宋诗','song-poetry','','[]','畏暑聊尋寺，追凉故遶池。',48,'全唐诗/poet.song.63000.json','["畏暑聊尋寺，追凉故遶池。", "雨園鳩喚婦，風徑燕將兒。", "散篆縈簾額，留雲暗井眉。", "龍蛇動屋壁，知有長公詩。"]'),
('3e2fee99-2e3c-4918-bf7b-07d209deb8cd','次韵黄奉議序致仕作','晁補之','宋','宋诗','song-poetry','','[]','聞道家書至，山中不厭寒。',48,'全唐诗/poet.song.63000.json','["聞道家書至，山中不厭寒。", "近臣多白髮，此老獨黄冠。", "金少從供具，身輕莫據鞍。", "勞心爲功業，持與世人看。"]'),
('0d2c46d3-ca46-48e0-afc2-a6c9a535bbdb','次韵履常見貽','晁補之','宋','宋诗','song-poetry','','[]','人皆愛陳子，新雨尚能來。',48,'全唐诗/poet.song.63000.json','["人皆愛陳子，新雨尚能來。", "但使門多客，何嫌室自埃。", "弓旌無遠野，城郭有遺才。", "底日常侯舍，傳聲四輩催。"]'),
('3e8fd259-e426-4db6-85eb-d94f38408790','次韵鄧正字慎思秋日同文館九首  其一','晁補之','宋','宋诗','song-poetry','','[]','平生鄧夫子，文墨晚相依。',48,'全唐诗/poet.song.63000.json','["平生鄧夫子，文墨晚相依。", "臺閣佳聲在，湖湘爽氣歸。", "詩誇束筍密，髮歎耨苗稀。", "勤苦千秋事，川明水孕璣。"]'),
('fc34606a-4820-49d9-97ad-831d82cf52e1','次韵鄧正字慎思秋日同文館九首  其二','晁補之','宋','宋诗','song-poetry','','[]','雄深張子句，山水發天光。',48,'全唐诗/poet.song.63000.json','["雄深張子句，山水發天光。", "黄鵠愁嚴道，玄龜困呂梁。", "愛君豪穎脫，嗟我病傖囊。", "驥尾何當附，西風萬里長。"]'),
('357010fe-43a0-41d0-bc37-c90fd8c1fd16','次韵鄧正字慎思秋日同文館九首  其三','晁補之','宋','宋诗','song-poetry','','[]','蔡侯南國秀，經緯耿昭回。',48,'全唐诗/poet.song.63000.json','["蔡侯南國秀，經緯耿昭回。", "文史蛙生甑，風雲蟄起隈。", "吾君求助意，之子爲時來。", "萬縷防秋費，何如一士才。"]'),
('e7ac6d3a-eaad-439f-973e-b489b81e8eeb','次韵鄧正字慎思秋日同文館九首  其四','晁補之','宋','宋诗','song-poetry','','[]','高堂置書几，連幕與雲齊。',48,'全唐诗/poet.song.63000.json','["高堂置書几，連幕與雲齊。", "暑服猶便葛，秋槃已飣梨。", "官醪聊足醉，古錦不成題。", "空對燈花喜，重城隔夜閨。"]'),
('04f79524-5144-4c1c-b48a-d637d8b8804d','次韵鄧正字慎思秋日同文館九首  其五','晁補之','宋','宋诗','song-poetry','','[]','輟直讎書館，聯裾校藝場。',48,'全唐诗/poet.song.63000.json','["輟直讎書館，聯裾校藝場。", "騰驤來萬匹，挺拔出千章。", "直釣何妨得，餐風未必香。", "搜才頼公等，要助俗成康。"]'),
('f159b20d-f53b-4595-a737-0573a914f73a','次韵鄧正字慎思秋日同文館九首  其六','晁補之','宋','宋诗','song-poetry','','[]','憶卧蓬萊閣，同聽午唱雞。',48,'全唐诗/poet.song.63000.json','["憶卧蓬萊閣，同聽午唱雞。", "星辰望天北，簪組隔城西。", "幾日宣魚鑰，長驅響月題。", "更憑催鄧子，要剸玉如泥。"]'),
('16785578-f210-4160-b961-1dbde9dd52c0','次韵鄧正字慎思秋日同文館九首  其七','晁補之','宋','宋诗','song-poetry','','[]','風雲日夕改，秋氣襲堂闈。',48,'全唐诗/poet.song.63000.json','["風雲日夕改，秋氣襲堂闈。", "映葉無蜩響，依叢有蝶歸。", "官壺催賜酎，鄰杵急成衣。", "留滯真何補，蓴鱸興又違。"]'),
('e665333e-cb62-44b5-8506-3f1bc070da6b','次韵鄧正字慎思秋日同文館九首  其八','晁補之','宋','宋诗','song-poetry','','[]','氣入中秋勁，更傳午夜長。',48,'全唐诗/poet.song.63000.json','["氣入中秋勁，更傳午夜長。", "青燈蛾舞急，白月雁啼凉。", "羈旅生來慣，淹留久却忘。", "吟詩酬鄧子，畢昴出東方。"]'),
('95afed12-952d-4f6a-9d96-480b5b7b53b5','次韵鄧正字慎思秋日同文館九首  其九','晁補之','宋','宋诗','song-poetry','','[]','前世諸生選，平居數路開。',48,'全唐诗/poet.song.63000.json','["前世諸生選，平居數路開。", "鄉閭自相與，巖穴亦時來。", "射雉空亡矢，爲蛇更奪盃。", "千金曾市骨，聊用作龍媒。"]'),
('b05f3c99-66cd-4356-8426-f7cc60006300','聞慎思說豪塘居','晁補之','宋','宋诗','song-poetry','','[]','聞在豪塘飲，松林日百回。',48,'全唐诗/poet.song.63000.json','["聞在豪塘飲，松林日百回。", "當年鹿何往，異世鶴歸來。", "未許茅齋並，終期蠟屐陪。", "丹留杉不死，夜氣看星魁。"]'),
('bd8f4260-0b5a-4f06-b2df-4085a2749cc0','陪發運右司叔父集金山次韵','晁補之','宋','宋诗','song-poetry','','[]','報國身無用，還山計欲成。',48,'全唐诗/poet.song.63000.json','["報國身無用，還山計欲成。", "煙霞異塵世，江海慰高情。", "幸繼阮咸集，恐慚疏受聲。", "清詩逢絕景，未覺負平生。"]'),
('4a971f03-479e-4154-8dc4-fc90f3b9ed89','送趙正夫京東漕','晁補之','宋','宋诗','song-poetry','','[]','朝持使者節，騎出大明宮。',48,'全唐诗/poet.song.63000.json','["朝持使者節，騎出大明宮。", "霜拂蓬壺外，春生海岱東。", "清時憂國事，白首問民風。", "我亦何爲者，丹鉛點勘中。"]'),
('27cf259e-aadb-45ad-825d-4edf0ddb9dba','次韵八弟西園課經二首  其一','晁補之','宋','宋诗','song-poetry','','[]','禾熟秋原靜，高蟬尚遠音。',48,'全唐诗/poet.song.63000.json','["禾熟秋原靜，高蟬尚遠音。", "半荒愁雨菊，獨秀畏風林。", "老覺田原好，慵疏里巷尋。", "心知阿連勝，新向佛乘深。"]'),
('b2cc83ed-5bf2-4e16-9199-c3d41b6a48ff','次韵八弟西園課經二首  其二','晁補之','宋','宋诗','song-poetry','','[]','懶曠期陶謝，呼兒讀晉書。',48,'全唐诗/poet.song.63000.json','["懶曠期陶謝，呼兒讀晉書。", "葛巾傾泛瀲，蠟屐上嶔嶇。", "回向空門舊，揩磨意地初。", "未堪朝市隠，且欲去衡廬。"]'),
('f602adfd-2581-401a-a9f9-93f6f37ecebe','千秋嶺上','晁補之','宋','宋诗','song-poetry','','[]','永日倦高躋，盤回四望迷。',48,'全唐诗/poet.song.63000.json','["永日倦高躋，盤回四望迷。", "松根危抱石，嶺路曲隨溪。", "馬腹飛雲薄，山腰過雨低。", "陰崖不可度，誰此構長梯。"]'),
('eaf11140-bec6-4366-852a-2de8b49fbc10','蒲津繫橋次李棻韵','晁補之','宋','宋诗','song-poetry','','[]','激箭波濤上，爲梁木石雄。',48,'全唐诗/poet.song.63000.json','["激箭波濤上，爲梁木石雄。", "鐵牛驚陝右，流馬出關東。", "潦集連艘斷，冰融一水通。", "詢謀自誰可，賢有贊皇公。"]'),
('da385667-04b4-4b79-8a0c-ed50a3c993cd','次韵練定祥符聽法','晁補之','宋','宋诗','song-poetry','','[]','彌天一滴水，何處是曹溪。',48,'全唐诗/poet.song.63000.json','["彌天一滴水，何處是曹溪。", "若作聲來解，還成瞪發迷。", "白雲遮剎遠，翠竹向檐低。", "是物元非物，莊周未可齊。"]'),
('03544b30-c0cf-45a0-8cdb-2a80dddeaefd','自畫山水寄無斁題其上','晁補之','宋','宋诗','song-poetry','','[]','湘吳昔窮覽，懷抱自難忘。',48,'全唐诗/poet.song.63000.json','["湘吳昔窮覽，懷抱自難忘。", "毫素開塵牖，江山入草堂。", "寄君花縣裏，虛我竹林傍。", "何物酬斯贈，清詩要一囊。"]'),
('7398a7ab-5643-4ffb-a8c8-0f95c144a580','贈別張堯詢','晁補之','宋','宋诗','song-poetry','','[]','趣操幾前輩，詞章近古風。',48,'全唐诗/poet.song.63000.json','["趣操幾前輩，詞章近古風。", "身名沉飲外，生事放言中。", "鵠鶩從龜吉，船車送鬼窮。", "支離不征戍，高卧有奇功。"]'),
('229aff2d-58dc-4d73-a211-3a395b75cf57','寄題寶應無斁鳬舄堂二首  其一','晁補之','宋','宋诗','song-poetry','','[]','賓戲令晁子，名堂無乃迂。',48,'全唐诗/poet.song.63000.json','["賓戲令晁子，名堂無乃迂。", "何爲仍負弩，祗合便飛鳬。", "彭澤且市隠，太丘猶世儒。", "解嘲吾亦倦，繫雁一相娛。"]'),
('8144b2e2-01b8-4f67-8e80-038e4ab2ac16','寄題寶應無斁鳬舄堂二首  其二','晁補之','宋','宋诗','song-poetry','','[]','弟才方濬發，兄老更疏迂。',48,'全唐诗/poet.song.63000.json','["弟才方濬發，兄老更疏迂。", "君自軒軒鶴，吾今泛泛鳬。", "何方折腰具，能作列仙儒。", "鈞是亡羊事，清樽稍可娛。"]'),
('eebb6f84-b94d-4168-9519-787628f5f299','憶廬山示無斁弟','晁補之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','湖口西江外，廬山已目前。',48,'全唐诗/poet.song.63000.json','["湖口西江外，廬山已目前。", "太虛藏不極，彭蠡浸無邊。", "五老寧行地，香罏自供天。", "芝田隔人世，應有讀書仙。"]'),
('68c3f06b-0499-4a68-ba57-40274c9cf220','秋夜西崗聯句','晁補之','宋','宋诗','song-poetry','','[]','城南遠人跡，蟲響最先秋。',144,'全唐诗/poet.song.63000.json','["城南遠人跡，蟲響最先秋。", "河漢橫疑近，星辰爛不收。", "露濃枝上月，風駛苑中籌。", "下直身田野，相忘世馬牛。", "市聲城郭夜，遥色草茅幽。", "寂莫容還往，文章得獻酬。", "天依閶闔轉，斗直未央留。", "清洛東輸海，夷門北拱州。", "寒燈知苦織，濁酒識窮愁。", "飽食容高議，蒼顔愧薄遊。", "黑貂寒事早，青史素心遒。", "附驥容吾鈍，黄金試絡頭。"]'),
('8223818c-f3b3-46cd-a009-dc8fea47b02a','凝祥池上聯句','晁補之','宋','宋诗','song-poetry','','[]','粉垣周十里，丹碧煥神宮。',48,'全唐诗/poet.song.63000.json','["粉垣周十里，丹碧煥神宮。", "樓閣晚多雨，梧桐天早風。", "人來夕照外，鳥起白蘋中。", "何用厭城郭，滄洲佳興同。"]'),
('935ae8a6-9f1e-4147-a09e-4cc93094eb27','廷賢求賦先春亭','晁補之','宋','宋诗','song-poetry','','[]','築圃名亭盡可人，東皋百卉故先春。',64,'全唐诗/poet.song.63000.json','["築圃名亭盡可人，東皋百卉故先春。", "丘原滿目皆安在，桃李成蹊又一新。", "薙草煩君開蔣徑，漱醪容我著陶巾。", "青門瓜好平生事，欲遣朱轓便卜鄰。"]'),
('86a8acd4-d43f-4f8d-8ecb-acae374a2fae','送會稽關彥遠罷官河北','晁補之','宋','宋诗','song-poetry','','[]','君年長我二十五，偶以氣同均弟昆。',64,'全唐诗/poet.song.63000.json','["君年長我二十五，偶以氣同均弟昆。", "三歲吹沙禹河曲，一身飛艇越雲門。", "未緣狗監知才思，端向牛衣無涕痕。", "秋月圓時應待我，慧林孤磬澹朝曛。"]'),
('a14df71d-afab-44ae-accf-e7997ae0fd3b','己卯六月赴上饒之謫醇臣以詩送行次韵留別','晁補之','宋','宋诗','song-poetry','','[]','小雅思深志不悲，反騷未與昔人違。',64,'全唐诗/poet.song.63000.json','["小雅思深志不悲，反騷未與昔人違。", "五車謾苦君何益，三徑都荒我未歸。", "要過香罏䨥履步，却從彭蠡一帆飛。", "它年笑向張公子，應带煙霞滿客衣。"]'),
('72a79971-e190-4093-837a-2df292fcdecd','對雪和王仲至','晁補之','宋','宋诗','song-poetry','','[]','鸞鳳交橫逐雨華，玉城銀澗共縈斜。',64,'全唐诗/poet.song.63000.json','["鸞鳳交橫逐雨華，玉城銀澗共縈斜。", "且看霧散千峰瘴，未覺雷驚萬谷芽。", "碧落高情元物外，金閨清夢自天涯。", "寧知夜半寒歌客，煙斷鄰牆四五家。"]'),
('317aa008-21c9-4e1a-8ae9-84e651400e80','春雨呈文潛','晁補之','宋','宋诗','song-poetry','','[]','倦將烏帽障黄日，一雨新開春已融。',64,'全唐诗/poet.song.63000.json','["倦將烏帽障黄日，一雨新開春已融。", "忽驚宮瓦出新碧，更喜海棠舒小紅。", "愛酒鄰張不可奈，聽歌老謝無由同。", "春如行客祗欲去，若爲挽取須壺空。"]'),
('4877435e-012c-4a97-b23c-5150b06efce0','魚溝懷家','晁補之','宋','宋诗','song-poetry','','[]','生涯身事任東西，藥笥書囊偶自賫。',64,'全唐诗/poet.song.63000.json','["生涯身事任東西，藥笥書囊偶自賫。", "柳嫩桑柔鴉欲乳，雪消冰動麥初齊。", "沙頭晚日檣竿直，淮上春風雁鶩低。", "歸去未應芳物老，桃花如錦遍松溪。"]'),
('f83e1aeb-c523-4203-bb6c-680344188943','次韵金鄉宰韓宗恕寺丞見贈三首  其一','晁補之','宋','宋诗','song-poetry','','[]','乘濤無意犯星躔，好在琴尊且樂全。',64,'全唐诗/poet.song.63000.json','["乘濤無意犯星躔，好在琴尊且樂全。", "彭澤孤吟成小隠，蘇門雙嘯劇登仙。", "平時主父言多困，晚節揚雄學始傳。", "鮑叔可能知管子，勞君相許寄忘年。"]'),
('f7a0ee36-fd82-48f4-8a1f-daaa07fc698c','次韵金鄉宰韓宗恕寺丞見贈三首  其二','晁補之','宋','宋诗','song-poetry','','[]','蜀客高詞詫割鮮，直吞雲夢氣仍全。',64,'全唐诗/poet.song.63000.json','["蜀客高詞詫割鮮，直吞雲夢氣仍全。", "自憐單閼窮爲賦，不向元和共得仙。", "嘉論一朝傾蓋合，新詩半夜叩關傳。", "西窗却話巴山事，它日相逢憶此年。"]'),
('faa405b8-6532-44d7-baec-da78f5a72e25','次韵金鄉宰韓宗恕寺丞見贈三首  其三','晁補之','宋','宋诗','song-poetry','','[]','公子翩翩出世賢，少時術業已成全。',64,'全唐诗/poet.song.63000.json','["公子翩翩出世賢，少時術業已成全。", "閑中道義輕三事，醉裏文章敵八仙。", "客舍寒罏聊可擁，縣樓昏鼓不須傳。", "河陽花發期相過，即是新年換故年。"]'),
('803accec-da44-4ba2-80b4-cd570678f36e','出都呈十五叔父','晁補之','宋','宋诗','song-poetry','','[]','凌兢瘦馬不堪驅，塞眼紅塵暗九衢。',64,'全唐诗/poet.song.63000.json','["凌兢瘦馬不堪驅，塞眼紅塵暗九衢。", "太學虀鹽聊樂只，故園桃李且歸歟。", "上書北闕三年困，種豆南山一半蕪。", "忍志動心天相我，莫慚關吏辱陳餘。"]'),
('b02f3a72-b2a8-4555-b1e0-47c268636185','贈歐陽成判官','晁補之','宋','宋诗','song-poetry','','[]','一言子産識然明，白首憐君獨抱經。',64,'全唐诗/poet.song.63000.json','["一言子産識然明，白首憐君獨抱經。", "去馬來牛隨白日，落花飛絮得浮名。", "曳裾五府非良計，發憤三書亦漫成。", "便作歸休豈無食，木蘭垂露菊含英。"]'),
('7eef5e8a-cb95-43f1-aac4-33fdb98f1203','次韵蘇注承議天鉢元長老像前捻香','晁補之','宋','宋诗','song-poetry','','[]','蕭然方丈病儀成，蓑笠忘來一境清。',64,'全唐诗/poet.song.63000.json','["蕭然方丈病儀成，蓑笠忘來一境清。", "應作是觀寧有相，實無得度即非情。", "日當居士行時午，月在生公講處明。", "能識微言只夫子，可憐惟我最初程。"]'),
('681a6e52-0b6f-4f12-9bfe-2f1242d4b832','次韵王正甫馬陵感事','晁補之','宋','宋诗','song-poetry','','[]','風雨關河浩蕩愁，騷人憭慄對清秋。',64,'全唐诗/poet.song.63000.json','["風雨關河浩蕩愁，騷人憭慄對清秋。", "追君舊事何堪聽，投我新詩不易酬。", "紙上安知百年後，酒中聊可一生浮。", "言歸款段誰能約，正有疏頑馬少游。"]'),
('c5b03f0f-4535-4b27-9f60-73c78976c339','送長道客滑道士','晁補之','宋','宋诗','song-poetry','','[]','海山兜率事悠悠，底處仍須著力修。',64,'全唐诗/poet.song.63000.json','["海山兜率事悠悠，底處仍須著力修。", "莫認箭邊曾有鹿，安知蓑外是無牛。", "社樗共作支離病，園絮同爲汗漫游。", "亦見顔公爲言此，春風過盡不擡頭。"]'),
('80e61047-81cc-477f-a1ff-17f2e67a48d4','別關景暉二首  其一','晁補之','宋','宋诗','song-poetry','','[]','鄴王臺上幾追陪，臺上鴉鳴古甓摧。',64,'全唐诗/poet.song.63000.json','["鄴王臺上幾追陪，臺上鴉鳴古甓摧。", "每對燈前青玉笛，不辭花下白銀杯。", "九重幽夢驪駒近，百卉佳時鷤䳏催。", "更約歡呼須繼日，從教河漢卷星迴。"]'),
('1cabb8cb-970f-4dc5-88c7-36872e4b05e6','別關景暉二首  其二','晁補之','宋','宋诗','song-poetry','','[]','筆陳雲橫未易陪，雁門端見壓城摧。',64,'全唐诗/poet.song.63000.json','["筆陳雲橫未易陪，雁門端見壓城摧。", "櫟中麋出君摶飯，地上蛇成我奪杯。", "好在田園心事懶，罷休簪組鬢毛催。", "稽山爲有知章否，欲泛扁舟定却迴。"]'),
('5c7e67b4-da5f-4781-b4c7-dd5708feab17','送曹子方福建轉運判官二首  其一','晁補之','宋','宋诗','song-poetry','','[]','談經草檄鬢華生，初擁閩山傳節行。',64,'全唐诗/poet.song.63000.json','["談經草檄鬢華生，初擁閩山傳節行。", "江入桐廬青欲斷，溪從劍浦碧來迎。", "茶雖戶種租宜薄，鹽不家煎價欲平。", "要使祈招歌德意，君恩不爲遠人輕。"]'),
('a1b8df87-7b5f-46cc-8043-8244175b6fde','送曹子方福建轉運判官二首  其二','晁補之','宋','宋诗','song-poetry','','[]','侏儒未用笑先生，孟博聊堪攬轡行。',64,'全唐诗/poet.song.63000.json','["侏儒未用笑先生，孟博聊堪攬轡行。", "學有人民可嘗試，詩須山水與逢迎。", "邊夷豈識朝廷治，耕釣唯知吏政平。", "臺閣時清多俊彥，蕭生雅意未宜輕。"]'),
('56e9335f-7c99-448a-8eb0-249dbb78ad34','飲校理盛居中家次韵二首  其一','晁補之','宋','宋诗','song-poetry','','[]','騎鸞玉府盡仙真，短羽愁攀天漢濱。',64,'全唐诗/poet.song.63000.json','["騎鸞玉府盡仙真，短羽愁攀天漢濱。", "詩懶便應推老手，飲豪獨未後諸賓。", "宮壺銀箭剛知夜，籠燭金華已報春。", "倒載微吟笑兒稚，時清寧是習池人。"]'),
('70e0c342-b204-426c-98ef-60c293344a97','飲校理盛居中家次韵二首  其二','晁補之','宋','宋诗','song-poetry','','[]','一倒南齋玉宇醇，絕勝不醉楚江濱。',64,'全唐诗/poet.song.63000.json','["一倒南齋玉宇醇，絕勝不醉楚江濱。", "驪駒且莫催歸御，鴝鵒何妨屬坐賓。", "我尚少年新白髮，君須痛飲敵青春。", "未愁驅使無詩句，怕遣壺空花笑人。"]'),
('15cb8968-ce65-4e42-84ab-d55a6c0e13d0','次韵校理盛居中上元','晁補之','宋','宋诗','song-poetry','','[]','四見都城燈火春，看驅肥馬走朱輪。',64,'全唐诗/poet.song.63000.json','["四見都城燈火春，看驅肥馬走朱輪。", "天傳九奏虛群籟，海踴三山跨萬鱗。", "追賞謾逃深禁直，拜迎祗望屬車塵。", "預知短髮非歡事，只有觥船未愧人。"]'),
('c7a2a6af-4854-438b-b3e3-5a46ffb9121c','次韵蘇中丞喜文潛病間','晁補之','宋','宋诗','song-poetry','','[]','携筇過子約朝朝，况是門無百步遥。',64,'全唐诗/poet.song.63000.json','["携筇過子約朝朝，况是門無百步遥。", "午卧檐曦茶可煮，夜談窗霰栗堪燒。", "范魚何用驚生釜，鄭鹿應知夢覆蕉。", "試作文殊問居士，從今一飯久如消。"]'),
('960f3dd4-cdae-40a6-8f4a-fb9fef321ea4','鎖試呈同舍三首  其一','晁補之','宋','宋诗','song-poetry','','[]','官局悠悠共此行，來時庭菊未含英。',64,'全唐诗/poet.song.63000.json','["官局悠悠共此行，來時庭菊未含英。", "五更脫葉驚書几，一夜寒砧滿禁城。", "詩似凉風來有思，酒如清露挹無聲。", "何時驄馬催歸去，更有林端魄一生。"]'),
('98ee759d-6af8-4d6d-8945-ad461d6ddf00','鎖試呈同舍三首  其二','晁補之','宋','宋诗','song-poetry','','[]','天街初月映天河，拜敕東華走馬過。',64,'全唐诗/poet.song.63000.json','["天街初月映天河，拜敕東華走馬過。", "解榻暫如龜遇木，閉簾還似雉嬰羅。", "倦依書冊工催睡，悶倚詩篇足當歌。", "可待紛紛厭朱墨，晝閑唯有飲無何。"]'),
('60810317-2ab6-48b9-94c5-4d82ca78a1bb','鎖試呈同舍三首  其三','晁補之','宋','宋诗','song-poetry','','[]','周行櫛比未應充，薦廟方求古鼎鐘。',64,'全唐诗/poet.song.63000.json','["周行櫛比未應充，薦廟方求古鼎鐘。", "經眼乍愁千紙積，解頤聊喜一言逢。", "黄花庭檻時雖過，白酒鄰槽願可從。", "更促寄衣真似旅，曉堂初怯露寒濃。"]'),
('fca7aaf5-2a18-4caa-8721-854205cc70b0','試院呈文潛用前韵','晁補之','宋','宋诗','song-poetry','','[]','神交千古聖賢中，尚想銅山應洛鐘。',64,'全唐诗/poet.song.63000.json','["神交千古聖賢中，尚想銅山應洛鐘。", "傾蓋十年唯子舊，知音一世更誰逢。", "天如蟻磨駸駸旦，談似繰車亹亹從。", "鄰榻鄧侯那不共，擁衾百首興方濃。"]'),
('ee89a28f-9033-4f4a-b3cf-c8b7c56fcd5b','慎思聞家弟無斁捷解見貽用前韵','晁補之','宋','宋诗','song-poetry','','[]','吾弟平生辛苦同，匹雛志舉百鈞鐘。',64,'全唐诗/poet.song.63000.json','["吾弟平生辛苦同，匹雛志舉百鈞鐘。", "自慚操瑟尚不斥，勸使力田終有逢。", "青眼故人欣捷報，白頭老母喜占從。", "書林儻預西城集，釂子酣酣杏正濃。"]'),
('c1e03424-397b-4072-8d88-5850c818e04a','復用前韵寄題慎思豪塘居','晁補之','宋','宋诗','song-poetry','','[]','玉泉飛落白霞峰，散入山田畝十鐘。',64,'全唐诗/poet.song.63000.json','["玉泉飛落白霞峰，散入山田畝十鐘。", "鄧子結廬真世外，陶公脫屣更誰逢。", "鶑啼春竹風煙近，龍起秋堂雨雹從。", "誰使山人空蕙帳，蓬萊金殿興方濃。"]'),
('147f454e-5933-471a-8640-60ab6da27ed7','呈曹子方','晁補之','宋','宋诗','song-poetry','','[]','曹子金門等陸沉，壯年裘馬四方心。',64,'全唐诗/poet.song.63000.json','["曹子金門等陸沉，壯年裘馬四方心。", "檄傳白羽從沙井，詩寫紅巾遍武林。", "兵甲胸中無敵國，絲桐世外有知音。", "相逢不飲何爲者，祗作寒廳擁鼻吟。"]'),
('c50f8870-950f-4b4b-99fa-cf15e82af0ce','泗州王諫議明叟留飲','晁補之','宋','宋诗','song-poetry','','[]','雲水東遊蚤歲懷，半生塵土却教回。',64,'全唐诗/poet.song.63000.json','["雲水東遊蚤歲懷，半生塵土却教回。", "兩行堤柳關心在，一點淮山入眼來。", "北省主人誇酒好，南風稚子喜帆開。", "揚州底事牽行色，端爲瓊花芍藥催。"]'),
('1468fed8-d52f-43c9-8c22-37fbddb0fc2d','招縉雲守關彥遠教授曾彥和集平山堂次關韵','晁補之','宋','宋诗','song-poetry','','[]','蜀岡勢與蜀山通，龍虎盤挐上紫空。',64,'全唐诗/poet.song.63000.json','["蜀岡勢與蜀山通，龍虎盤挐上紫空。", "小語還憂驚太一，高堂元自在天中。", "少師楊柳無遺跡，承旨歌謠有舊風。", "斜日蕪城易興感，忘懷猶喜故人同。"]'),
('e8d517ef-29bb-4da2-b1cd-d7453a59a7b5','陪關彥遠曾彥和集龍興寺詠隋時雙鴨脚次關韵','晁補之','宋','宋诗','song-poetry','','[]','風起雷塘陵上塵，雨荒苔院兩株春。',64,'全唐诗/poet.song.63000.json','["風起雷塘陵上塵，雨荒苔院兩株春。", "樓臺有跡皆餘燼，草木無知尚見珍。", "博士獨能名玉棐，使君還許壽靈椿。", "宣城此物常充貢，誰與連艘送萬囷。"]'),
('06b22724-001d-41d4-93cc-c35e95866659','閻醇老作默齋','晁補之','宋','宋诗','song-poetry','','[]','浄名良久文殊歎，此是如來不二門。',64,'全唐诗/poet.song.63000.json','["浄名良久文殊歎，此是如來不二門。", "要識結瘖非是默，應知分別亦無言。", "一絃曾得嵇生愧，三復能令孔子尊。", "正復立談封萬戶，時清何害口瀾翻。"]'),
('d0211d3c-ffd9-4ef7-a135-40428da697bb','與曇秀師別垂二十年而後相會於金山作','晁補之','宋','宋诗','song-poetry','','[]','詩筆多生習氣牽，老來經唄亦隨緣。',64,'全唐诗/poet.song.63000.json','["詩筆多生習氣牽，老來經唄亦隨緣。", "何妨偶入東坡夢，未害閑依北固禪。", "萬里波濤憑檻語，一山風雨並窗眠。", "未甘白首塵埃地，更約相逢二十年。"]'),
('87c73caf-eb46-43c6-99c5-a6ff1c1ee95f','送曇秀師歸廬山夢齋','晁補之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','扁舟又過楚江東，廬阜霜晴翠埽空。',64,'全唐诗/poet.song.63000.json','["扁舟又過楚江東，廬阜霜晴翠埽空。", "四海五湖皆逆旅，千巖萬壑正秋風。", "會觀沙界無華處，何必茅齋是夢中。", "已悟三生舊知識，不因天竺寺前逢。"]'),
('2589951c-601c-4a2c-b357-f9bba7d584bd','戊子六月十三日曝書得史院賜筆感懷','晁補之','宋','宋诗','song-poetry','','[]','君王孝悌纂修意，丞相忠良典領宜。',64,'全唐诗/poet.song.63000.json','["君王孝悌纂修意，丞相忠良典領宜。", "却恨身爲周柱史，不令人識漢官儀。", "當年請郡新進笑，今日曝書陳迹迷。", "猶有院中宣賜筆，不妨林下醉題詩。"]'),
('a57059f1-4e4b-4f73-8bd7-07a0da2b6640','和二叔父少監入館見賜詩','晁補之','宋','宋诗','song-poetry','','[]','楩柟要是晚方成，雄朔遺風世共驚。',64,'全唐诗/poet.song.63000.json','["楩柟要是晚方成，雄朔遺風世共驚。", "屑去未驚容必去，逃名還自得高名。", "歌行元白辭濤壯，書畫鍾王筆勢精。", "乘馬輜車何足算，不將稽古愧桓榮。"]'),
('15716218-4141-4ff7-8443-baed19858433','次韵四叔父寄賀二叔父少監入館并見寄詩','晁補之','宋','宋诗','song-poetry','','[]','琅邪太守魯儒英，典校還高劉更生。',64,'全唐诗/poet.song.63000.json','["琅邪太守魯儒英，典校還高劉更生。", "已似諸荀並才子，復如群竇占詩名。", "尚吟河水憐孤姪，應與鄉人痛伯兄。", "老鶴長鳴近天漢，可容叢灌和驪庚。"]'),
('88368a85-3984-4855-aac4-8e99d7062e16','送歐誠發','晁補之','宋','宋诗','song-poetry','','[]','春風共載揚州路，屈指都疑夢夜闌。',64,'全唐诗/poet.song.63000.json','["春風共載揚州路，屈指都疑夢夜闌。", "可是重來俱白髮，只堪歸去却黄冠。", "爲郎我頼文書少，作邑君逢政令寬。", "自古江山勝塵土，莫輕故步愛邯鄲。"]'),
('90080f3b-2e3d-489a-821c-3e72cabc39c2','守蒲次新安西先寄府教授之道弟','晁補之','宋','宋诗','song-poetry','','[]','文章之子日翹翹，恐不能如豈有超。',64,'全唐诗/poet.song.63000.json','["文章之子日翹翹，恐不能如豈有超。", "助我彤襜問民俗，煩君泮水採風謠。", "預知薄宦妨同處，且可清樽約屢招。", "十月驅車漢函谷，冷雲高處望中條。"]'),
('49e37d93-2d43-4446-a2a5-6aaeede1c498','再用前韵答之道弟府教授','晁補之','宋','宋诗','song-poetry','','[]','文辭便是升堂賈，談辯寧非入幕超。',64,'全唐诗/poet.song.63000.json','["文辭便是升堂賈，談辯寧非入幕超。", "已謂囊中能出穎，那知車下正哀謠。", "但從袁盎無何飲，莫笑馮公不見招。", "伴我河山訪陳迹，明年紅紫滿陽條。"]'),
('38f8aed6-866e-48f4-81c6-0a352131f471','澠池道中寄福昌令張景良通直','晁補之','宋','宋诗','song-poetry','','[]','十年一夢間湖湘，欲往從之道阻長。',64,'全唐诗/poet.song.63000.json','["十年一夢間湖湘，欲往從之道阻長。", "可但知君愛彭澤，不應言我薄淮陽。", "馬穿崤底流泉白，鳥下關頭落照黄。", "愁作驛亭寒不寐，懷人思古九迴腸。"]'),
('3a7ce095-3287-426d-b012-9f389572b87a','次韵毅父提刑將至蒲見寄','晁補之','宋','宋诗','song-poetry','','[]','騎報山雲見旗脚，吏趨原雪沒靴翁。',64,'全唐诗/poet.song.63000.json','["騎報山雲見旗脚，吏趨原雪沒靴翁。", "朅來定坐玄猶白，捷去還憂易又東。", "他日江湖空白首，只今關隴有清風。", "登瀛契分南遷夢，十五年來事事同。"]'),
('88e81be8-834a-49f7-bc1f-ce2585b215ad','次韵毅父戶部兄游栖巖寺','晁補之','宋','宋诗','song-poetry','','[]','恐是初禪第一天，千秋龍象鎮危巔。',64,'全唐诗/poet.song.63000.json','["恐是初禪第一天，千秋龍象鎮危巔。", "坐看玉井蓮飄葉，絕勝香罏日照煙。", "點點蟻封知晉甸，紛紛雁背向秦川。", "要須浩蕩奇言稱，付與南華舊老仙。"]'),
('f1bb83b0-cb5a-4ddd-89e2-3570c79da51d','廬山','晁補之','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','丹碧沉沉虎豹閑，松幢引度九重關。',64,'全唐诗/poet.song.63000.json','["丹碧沉沉虎豹閑，松幢引度九重關。", "人間未覺渾無路，天上還驚更有山。", "瑶草紅泉供挹酌，金風白露送躋攀。", "良游自歎平生誤，便作歸來鬢已斑。"]'),
('e47db264-cac4-4953-ab34-bede795c85ef','敘舊感懷呈提刑毅父并再和六首  其一','晁補之','宋','宋诗','song-poetry','','[]','兒童豪氣自堪驚，未入鄉人月旦評。',64,'全唐诗/poet.song.63000.json','["兒童豪氣自堪驚，未入鄉人月旦評。", "叔向亦聞呼使上，子將一見便知名。", "平生蘭省追高步，老去秦川共此行。", "頼有蒲城桑落酒，高樓條華慰人情。"]'),
('4681afd5-ea10-4832-b477-84a591843eba','敘舊感懷呈提刑毅父并再和六首  其二','晁補之','宋','宋诗','song-poetry','','[]','賦成庚子尚魂驚，往事如風未暇評。',64,'全唐诗/poet.song.63000.json','["賦成庚子尚魂驚，往事如風未暇評。", "長樂鐘前偶相對，凌煙圖上等浮名。", "登車豈是君無意，襆被何妨我自行。", "更許心親遺貌敬，老來尤見舊交情。"]'),
('a643e8c9-3d15-4de4-8e51-21cc0c9eda01','敘舊感懷呈提刑毅父并再和六首  其三','晁補之','宋','宋诗','song-poetry','','[]','二人射策幾人驚，要與三蘇共入評。',64,'全唐诗/poet.song.63000.json','["二人射策幾人驚，要與三蘇共入評。", "先聖子孫多異稟，累朝圖牒有高名。", "書傳科斗猶須定，釣拂珊瑚未可行。", "子墨文章豪氣在，登臨懷古一含情。"]'),
('1e165116-0507-4467-bf3d-605627e4f567','敘舊感懷呈提刑毅父并再和六首  其四','晁補之','宋','宋诗','song-poetry','','[]','須彌納芥事堪驚，千歲聊堪一日評。',64,'全唐诗/poet.song.63000.json','["須彌納芥事堪驚，千歲聊堪一日評。", "世上相逢俱夢寐，古來何處是功名。", "簿書聽我依稀了，雲水陪君浩蕩行。", "便與此山同不朽，不應惆悵復牽情。"]'),
('290d7072-d79f-4ef3-9166-85ecbdf514b1','敘舊感懷呈提刑毅父并再和六首  其五','晁補之','宋','宋诗','song-poetry','','[]','郎潛如我未宜驚，戶部須推宰相評。',64,'全唐诗/poet.song.63000.json','["郎潛如我未宜驚，戶部須推宰相評。", "他日碧山思却走，當年紫府已收名。", "共知白髮生青鬢，未廢長歌續短行。", "樽酒不空多坐客，君家餘事足陶情。"]'),
('4aaa8ee5-fa82-40d3-9c70-66cd8e9f7cd0','敘舊感懷呈提刑毅父并再和六首  其六','晁補之','宋','宋诗','song-poetry','','[]','親見揚雄自不驚，吾人要使後人評。',64,'全唐诗/poet.song.63000.json','["親見揚雄自不驚，吾人要使後人評。", "白圭未可輕三復，小草須防得二名。", "太華聳天如劍立，黄河蹙野似軍行。", "栖遲自憶衡門後，可是登樓不稱情。"]'),
('286d1a8e-8c17-4567-910c-1c0f64dfa604','用評字韵和答府教授十二弟','晁補之','宋','宋诗','song-poetry','','[]','君詩飄舉似鴻驚，書入揚州子弟評。',64,'全唐诗/poet.song.63000.json','["君詩飄舉似鴻驚，書入揚州子弟評。", "聖世由來升俊造，少年已自得聲名。", "六經正可三冬足，萬里聊堪一日行。", "更約彌敦同姓樂，能來觸詠暢幽情。"]'),
('7791ac0a-bc2a-43a5-bf39-f90d215eaea0','次韵邠倅王正夫','晁補之','宋','宋诗','song-poetry','','[]','函谷雞鳴滿面塵，夫君泛愛尚爲親。',64,'全唐诗/poet.song.63000.json','["函谷雞鳴滿面塵，夫君泛愛尚爲親。", "清時有味俱吾黨，黄髮相看更幾人。", "物理未驚翁喪馬，世情應笑子知津。", "似聞絕塞風沙苦，只約觥船莫負春。"]'),
('744ec50b-2b40-4276-a69f-7005e8c01d76','蠖軒孤坐寄曹南教授八弟','晁補之','宋','宋诗','song-poetry','','[]','畏暑經旬不涉街，蠖軒孤坐壁生苔。',64,'全唐诗/poet.song.63000.json','["畏暑經旬不涉街，蠖軒孤坐壁生苔。", "出檐碧筍猶爭長，映戶丹榴故後開。", "雙蝶風前愁夜去，一蟬雨外送秋來。", "曹南瘦弟應相憶，白首遷兄未放回。"]'),
('c291953d-2602-4a35-807f-64474b728d06','次韵袁疇耕道見貽','晁補之','宋','宋诗','song-poetry','','[]','閱世紛紛共旅亭，歸來眼爲里人明。',64,'全唐诗/poet.song.63000.json','["閱世紛紛共旅亭，歸來眼爲里人明。", "老夫未歎嘗三已，吾子何憂取一名。", "仁義夙心成自誤，文章小道得高評。", "曲池遠市偏宜暑，携卷同來看月生。"]'),
('d9e8ea77-7efe-4596-a978-b390b28f81ba','寄懷八弟三首  其一','晁補之','宋','宋诗','song-poetry','','[]','君好作官容我隠，我專築室待君歸。',64,'全唐诗/poet.song.63000.json','["君好作官容我隠，我專築室待君歸。", "古來奇特俱安用，老去疏慵自不違。", "五府交書何怪密，雙林白社未嫌稀。", "先君門戶觀之子，葵藿吾今遯益肥。"]'),
('59850e35-08bd-4444-a2c1-347be1fd1923','寄懷八弟三首  其二','晁補之','宋','宋诗','song-poetry','','[]','平日鴒原左右手，蟨邛前後未須論。',64,'全唐诗/poet.song.63000.json','["平日鴒原左右手，蟨邛前後未須論。", "清秋淮上多詩句，白首籬邊近酒樽。", "杜舅高情篤兄弟，先君至性厚閨門。", "兩公與爾同師法，相待歸來老此園。"]'),
('6ae865db-d792-4cd1-b002-9fdaec52e197','寄懷八弟三首  其三','晁補之','宋','宋诗','song-poetry','','[]','揚州全盛吾能說，鴨脚瓊花五百年。',64,'全唐诗/poet.song.63000.json','["揚州全盛吾能說，鴨脚瓊花五百年。", "忽見山光好詩軸，却思淮浦舊漁船。", "柴荆故俗真虛老，松菊幽齋已重遷。", "便作扶藜望衡霍，清秋隨分有風煙。"]'),
('4db4e353-7728-47e7-b4d8-d31d1df3a52e','感興','晁補之','宋','宋诗','song-poetry','','[]','淵明褊志迷歸去，叔夜支辭謬養生。',64,'全唐诗/poet.song.63000.json','["淵明褊志迷歸去，叔夜支辭謬養生。", "道有窮通千世運，命無夭壽四時行。", "我能爲蝶斯同化，子亦知魚乃至情。", "謂馬謂牛無不可，楚肝越膽太分明。"]'),
('733eb486-5643-4593-b63e-564debaf5b2c','次韵留守王公喜春','晁補之','宋','宋诗','song-poetry','','[]','午窗罏火不應殘，春許花期特地寬。',64,'全唐诗/poet.song.63000.json','["午窗罏火不應殘，春許花期特地寬。", "塞雁初驚池藻暖，谷鶑猶怯井梧寒。", "未須園裏幽尋去，且更樓前遠望看。", "四牡行春定何日，亦聞鐘鼓滿城歡。"]'),
('49bd1a3c-d230-4313-bfd1-6fbf686a6f88','游華嶽歸道中望仙掌','晁補之','宋','宋诗','song-poetry','','["\u534e\u5c71"]','深巖踏遍尋歸路，仙掌依然在碧虛。',64,'全唐诗/poet.song.63000.json','["深巖踏遍尋歸路，仙掌依然在碧虛。", "無限游人重駐馬，豈惟狂客倒騎馿。", "挂圖天漢朝霞上，落影秦關夕照餘。", "千古全生纔一士，可憐登覽盡丘墟。"]'),
('fbc3865e-e267-4394-b26f-090d6340fcf4','潼關道中','晁補之','宋','宋诗','song-poetry','','[]','塵土長安古道深，潼關依舊接桃林。',64,'全唐诗/poet.song.63000.json','["塵土長安古道深，潼關依舊接桃林。", "使君驄馬來何後，道士青牛去莫尋。", "春半河山猶寂莫，日長坑阪正崎嶔。", "平生冷笑元龍誤，老覺求田負寸心。"]'),
('eaae9bbc-4162-4bb9-8950-d62ff3b92074','自蒲赴湖早行作','晁補之','宋','宋诗','song-poetry','','[]','小隠幽情薄宦身，五更騎馬壽安塵。',64,'全唐诗/poet.song.63000.json','["小隠幽情薄宦身，五更騎馬壽安塵。", "春如流水行隨客，曉與青山氣逼人。", "報國丹心千載事，對花霜鬢一番新。", "秦吳絕域從來恨，我已能知莫問津。"]'),
('c42187b6-2c0b-4a52-957d-125bad53d124','罷蒲乾濠道中寄府教授之道弟','晁補之','宋','宋诗','song-poetry','','[]','衝寒到郡待花開，花未開時却遣回。',64,'全唐诗/poet.song.63000.json','["衝寒到郡待花開，花未開時却遣回。", "敢意三年容我隠，只如千里訪君來。", "二崤轂擊何爲者，五老雲霾安在哉。", "更約劖詩猿虎谷，它年重過埽莓苔。"]'),
('2b0e8239-8250-4572-80b0-59bc163b2bac','次韵文潛尉福昌時壁間清暑亭詩','晁補之','宋','宋诗','song-poetry','','[]','梅福當年守此官，荆山誰見韞琅玕。',64,'全唐诗/poet.song.63000.json','["梅福當年守此官，荆山誰見韞琅玕。", "人如修竹三冬好，詩與清溪九夏寒。", "未信簪裳妨小隠，蚤時雷雨起深蟠。", "春風攬轡河陽縣，痛飲狂歌憶舊年。"]'),
('0be7fea3-4ea6-4694-8963-2c4b35c52c19','赴蒲道中寄洛倅王定國','晁補之','宋','宋诗','song-poetry','','[]','莫嫌馬上過春風，得句桃溪柳澗中。',64,'全唐诗/poet.song.63000.json','["莫嫌馬上過春風，得句桃溪柳澗中。", "王事勤君急星火，客程驅我正萍蓬。", "朅來尚可輕千里，歸去何妨共兩翁。", "學道如今有微力，作官求了不求功。"]'),
('47f9bd7c-bc10-4a74-8b02-556c3a3e8f8e','再寄定國','晁補之','宋','宋诗','song-poetry','','[]','河南少尹古臞仙，銷盡新緣窘舊緣。',64,'全唐诗/poet.song.63000.json','["河南少尹古臞仙，銷盡新緣窘舊緣。", "草字更無千載聖，談言自有一家天。", "遠游輕世唯何甚，少貶求容否不然。", "選壯坐狂俱齟齬，社樗元自可忘年。"]'),
('46f8f017-ad1e-45c4-8ad6-c3fad1232935','答閎中順之','晁補之','宋','宋诗','song-poetry','','[]','黄卷翛然遇古人，千秋遺恨一朝伸。',64,'全唐诗/poet.song.63000.json','["黄卷翛然遇古人，千秋遺恨一朝伸。", "久乾文舉尊中酒，虛負淵明頭上巾。", "纓冠未暇念同室，閉眼自欲觀吾身。", "幸有元和文似錦，不妨白雪和陽春。"]'),
('a0cbadb7-a632-4f9d-b315-97466a86805d','自蒲赴湖至板橋逢杜謀伯','晁補之','宋','宋诗','song-poetry','','[]','二年兩度踏京塵，猶喜常逢杜子春。',64,'全唐诗/poet.song.63000.json','["二年兩度踏京塵，猶喜常逢杜子春。", "文學老來從舊日，金蘭同好更何人。", "身慚隨檄終難强，計欲歸耕未敢陳。", "正是桃花紅似血，不應無酒但霑巾。"]'),
('de67e52d-50dc-4dd8-989b-6f77f3a18cd9','和石明叔喜雪','晁補之','宋','宋诗','song-poetry','','[]','解凍南風故未薰，六英先歲舞車塵。',64,'全唐诗/poet.song.63000.json','["解凍南風故未薰，六英先歲舞車塵。", "盡消日觀千巖雪，初破江梅一萼春。", "立召金閨通籍客，更呼花艷大堤人。", "使君日飲無功業，同樂何妨亦爲民。"]'),
('1e762506-0c65-455a-ac0c-fdbafa5b7df6','次韵韓求仁南臺朝請晚過南湖見寄','晁補之','宋','宋诗','song-poetry','','[]','浮花浪蕊信東西，何許尋芳去自遲。',64,'全唐诗/poet.song.63000.json','["浮花浪蕊信東西，何許尋芳去自遲。", "流景不須驚石火，寸田應已長瓊枝。", "想君清興聊堪發，遣我憂心久欲夷。", "便作崔丞日臨水，鳬行擿尾不須知。"]'),
('0d079010-2cbc-49b6-97a1-63f73133d096','再用前韵和答','晁補之','宋','宋诗','song-poetry','','[]','當時同赴飲城西，傾蓋論心已恨遲。',64,'全唐诗/poet.song.63000.json','["當時同赴飲城西，傾蓋論心已恨遲。", "湖海可無年少氣，雪霜還有歲寒枝。", "功傳汗竹藏王府，詩入文弢動島夷。", "不會書生安用此，眼前睫固未曾知。"]'),
('fa29c64c-926d-4201-a70f-5b270f928653','用前韵答李行正教授','晁補之','宋','宋诗','song-poetry','','[]','見我淮南初召西，重來學館尚棲遲。',64,'全唐诗/poet.song.63000.json','["見我淮南初召西，重來學館尚棲遲。", "未容小隠通三徑，聊可卑飛共一枝。", "飲罷玉山方突兀，賦成筆陳已淫夷。", "霜荷葉歎青衫舊，聞子修身自畏知。"]'),
('d87245e1-b5e9-49fc-a03c-544aaf977d37','次韵和求仁不赴照碧堂會呈無愧之作','晁補之','宋','宋诗','song-poetry','','[]','政成歡誦沸田萊，留鑰雍容更上才。',64,'全唐诗/poet.song.63000.json','["政成歡誦沸田萊，留鑰雍容更上才。", "繚郭平湖從昔好，倚天朱檻爲誰開。", "曳裾况是他年舊，倒載何妨盡日陪。", "自有登高能賦客，可容清坐詠南臺。"]'),
('cace9cc6-1730-437e-a446-50b5edac1825','求仁復示怨句次韵','晁補之','宋','宋诗','song-poetry','','[]','聞說高情久沉寥，縶維誰與永今朝。',64,'全唐诗/poet.song.63000.json','["聞說高情久沉寥，縶維誰與永今朝。", "五車猶累方書好，萬物先從辯說彫。", "已向季咸心獨醉，更緣順子意都消。", "清秋璧月凉如水，莫遣纖雲翳紫霄。"]'),
('379dbcef-d278-4a48-ac94-336b39980443','元符戊寅與無斁弟卜居緡城東述情','晁補之','宋','宋诗','song-poetry','','[]','四海一居何處卜，北窗祗取見家山。',64,'全唐诗/poet.song.63000.json','["四海一居何處卜，北窗祗取見家山。", "要無名利來心曲，便有園林出世間。", "拙宦莫興三黜歎，老歸未厭百年閑。", "先君餘慶期之子，吾駕如今不可還。"]'),
('a5b5a924-4072-4fc1-b3b2-32d514a3bd11','次韵信守李秬二首  其一','晁補之','宋','宋诗','song-poetry','','[]','誰榜鈴齋作面山，晦明終日卷簾看。',64,'全唐诗/poet.song.63000.json','["誰榜鈴齋作面山，晦明終日卷簾看。", "賦成夜燭纔銷寸，衙退朝曦未半竿。", "枉渚孤吟愁旅雁，蘇門雙嘯駭朱鸞。", "平生五袴何須詠，一借黄鍾變谷寒。"]'),
('12a873bc-11fe-45f2-bf69-b26c587a80f8','次韵信守李秬二首  其二','晁補之','宋','宋诗','song-poetry','','[]','愛山何必俟歸山，簿領忙時撥置看。',64,'全唐诗/poet.song.63000.json','["愛山何必俟歸山，簿領忙時撥置看。", "閶闔自應行發軔，珊瑚終未拂垂竿。", "樽中屢許陪文舉，廡下猶堪寄伯鸞。", "便作功成同范蠡，白鷗盟誓不教寒。"]'),
('7cb4e542-2810-40af-a5e8-ef8cb322820d','再和嘉父見貽','晁補之','宋','宋诗','song-poetry','','[]','使君心賞在高山，櫟社寧煩匠石看。',64,'全唐诗/poet.song.63000.json','["使君心賞在高山，櫟社寧煩匠石看。", "能似鼠多愁渡谷，仕如鮎鈍笑緣竿。", "威儀披霧窺文豹，音韵當衢聽玉鸞。", "曾共廣陵花下醉，綈袍應歎一何寒。"]'),
('903d48a6-c6b9-4a1a-9675-97b8005d861a','次韵嘉父喜雪','晁補之','宋','宋诗','song-poetry','','[]','六出先春兆物華，故撩高韵發車斜。',64,'全唐诗/poet.song.63000.json','["六出先春兆物華，故撩高韵發車斜。", "散榆天上齊飛筴，布玉畦中盡吐芽。", "梁苑俊遊風不極，剡溪清泛月無涯。", "雄豪樂事幽人詠，都屬江南太守家。"]'),
('9d97e341-f951-430c-ac15-b37fe9e0dff6','次韵信倅練定夢雪中過王侍郎','晁補之','宋','宋诗','song-poetry','','[]','夢覓毗耶看雨華，玉城銀澗過縈斜。',64,'全唐诗/poet.song.63000.json','["夢覓毗耶看雨華，玉城銀澗過縈斜。", "乍疑霧廓千峰障，未覺雷驚萬谷芽。", "碧落清談元物外，金閨高興共天涯。", "寒雞喚起新詩就，誰憶袁安正卧家。"]'),
('ea08f1f4-0e8c-43d0-bbfc-9942d7dbd6aa','次韵李秬靈山亭宴集寵戲之句','晁補之','宋','宋诗','song-poetry','','[]','勝游誰繼竹林賢，峴首高情自邈然。',64,'全唐诗/poet.song.63000.json','["勝游誰繼竹林賢，峴首高情自邈然。", "寶剎千尋出天半，靈山三面落樽前。", "梅花摘得寧煩驛，桃葉呼來不用船。", "南楚何須說窮巷，且陪鈴閤聽鵾絃。"]'),
('0bd8c21a-1772-4c7d-81f9-37be032c0f96','次韵李秬梅花','晁補之','宋','宋诗','song-poetry','','[]','寒巖幽霧不曾開，殘雪猶封宿草荄。',64,'全唐诗/poet.song.63000.json','["寒巖幽霧不曾開，殘雪猶封宿草荄。", "一萼故應先臘破，百花渾未覺春來。", "慚非上苑青房比，誤作唐昌碎月猜。", "常恨清溪照疏影，橫斜還許落金盃。"]'),
('f9785e95-c884-4e71-a5e7-2ee2fceacf6a','次韵李秬祥符軒','晁補之','宋','宋诗','song-poetry','','[]','雲端紅粉拊雕欄，謝守綸巾語笑間。',64,'全唐诗/poet.song.63000.json','["雲端紅粉拊雕欄，謝守綸巾語笑間。", "游客乍驚人外境，居僧初識面前山。", "暫來猶足留公賞，借與真堪著我頑。", "鈴閤多餘賓從少，誰教缾盎不曾閑。"]'),
('e1f2e2ff-5f6f-4f2d-bcae-192301c7160f','次韵李秬重修宴亭','晁補之','宋','宋诗','song-poetry','','[]','壁間雙記快沉冥，山畔譙門水畔亭。',64,'全唐诗/poet.song.63000.json','["壁間雙記快沉冥，山畔譙門水畔亭。", "相國名因稽古白，使君眼爲好賢青。", "廢堤不復風搖柳，新檻依然月滿汀。", "羈旅從公厭游樂，欲圖佳致作幽屏。"]'),
('bf74dd48-374d-4112-bb50-2aaf7716891c','次韵李秬新庵','晁補之','宋','宋诗','song-poetry','','[]','無心何用說心灰，庵在青蘿綠篠隈。',64,'全唐诗/poet.song.63000.json','["無心何用說心灰，庵在青蘿綠篠隈。", "自可談間公事了，不妨閑處道書開。", "更携邀月清樽上，只著登山小屐來。", "桃李他年應勿剪，使君嘉譽在閨臺。"]'),
('3243482f-379b-4e97-af92-efd5c794103b','次韵李秬新移牡丹二首  其一','晁補之','宋','宋诗','song-poetry','','[]','史君著意與深培，爲向吳宮好處來。',64,'全唐诗/poet.song.63000.json','["史君著意與深培，爲向吳宮好處來。", "得地且從三月暖，明年應更十分開。", "溱傍芍藥羞香骨，江裏芙蓉妬艷腮。", "雲雨鴻龍總非比，沉香亭北漫相猜。"]'),
('8be7bd6d-4c4f-4ab0-b1e0-ee84e55b696b','次韵李秬新移牡丹二首  其二','晁補之','宋','宋诗','song-poetry','','[]','笑倚東風幾百般，忽疑洛渚在江干。',64,'全唐诗/poet.song.63000.json','["笑倚東風幾百般，忽疑洛渚在江干。", "玉容可得朝朝好，金盞須教一一乾。", "送目漢皋行已失，斷魂巫峽夢將殘。", "七閩溪畔防偷本，四照亭邊更著欄。"]'),
('2e5fbbb7-a1cc-4f98-909b-6ebf30a36752','次韵李秬約賞牡丹','晁補之','宋','宋诗','song-poetry','','[]','夭紅濃綠總教回，更待清明穀雨催。',64,'全唐诗/poet.song.63000.json','["夭紅濃綠總教回，更待清明穀雨催。", "一朵故應偏晚出，百花渾似不曾開。", "常誇西洛青屏簇，久說南滁紫線堆。", "任是無情還有意，不知千里爲誰來。"]'),
('43b7abf9-ec4e-4fa0-90d7-c1216e2ad468','次韵李秬雙頭牡丹','晁補之','宋','宋诗','song-poetry','','[]','寒食春光欲盡頭，誰拋兩兩路傍毬。',64,'全唐诗/poet.song.63000.json','["寒食春光欲盡頭，誰拋兩兩路傍毬。", "二喬新獲吳宮怯，雙隗初臨晉帳羞。", "月底故應相伴語，風前各是一般愁。", "使君腹有詩千首，爲爾情如篆印繆。"]'),
('957fe95c-8a5b-4d04-9553-88fa2185c8e2','次韵李秬賞花','晁補之','宋','宋诗','song-poetry','','[]','天香國色競新奇，初過清明未覺稀。',64,'全唐诗/poet.song.63000.json','["天香國色競新奇，初過清明未覺稀。", "困舞尚迎風嫋嫋，醉粧猶弄日暉暉。", "飄零洛下千金價，慚愧江南百草菲。", "謝守多才最憐爾，百篇能伴羽觴飛。"]'),
('8fd477c2-185b-474d-a473-c1f47fe3c2db','次韵李秬酴醾','晁補之','宋','宋诗','song-poetry','','[]','夭紅瑣碎競春嬌，後出何妨便奪標。',64,'全唐诗/poet.song.63000.json','["夭紅瑣碎競春嬌，後出何妨便奪標。", "雲鶴嬉晴來萬隻，玉龍驚震上千條。", "蓐收晃蕩風前仗，萼綠飄翩月下綃。", "曾向瓊林亭畔見，天涯相遇一魂銷。"]'),
('1c34bff7-38de-4a2c-86aa-69319b41fca0','立春日呈通守資中通直','晁補之','宋','宋诗','song-poetry','','[]','搖軒柳態未應還，正在憑高望遠間。',64,'全唐诗/poet.song.63000.json','["搖軒柳態未應還，正在憑高望遠間。", "一夜春風吹北渚，清晨佳氣滿南山。", "動頭樂事從今數，信手詩章莫放閑。", "但惜濉陽蔡公子，鶑花爛漫向京關。"]'),
('fe05455b-3ab7-48ac-834d-3b0540940482','題文潛詩冊後','晁補之','宋','宋诗','song-poetry','','[]','君詩容易不著意，忽似春風開百花。',64,'全唐诗/poet.song.63000.json','["君詩容易不著意，忽似春風開百花。", "上苑離宮曾絕艷，野牆荒徑故幽葩。", "愜心芻豢非雜俎，垂世江河自一家。", "頭白昏昏醉眠處，憶君頻夜夢天涯。"]'),
('1a4a894b-8d0c-43e5-a4d5-f720ac52e1f8','次韵杜天達見寄','晁補之','宋','宋诗','song-poetry','','[]','冷屋寒舟兩處懷，一封歸信隔年開。',64,'全唐诗/poet.song.63000.json','["冷屋寒舟兩處懷，一封歸信隔年開。", "愁容頓與河冰泮，佳思先隨岸柳來。", "射雉便甘忘我矢，畫蛇何怪奪君杯。", "端知雪裏清吟好，未減山陰興盡回。"]'),
('0609fd9b-c2b3-4d2e-b683-997ffcbc3548','景修二十歲褎爲鄉舉之首晚乃尉青田無不遇色其里人晁補之爲賦五十六字以別且勉之','晁補之','宋','宋诗','song-poetry','','[]','一尉三千五百里，昔人嘗已歎沉英。',64,'全唐诗/poet.song.63000.json','["一尉三千五百里，昔人嘗已歎沉英。", "陸機文賦成童妙，梅福官資向老清。", "盡說江山多勝事，且臨風月慰高情。", "它年見我長安道，貨藥無心更避名。"]'),
('23020e1e-4507-4734-8676-f22430b76fb1','赴元老劉園之集呈十二朝請十五推官二叔父兼呈元老邦式諸公','晁補之','宋','宋诗','song-poetry','','[]','故鄉等作異鄉愁，常笑吾生不自謀。',64,'全唐诗/poet.song.63000.json','["故鄉等作異鄉愁，常笑吾生不自謀。", "百日狂風春草草，十年歸夢客悠悠。", "倦游情話陪諸父，老罷親鋤學故侯。", "得坎乘流兩皆可，名亭應不用三休。"]'),
('13635581-84fc-4a19-b4ef-2723f952a66b','次韵棠美甥晝眠','晁補之','宋','宋诗','song-poetry','','[]','炎歊暫卧北窗凉，更覺甘如飯稻粱。',64,'全唐诗/poet.song.63000.json','["炎歊暫卧北窗凉，更覺甘如飯稻粱。", "宰我糞牆譏敢避，孝先經笥謔兼忘。", "憂虞心謝知更雁，安穩身如掛角羊。", "要識熙熙不爭競，華胥別是一仙鄉。"]'),
('507d9555-9d01-4dc7-b7c1-77213c40fba5','和王定國見寄','晁補之','宋','宋诗','song-poetry','','[]','請說當年王武子，淮南別乘謫仙人。',64,'全唐诗/poet.song.63000.json','["請說當年王武子，淮南別乘謫仙人。", "自從金馬還通籍，直恐瓊花便不春。", "遺愛誰方府中步，舊時獨埽壁間塵。", "平山送目思公子，自許詩成覺有神。"]'),
('b49fab8c-48f2-45dd-a741-d520036a83fe','和歐陽宣德經野步','晁補之','宋','宋诗','song-poetry','','[]','遡風何敢祝淮神，青律飛灰氣自醇。',64,'全唐诗/poet.song.63000.json','["遡風何敢祝淮神，青律飛灰氣自醇。", "顧我衰容唯殢酒，因君佳句始知春。", "山中桂子年年好，觀裏桃英日日新。", "延對彤廷須努力，詹生學問及昌辰。"]'),
('7a33a73d-6727-414f-ad33-b038d9097ed4','國子監暮歸','晁補之','宋','宋诗','song-poetry','','[]','杖屨清晨往，縑囊薄暮歸。',24,'全唐诗/poet.song.63000.json','["杖屨清晨往，縑囊薄暮歸。", "閑官廳事冷，蝴蝶上階飛。"]'),
('de924a9f-76ca-46d5-a437-5cf9e8fe14fb','答李令','晁補之','宋','宋诗','song-poetry','','[]','知音慚李令，問我復何爲。',24,'全唐诗/poet.song.63000.json','["知音慚李令，問我復何爲。", "道義惟添睡，功名只有詩。"]'),
('ec6561f1-4efe-42d4-a2f9-1af107a61438','身世謾悠哉  其一','晁補之','宋','宋诗','song-poetry','','[]','月墮孤村露合，日出高原霧開。',28,'全唐诗/poet.song.63000.json','["月墮孤村露合，日出高原霧開。", "道逐故河西去，人將新雁南來。"]'),
('64036e97-cd8a-4987-abe3-02505a8f71a6','身世謾悠哉  其二','晁補之','宋','宋诗','song-poetry','','[]','三徑蔣生里第，再見虞君客卿。',28,'全唐诗/poet.song.63000.json','["三徑蔣生里第，再見虞君客卿。", "多病增予歸思，少年許子高名。"]'),
('8f22f581-0cf4-42cd-b3eb-a217b644ab8a','身世謾悠哉  其三','晁補之','宋','宋诗','song-poetry','','[]','林下囊裝夙興，雲間鴻雁悲鳴。',28,'全唐诗/poet.song.63000.json','["林下囊裝夙興，雲間鴻雁悲鳴。", "行役正嗟予弟，言旋當復諸兄。"]'),
('a91d054d-70aa-4565-8c12-fb4cbbe5a6ee','館宿','晁補之','宋','宋诗','song-poetry','','[]','殘雪封條未乾，蘭臺襆被春寒。',28,'全唐诗/poet.song.63000.json','["殘雪封條未乾，蘭臺襆被春寒。", "斜日房櫳吏散，鳴鳩飛下欄干。"]'),
('2078b672-9734-4bba-b600-157d704d4621','季夏即事','晁補之','宋','宋诗','song-poetry','','[]','紅葵有雨長穗，青棗無風壓枝。',28,'全唐诗/poet.song.63000.json','["紅葵有雨長穗，青棗無風壓枝。", "溼礎人霑汗際，蒸林蟬烈號時。"]'),
('35e986eb-27a9-412b-9eab-d53ddc8b4334','新城塔山對雨二首  其一','晁補之','宋','宋诗','song-poetry','','[]','山外圓天一鏡開，山頭雲起似浮埃。',32,'全唐诗/poet.song.63000.json','["山外圓天一鏡開，山頭雲起似浮埃。", "松吟竹舞水紋亂，坐見溪南風雨來。"]'),
('c8f7165c-e39e-45d9-9f50-603def21d42f','新城塔山對雨二首  其二','晁補之','宋','宋诗','song-poetry','','[]','竹枝草履步蒼苔，山上孤亭四牖開。',32,'全唐诗/poet.song.63000.json','["竹枝草履步蒼苔，山上孤亭四牖開。", "煙雨濛濛溪又急，小篷時轉碧灘來。"]'),
('7ae2fa0c-8297-4182-879c-5e1db89c53a8','同柳戒之夜過三學院','晁補之','宋','宋诗','song-poetry','','[]','步月尋溪過佛齋，溪邊石蘚溼芒鞋。',32,'全唐诗/poet.song.63000.json','["步月尋溪過佛齋，溪邊石蘚溼芒鞋。", "虛窗獨卧聽松竹，半夜一山風雨來。"]'),
('ee0df081-a3b0-4479-8baf-1806351716a9','汴堤暮雪懷徑山澄慧道人','晁補之','宋','宋诗','song-poetry','','[]','朔風吹雪亂霑襟，走馬投村日向沉。',32,'全唐诗/poet.song.63000.json','["朔風吹雪亂霑襟，走馬投村日向沉。", "遥想道人敲石火，冷杉寒竹五峰深。"]'),
('5717bdea-f713-4ef0-bce1-a06f7b05fada','送李知章下第歸河北','晁補之','宋','宋诗','song-poetry','','[]','鬭雞擊劍鄴王臺，萬古英雄死不埋。',32,'全唐诗/poet.song.63000.json','["鬭雞擊劍鄴王臺，萬古英雄死不埋。", "子去悲歌宜有和，露螢白首亦常材。"]'),
('056ad4c6-ab13-49d8-bc83-551227acf552','晚發長蘆','晁補之','宋','宋诗','song-poetry','','[]','船頭勾曲洪濤外，船尾長蘆白霧中。',32,'全唐诗/poet.song.63000.json','["船頭勾曲洪濤外，船尾長蘆白霧中。", "千里山容初上日，一江帆影盡乘風。"]'),
('6e21255e-204f-4fb4-a201-a22eda923d04','晚雪示閻仲孺','晁補之','宋','宋诗','song-poetry','','[]','拂檐點砌靜如沙，無限寒林頃刻花。',32,'全唐诗/poet.song.63000.json','["拂檐點砌靜如沙，無限寒林頃刻花。", "明日窮檐深一尺，不知何處覓袁家。"]'),
('0cafcf76-61ba-483b-9c47-117b0e4d43c8','村居即事','晁補之','宋','宋诗','song-poetry','','[]','十載京塵化客衣，故園榆柳識春歸。',32,'全唐诗/poet.song.63000.json','["十載京塵化客衣，故園榆柳識春歸。", "深村芳物無由覓，蝴蝶雙尋麥隴飛。"]'),
('dc42a8c7-d259-40db-b8bd-6c5b506ea23b','流民','晁補之','宋','宋诗','song-poetry','','[]','生涯不復舊桑田，瓦釜荆籃止道邊。',32,'全唐诗/poet.song.63000.json','["生涯不復舊桑田，瓦釜荆籃止道邊。", "日暮榆園拾青莢，可憐無數沈郎錢。"]'),
('8d2a7d96-4d26-448c-b109-cb2c470ef2b3','先塋治事歸','晁補之','宋','宋诗','song-poetry','','[]','先人昔慕栖山樂，賤子今懷陟岵悲。',32,'全唐诗/poet.song.63000.json','["先人昔慕栖山樂，賤子今懷陟岵悲。", "柏葉初生石牆短，况無金带買豐碑。"]'),
('e9ecf0de-efae-46e9-834f-e922c47d0bf5','陌上花八首  其一','晁補之','宋','宋诗','song-poetry','','[]','郊外金軿步帳隨，道邊游女看王妃。',32,'全唐诗/poet.song.63000.json','["郊外金軿步帳隨，道邊游女看王妃。", "內官走馬傳書報，陌上花開緩緩歸。"]'),
('6a7c6e26-3c76-4fef-937c-e6f82084f6f0','陌上花八首  其二','晁補之','宋','宋诗','song-poetry','','[]','朝雲暮雨山頭宅，暖日晴風陌上花。',32,'全唐诗/poet.song.63000.json','["朝雲暮雨山頭宅，暖日晴風陌上花。", "絳幕何妨行緩緩，送春歸盡妾還家。"]'),
('8e407847-4d46-4687-9f5a-d52c0d6b833a','陌上花八首  其三','晁補之','宋','宋诗','song-poetry','','[]','娘子歌傳樂府悲，當年陌上看芳菲。',32,'全唐诗/poet.song.63000.json','["娘子歌傳樂府悲，當年陌上看芳菲。", "曼聲更緩何妨緩，莫似東風火急歸。"]'),
('f89550ef-1027-4491-b266-0050db637b9a','陌上花八首  其四','晁補之','宋','宋诗','song-poetry','','[]','荆王夢罷已春歸，陌上花隨暮雨飛。',32,'全唐诗/poet.song.63000.json','["荆王夢罷已春歸，陌上花隨暮雨飛。", "却喚江船人不識，杜秋紅淚滿羅衣。"]'),
('ddffb74c-c831-4a1c-bf31-1c5a26c8e0a7','陌上花八首  其五','晁補之','宋','宋诗','song-poetry','','[]','吳歌白紵怨芳菲，腸斷懷王去不歸。',32,'全唐诗/poet.song.63000.json','["吳歌白紵怨芳菲，腸斷懷王去不歸。", "陌上如今小花伴，山前山後白鷳飛。"]'),
('8d52f67f-b0b9-4931-9ed4-35f8b92a5b94','陌上花八首  其六','晁補之','宋','宋诗','song-poetry','','[]','臨安城郭半池臺，曾是香塵撲面來。',32,'全唐诗/poet.song.63000.json','["臨安城郭半池臺，曾是香塵撲面來。", "不見當時翠軿女，今年陌上又花開。"]'),
('52b399b4-6c6e-4384-a6ae-93f752216228','陌上花八首  其七','晁補之','宋','宋诗','song-poetry','','[]','雲母蠻牋作信來，佳人陌上看花回。',32,'全唐诗/poet.song.63000.json','["雲母蠻牋作信來，佳人陌上看花回。", "妾行不似東風急，爲報花須緩緩開。"]'),
('db682858-4729-46a1-878e-4405c081a12b','陌上花八首  其八','晁補之','宋','宋诗','song-poetry','','[]','陌上偷來爲看花，饒聲鸚鵡莫夭斜。',32,'全唐诗/poet.song.63000.json','["陌上偷來爲看花，饒聲鸚鵡莫夭斜。", "犢車緩緩隨芳草，不去桃源阿母家。"]'),
('f862d933-ba0e-4a24-ab06-7d0d026610dd','外舅杜寺丞永城守水作詩寄呈','晁補之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','雪消冰動看通津，草長江南岸岸春。',32,'全唐诗/poet.song.63000.json','["雪消冰動看通津，草長江南岸岸春。", "莫唱龍舟五更曲，揚州楊柳解愁人。"]'),
('b46f430d-0271-4b8e-a055-8148b2c0612b','都門','晁補之','宋','宋诗','song-poetry','','[]','飄零何處是生涯，瘦馬都門踏落花。',32,'全唐诗/poet.song.63000.json','["飄零何處是生涯，瘦馬都門踏落花。", "芳物攪心看不得，綈袍遮眼畏風沙。"]'),
