('3d895378-6e9d-4a2f-adbf-adc38d7f319a','蔡州叔父金部挽歌辭五首  其四','晁補之','宋','宋诗','song-poetry','','[]','聞道一廛親卜築，亦求百畝伴鉏犁。',32,'全唐诗/poet.song.63000.json','["聞道一廛親卜築，亦求百畝伴鉏犁。", "那知湖海歸來日，只及鄉閭會葬時。"]'),
('0c40f07a-1e46-402a-a129-bcfc09302954','蔡州叔父金部挽歌辭五首  其五','晁補之','宋','宋诗','song-poetry','','[]','並直儀曹前後廳，當簷種竹已青青。',32,'全唐诗/poet.song.63000.json','["並直儀曹前後廳，當簷種竹已青青。", "平生不試南宮筆，可忍圖公地下銘。"]'),
('20a1d394-66c0-42a1-9375-e61d43d2320e','蔡州叔父金部挽辭別二首  其一','晁補之','宋','宋诗','song-poetry','','[]','書來猶勸還鄉早，路梗誰令去棹遲。',32,'全唐诗/poet.song.63000.json','["書來猶勸還鄉早，路梗誰令去棹遲。", "曾綴鏘金拜先壘，可堪扱衽送靈輀。"]'),
('45465509-41bf-46ef-a681-22e77da11f84','蔡州叔父金部挽辭別二首  其二','晁補之','宋','宋诗','song-poetry','','[]','學比我公常恐後，身於餘子似蒙知。',32,'全唐诗/poet.song.63000.json','["學比我公常恐後，身於餘子似蒙知。", "心驚並直儀曹夜，淚盡孤吟海浦時。"]'),
('b50a5861-ce32-4fae-b69c-c407d39d9ed5','秦國夫人挽辭安門下母二首  其一','晁補之','宋','宋诗','song-poetry','','[]','瓜瓞傳仙裔，鳲鳩媲積功。',48,'全唐诗/poet.song.63000.json','["瓜瓞傳仙裔，鳲鳩媲積功。", "龍章看子貴，鶴髮與夫同。", "褕翟丹青裏，珠襦鼓吹中。", "秋原送車淚，斜日起西風。"]'),
('1d4d92be-5541-4b5f-8423-017dcc1b0e83','秦國夫人挽辭安門下母二首  其二','晁補之','宋','宋诗','song-poetry','','[]','城南塞冠蓋，哀挽送何人。',48,'全唐诗/poet.song.63000.json','["城南塞冠蓋，哀挽送何人。", "吉卜郊連浚，恩封國號秦。", "桓碑空復古，蒿里不知春。", "應奪居廬念，朝廷佇弼臣。"]'),
('03ffed22-0f99-4bb6-b93c-d0e9991edaf0','秦國夫人挽辭三首  其一','晁補之','宋','宋诗','song-poetry','','[]','指李仙源後，興唐帝胄餘。',48,'全唐诗/poet.song.63000.json','["指李仙源後，興唐帝胄餘。", "家傳湖北句，人誦嶺南書。", "知子唯賓客，揚名屬起居。", "平生操史筆，遺事一欷歔。"]'),
('b3769686-d128-4c1d-85d7-05bb6ff94ff7','秦國夫人挽辭三首  其二','晁補之','宋','宋诗','song-poetry','','[]','相國家風獨，夫人壼範如。',48,'全唐诗/poet.song.63000.json','["相國家風獨，夫人壼範如。", "寶珈宜服象，文錦合軒魚。", "感慨溫成議，光華慶壽餘。", "非夫聞敵退，應愧此生虛。"]'),
('4914006f-3bb2-44f6-8494-e50b397597ad','秦國夫人挽辭三首  其三','晁補之','宋','宋诗','song-poetry','','[]','酷好春秋學，親書列女篇。',48,'全唐诗/poet.song.63000.json','["酷好春秋學，親書列女篇。", "胡兒吟敢並，逸少字方傳。", "餘事猶閨範，高材自世賢。", "凱風君莫誦，秋柏已成阡。"]'),
('bfe711fb-9ace-4d37-85ea-401ae93bb767','任承制挽辭劉校勘槩求作','晁補之','宋','宋诗','song-poetry','','[]','生業清談外，浮名痛飲餘。',48,'全唐诗/poet.song.63000.json','["生業清談外，浮名痛飲餘。", "誰令力如虎，坐使食無魚。", "壁冷猶鳴劍，床空未卷書。", "呻吟待河潤，秋柏只遺墟。"]'),
('a960472c-e923-40ca-a10d-e9cfabdad348','奉答文潛戲贈','晁補之','宋','宋诗','song-poetry','','[]','倦游年少憶安巢，歸夢嘗慚斷織刀。',32,'全唐诗/poet.song.63000.json','["倦游年少憶安巢，歸夢嘗慚斷織刀。", "老去周顒雖有婦，黄經對几夜騷騷。"]'),
('310b9c08-069f-423a-bbe4-0bb6f4ddf160','考校同文館戲贈子方兼呈文潛','晁補之','宋','宋诗','song-poetry','','[]','二十年來曹子方，新詩曾見未能忘。',352,'全唐诗/poet.song.63000.json','["二十年來曹子方，新詩曾見未能忘。", "多才善戲稱物芳，吳娃席上呼作郎。", "瞥然何許歲月長，只今未老毛髮蒼。", "自言逢掖非昔狂，傳經華陰夫子堂。", "何曾騎馬身挾槍，詔隨上將西擊羌。", "董蒲跗注謂我臧，夜行馬頓饑無糧。", "鼓鼙驚谷騎卷岡，吏呼爲微醉在牀。", "前鋒奄至靈武傍，中堅反後無敢驤。", "城開三日牧蔽隍，百馳載笴千橐裝。", "旌旗立壘烏鳥揚，還軍不省一矢亡。", "坐師無獲勞不償，鐃歌入奏虛錦囊。", "秋風鱸魚思故鄉，銳頭宜董鸛鵝行。", "得官猶領萬驌驦，王城對巷如參商。", "那知連月居茲房，稱多量少非我王。", "群公古鏡懸秋光，閉門飯飽庭葉黄。", "秋盤登兔官酎香，吳音訛變雜秦凉。", "令壺老柏笑覆觴，淹留平日夢欲翔。", "得君可樂殊未央，人生傾蓋何所望。", "結交松柏要冰霜，中天號出玉璽章。", "青驄御史騰康莊，歸期屈指未可忙。", "聞君况有夢虺祥，生女不惡嫁鄰牆。", "掃軒留客具酒漿，與君更約城南張。"]'),
('1dfc8472-86e2-4355-b1c9-29a40661b969','復用方字韵奉贈同舍慎思文潛同年天啟','晁補之','宋','宋诗','song-poetry','','[]','平生數子天一方，今夕何夕情難忘。',352,'全唐诗/poet.song.63000.json','["平生數子天一方，今夕何夕情難忘。", "荷衣攬蕙氣芬芳，冊府兩公同舍郎。", "崑崙方軌萬里長，西城却望天蒼蒼。", "秋庭風雨翻幕狂，夜語蔡侯同一堂。", "張侯老筆森矛槍，文詞楚些遺蹇羌。", "胸中水鏡誰否臧，學三百囷羞裹糧。", "思如决瀆萬仞崗，大編小軸山壓牀。", "城南買屋君舍旁，疲驂日附驥尾驤。", "我慚昧道由四隍，人如燕宋初束裝。", "聽君雄辯神揚揚，却思得一愁十亡。", "鄧侯韞櫝價不償，有方未試聊貯囊。", "起家牛斗玉笥鄉，鴻鶱早入鵷鷺行。", "和鸞采齊要驌驦，一鐸便足諧宮商。", "知君雲壑有松房，南陽耒耜心霸王。", "玉池復說夜有光，仙人藏丹金鼎黄。", "願分神瀵浴骨香，非我其人慚德凉。", "蔡侯發迹江濫觴，閉籠祗欲擘海翔。", "此公事業未渠央，六奇他日吾所望。", "烏號張月刀瑩霜，裂五單于加印章。", "穰苴可但虛斬莊，遭時立志未可忘。", "白犢得瞽寧非祥，嗟予企踵不及牆。", "逢君如渴御蔗漿，怯雖如鼠猶膽張。"]'),
('d87a32b1-aace-4b6e-9dbd-cf4f26e0805f','四客各有所長','晁補之','宋','宋诗','song-poetry','','[]','黄子似淵明，城市亦復真。',48,'全唐诗/poet.song.63000.json','["黄子似淵明，城市亦復真。", "陳君有道舉，化行閭井淳。", "張侯公瑾流，英思春泉新。", "高才更難及，淮海一髯秦。"]'),
('cd9537c8-3663-4c96-aa36-98ed63df2686','酴醾','晁補之','宋','宋诗','song-poetry','','[]','喚將梅蕊要同韵，羞殺梨花不解香。',32,'全唐诗/poet.song.63000.json','["喚將梅蕊要同韵，羞殺梨花不解香。", "如何五月露寒殿，不與薰風送晚凉。"]'),
('28a29432-9c89-4e51-93db-64ec3651537a','與同年廖明略','晁補之','宋','宋诗','song-poetry','','[]','十年山林廖居士，今隨詔書稱舉子。',32,'全唐诗/poet.song.63000.json','["十年山林廖居士，今隨詔書稱舉子。", "文章宏麗學西京，新有詩聲似侯喜。"]'),
('e4e087c9-8439-4398-98ef-bda946d651ef','詩一首','晁補之','宋','宋诗','song-poetry','','[]','上山割白紵，山高葉摵摵。',24,'全唐诗/poet.song.63000.json','["上山割白紵，山高葉摵摵。", "持歸當戶績，爲君爲絺綌。"]'),
('58a93b5f-bcba-476c-8919-9f6c65fd4d17','句  其一','晁補之','宋','宋诗','song-poetry','','[]','短棹孤飛誇寥廓，洪濤高卧看星辰。',16,'全唐诗/poet.song.63000.json','["短棹孤飛誇寥廓，洪濤高卧看星辰。"]'),
('723450c0-595f-471f-9beb-e08cb1eddbb6','句  其二','晁補之','宋','宋诗','song-poetry','','[]','閩侯貢璧琢蒼玉，中有掉尾寒潭龍。',16,'全唐诗/poet.song.63000.json','["閩侯貢璧琢蒼玉，中有掉尾寒潭龍。"]'),
('e0f7bd9c-1dd6-4b93-8484-5b665c507182','句  其三','晁補之','宋','宋诗','song-poetry','','[]','山色不違人，嵌滿千家窗。',12,'全唐诗/poet.song.63000.json','["山色不違人，嵌滿千家窗。"]'),
('270e233c-a983-4bd5-90f4-d6238f4d61d4','句  其四','晁補之','宋','宋诗','song-poetry','','[]','日月中人照與芬。',8,'全唐诗/poet.song.63000.json','["日月中人照與芬。"]'),
('2a7316da-8e00-4ddb-8e04-b4074e9ce2d0','存目','晁補之','宋','宋诗','song-poetry','','[]','詩題：和蔡天啟小詩戲無咎首句：文書盈几法筵埋。',23,'全唐诗/poet.song.63000.json','["詩題：和蔡天啟小詩戲無咎首句：文書盈几法筵埋。"]'),
('daa1eb50-f449-40d0-b88c-918169db76bf','偈六十九首  其一','釋道寧','宋','宋诗','song-poetry','','[]','寶座既登，清風四起。',40,'全唐诗/poet.song.63000.json','["寶座既登，清風四起。", "要津把斷，凡聖俱亡。", "放一線道，別露風規。", "具眼禪人，一任施設。"]'),
('b250bb8d-d87b-47ac-9a79-4cc82e0979b8','偈六十九首  其二','釋道寧','宋','宋诗','song-poetry','','[]','風攪長空，春雲四起。',46,'全唐诗/poet.song.63000.json','["風攪長空，春雲四起。", "六臂三頭，徒誇唇觜。", "匝地普天，全非伴侶。", "等閒拈出與君看，直下分明須薦取。"]'),
('dd79a1b7-a509-4829-ba70-dad7c29ecfa8','偈六十九首  其三','釋道寧','宋','宋诗','song-poetry','','[]','沒絃琴韵，罕遇知音。',40,'全唐诗/poet.song.63000.json','["沒絃琴韵，罕遇知音。", "無影林中，難尋足迹。", "同聲同氣，方辨端倪。", "不是當家，徒勞側耳。"]'),
('f8c80e31-79a5-4122-9bcd-35414d316d8b','偈六十九首  其四','釋道寧','宋','宋诗','song-poetry','','[]','數聲歸笛離春浦，一片孤帆過洞津。',32,'全唐诗/poet.song.63000.json','["數聲歸笛離春浦，一片孤帆過洞津。", "到岸捨舟常式事，何須更問渡頭人。"]'),
('17d6fb30-435c-4679-9ace-d8a4723be982','偈六十九首  其五','釋道寧','宋','宋诗','song-poetry','','[]','棋逢敵手，密行難藏。',40,'全唐诗/poet.song.63000.json','["棋逢敵手，密行難藏。", "琴遇知音，希聲乃布。", "摩竭正令，同道方知。", "捏聚放開，悟迷一决。"]'),
('d1db34e8-1bb2-4452-ab10-cb11cb6d6a7e','偈六十九首  其六','釋道寧','宋','宋诗','song-poetry','','[]','父母所生口，何妨爲子說。',28,'全唐诗/poet.song.63000.json','["父母所生口，何妨爲子說。", "莫將閒事掛心頭，便是人間好時節。"]'),
('50b56497-6cff-4a68-9af5-baed25c02b40','偈六十九首  其七','釋道寧','宋','宋诗','song-poetry','','[]','子只見風清月白，焉知洞裏花香。',31,'全唐诗/poet.song.63000.json','["子只見風清月白，焉知洞裏花香。", "曾看江上弄潮人，未聞愛水嫌波浪。"]'),
('4ee4d453-cfb8-45df-b43e-1b582b6b9d85','偈六十九首  其八','釋道寧','宋','宋诗','song-poetry','','[]','千聖不傳，諸祖祕語。',30,'全唐诗/poet.song.63000.json','["千聖不傳，諸祖祕語。", "不惜眉毛，爲君親舉。", "衲子擡眸，白雲萬里。"]'),
('771aee4c-95ec-47b4-8461-b5508b87ea13','偈六十九首  其九','釋道寧','宋','宋诗','song-poetry','','[]','報慈一要，凡聖同妙。',69,'全唐诗/poet.song.63000.json','["報慈一要，凡聖同妙。", "犬吠馿鳴，龍吟虎嘯。", "道吾樂神，師巫祭廟。", "雨過山青，雲收日照。", "拾得與寒山，不覺呵呵笑。", "休休，他年自有知音，豈待今朝說破。"]'),
('aafb51c9-0875-406f-9036-95c19155eb10','偈六十九首  其一○','釋道寧','宋','宋诗','song-poetry','','[]','晷運推移，日南長至。',106,'全唐诗/poet.song.63000.json','["晷運推移，日南長至。", "分明一道恩光，照徹十方三世。", "全彰諸祖玄關，漏泄衲僧巴鼻。", "靈雲剛道無疑，彌勒徒誇授記。", "爭如李四張三，相賀街頭巷尾。", "不是海印發光，亦非楞嚴三昧。", "林下高人，休要瞌睡。", "令余暗裏笑舒眉，直是清風動天地。"]'),
('e2e50689-4a93-45d7-96b8-86fa57032ce6','偈六十九首  其一一','釋道寧','宋','宋诗','song-poetry','','[]','宗門奧旨，造者還稀。',64,'全唐诗/poet.song.63000.json','["宗門奧旨，造者還稀。", "體用無私，隨流得妙。", "有時互爲主，伴敲唱玄風。", "有時對面藏，身難窺影迹。", "要津把斷，凡聖迷源。", "利物垂慈，等閒入艸。"]'),
('cec523ae-2621-4f68-9994-66f1f3b15996','偈六十九首  其一二','釋道寧','宋','宋诗','song-poetry','','[]','蕩蕩無迂曲，明明透古今。',98,'全唐诗/poet.song.63000.json','["蕩蕩無迂曲，明明透古今。", "問無別語，答豈異音。", "一人張帆，一人把柁。", "鐵笛橫吹，漁歌唱和。", "啐啄同時，知音幾個。", "順水逆流歸去來，到岸方諳不恁麽。", "不恁麽，爲君宣，甜如砂蜜，苦似黄連。", "若不同牀卧，焉知被底穿。"]'),
('cb9c4df6-36f8-4ce3-9575-d3f1b9d6aa85','偈六十九首  其一三','釋道寧','宋','宋诗','song-poetry','','[]','解語非干舌，能言不是聲。',36,'全唐诗/poet.song.63000.json','["解語非干舌，能言不是聲。", "非聲非舌用，方乃號圓成。", "妙造如如旨，還家罷問程。"]'),
('52885496-076b-49ef-8281-a612087112e8','偈六十九首  其一四','釋道寧','宋','宋诗','song-poetry','','[]','數日寺門浩浩，全身走入荒艸。',99,'全唐诗/poet.song.63000.json','["數日寺門浩浩，全身走入荒艸。", "五湖高士安禪，休要別處尋討。", "廊下喏諾分明，階前斛斟叫噪。", "勞生日用無私，般若光中虛老。", "燈籠暗地攢眉，露柱低頭懊惱。", "令予冷眼偷看，不覺呵呵笑倒。", "三錢買個鄭州梨，元來是青州棗。"]'),
('411075b2-9d3a-4762-84dc-2559306dad38','偈六十九首  其一五','釋道寧','宋','宋诗','song-poetry','','[]','春山青，春水淥，啼鳥落花清耳目。',32,'全唐诗/poet.song.63000.json','["春山青，春水淥，啼鳥落花清耳目。", "一带平原畫不成，妙印無羈豈拘束。"]'),
('a92c21ca-6a91-4ec3-9adb-02f04608df85','偈六十九首  其一六','釋道寧','宋','宋诗','song-poetry','','[]','聞聲不悟道，見色豈明心。',24,'全唐诗/poet.song.63000.json','["聞聲不悟道，見色豈明心。", "大冶紅爐裏，真鍮不博金。"]'),
('45021ac1-a6c1-42a1-825b-40c411260e96','偈六十九首  其一七','釋道寧','宋','宋诗','song-poetry','','[]','難中之難，妙中之妙。',20,'全唐诗/poet.song.63000.json','["難中之難，妙中之妙。", "千聖攢眉，是何關要。"]'),
('8d67e1e8-85a9-464f-beef-4201267e8b70','偈六十九首  其一八','釋道寧','宋','宋诗','song-poetry','','[]','薰風乍扇，雲霧頓開。',101,'全唐诗/poet.song.63000.json','["薰風乍扇，雲霧頓開。", "杲日騰空，森羅互顯。", "如鏡照像，不礙光輝。", "汝等諸人，二六時中。", "發宣前塵，憑何印可。", "這裏薦得，無明界內，古佛家風。", "荆棘林中，衲僧巴鼻。", "大地山河，借你出氣。", "借水獻花常式事，傍觀猶笑老婆心。"]'),
('6a276c07-35e9-4757-b31d-7e09f28f1154','偈六十九首  其一九','釋道寧','宋','宋诗','song-poetry','','[]','宗門妙旨，海口難宣。',71,'全唐诗/poet.song.63000.json','["宗門妙旨，海口難宣。", "簡要提撕，知音罕遇。", "事無一向，理出多門。", "豈不見道，有句無句，如藤倚樹。", "樹倒藤枯，句歸何處。", "深秋簾外千家雨，落日樓前一笛風。"]'),
('fa8f227f-c719-42aa-9878-9fe8b041ebba','偈六十九首  其二○','釋道寧','宋','宋诗','song-poetry','','[]','春風浩浩，春鳥喃喃。',57,'全唐诗/poet.song.63000.json','["春風浩浩，春鳥喃喃。", "山花開似錦，澗水湛如藍。", "大圓鏡裏，扣己而參，便恁麽去也太無端。", "文殊去後無消息，休問前三與後三。"]'),
('681ba8e1-04e3-40c7-9191-1ff0f658db86','偈六十九首  其二一','釋道寧','宋','宋诗','song-poetry','','[]','枯木巖前，道人不顧。',76,'全唐诗/poet.song.63000.json','["枯木巖前，道人不顧。", "塵勞界內，衲子興悲。", "戀著玄關，全虧大用。", "灰身滅智，豈是良圖。", "裂破面門，救諸苦趣。", "爲祥爲瑞，今正是時。", "撈龍趁鳳男兒事，淺種深耕效仰山。"]'),
('6378d891-b53a-4f40-860e-d24335b0ee09','偈六十九首  其二二','釋道寧','宋','宋诗','song-poetry','','[]','曙色纔分煙氣消，嚴風括地不相饒。',48,'全唐诗/poet.song.63000.json','["曙色纔分煙氣消，嚴風括地不相饒。", "爐中幸有無煙炭，莫學丹霞把佛燒。", "恩大不知何以報，寥寥千載古風清。"]'),
('e9afadc0-c62a-4d3d-9262-21fd54ab7c64','偈六十九首  其二三','釋道寧','宋','宋诗','song-poetry','','[]','大道無私，要由心悟。',30,'全唐诗/poet.song.63000.json','["大道無私，要由心悟。", "心無形狀，全物而彰。", "妙契斯關，萬緣俱備。"]'),
('c0950441-f7d5-43f3-b94f-24ac2a2c63dd','偈六十九首  其二四','釋道寧','宋','宋诗','song-poetry','','[]','同阬無異土，千古少人知。',24,'全唐诗/poet.song.63000.json','["同阬無異土，千古少人知。", "月下休相喚，還從舊路歸。"]'),
('bb497aaa-b3a9-441e-9c1e-02a7a9a42fc2','偈六十九首  其二五','釋道寧','宋','宋诗','song-poetry','','[]','人從卞州來，不得東京信。',36,'全唐诗/poet.song.63000.json','["人從卞州來，不得東京信。", "陝路既相逢，到底難親覲。", "撫掌笑呵呵，解佩空王印。"]'),
('9bccca14-a55f-41a7-9d99-27886823406b','偈六十九首  其二六','釋道寧','宋','宋诗','song-poetry','','[]','先賢垂範早涉離，微言無展事句裏。',88,'全唐诗/poet.song.63000.json','["先賢垂範早涉離，微言無展事句裏。", "藏機百千諸佛知，黄鶴樓前握手歸。", "夏雨落綿綿，民歌堯舜天。", "千山增翠色，萬壑鎖青煙。", "唯有禪家無一事，饑來喫飯困來眠。", "路逢死蛇莫打殺，沒底籃子盛將歸。"]'),
('ab343ff6-8379-4208-84c4-7b3226f27023','偈六十九首  其二七','釋道寧','宋','宋诗','song-poetry','','[]','陰雲彌四野，心地長塵埃。',24,'全唐诗/poet.song.63000.json','["陰雲彌四野，心地長塵埃。", "試請回光看，生從何處來。"]'),
('4ef58b65-b2db-4f54-ab40-fcbe25dd3b82','偈六十九首  其二八','釋道寧','宋','宋诗','song-poetry','','[]','叢林浩浩，誰是知音。',128,'全唐诗/poet.song.63000.json','["叢林浩浩，誰是知音。", "馬祖堂中，盤山回首。", "雲門會裏，明教翻身。", "彼此一時，孰分優劣。", "入鄽不露迹，隨處是家風。", "淺種與深耕，秋冬收顆粒。", "從他五湖衲子，端坐無疑。", "日高一鉢和羅飯，禪道是非都不知。", "塵中辨主，鬧裏求人。", "兩手扶犁，钁頭邊事。", "陋巷不騎金鐙馬，回來却著破襴衫。"]'),
('9437d85c-f850-4783-873b-d7430d5d029a','偈六十九首  其二九','釋道寧','宋','宋诗','song-poetry','','[]','數日滂沱雨，今朝彷彿晴。',90,'全唐诗/poet.song.63000.json','["數日滂沱雨，今朝彷彿晴。", "煙雲消散盡，天地廓然清。", "簷前鵲噪，林裏鶑鳴。", "嶺外牧童歌野徑，江邊漁父釣長鯨。", "禪家高卧無餘事，渴飲饑飧賀大平。", "兩彩一賽，凡聖齊收。", "若作佛法商量，大似抱贓叫屈。"]'),
('0b9b632d-4411-4e97-bc3e-847ff96d9fa5','偈六十九首  其三○','釋道寧','宋','宋诗','song-poetry','','[]','報慈一言，千聖不傳。',32,'全唐诗/poet.song.63000.json','["報慈一言，千聖不傳。", "即時妙會，火裏生蓮。", "路遥知馬力，歲久見人心。"]'),
('eb3405c3-51ef-4fa6-971f-567b357c752b','偈六十九首  其三一','釋道寧','宋','宋诗','song-poetry','','[]','琉璃殿上，古佛舒光。',124,'全唐诗/poet.song.63000.json','["琉璃殿上，古佛舒光。", "明月堂前，曇華布影。", "不用南詢彌勒，何須東覓文殊。", "華藏門開，任君瞻仰。", "或舒或卷，塵塵普現色身。", "或放或收，處處毗盧境界。", "不舒不卷，寂爾無根。", "不放不收，是真常住。", "絲毫無礙，統攝聖凡。", "自利兼他，古今不墜。", "夜半不須敲玉戶，天明鳳子笑銜花。"]'),
('f6f93718-2291-43ba-bd75-9d470a598e0a','偈六十九首  其三二','釋道寧','宋','宋诗','song-poetry','','[]','透脫玄關，更無凝滯。',20,'全唐诗/poet.song.63000.json','["透脫玄關，更無凝滯。", "一瞖落眼，空華亂墜。"]'),
('773193b8-920a-4739-9b75-023b17d9384d','偈六十九首  其三三','釋道寧','宋','宋诗','song-poetry','','[]','塑不就，畫不成。',52,'全唐诗/poet.song.63000.json','["塑不就，畫不成。", "鋒芒不動，海晏河清。", "五湖衲子，抖擻精神。", "爲君通一線，教子快平生。", "夜來春睡重，一覺到天明。"]'),
('87aec228-8e63-457f-9a1a-7b667142927f','偈六十九首  其三四','釋道寧','宋','宋诗','song-poetry','','[]','衲子玄關，群生命脈。',60,'全唐诗/poet.song.63000.json','["衲子玄關，群生命脈。", "鋒芒未兆，便好承當。", "文彩纔彰，翻成影事。", "空劫已前，乾坤未剖。", "凝然一片，非聖非凡。", "不涉熏脩，豈從外有。"]'),
('ec4aba06-3423-4dab-8791-1e071ad21655','偈六十九首  其三五','釋道寧','宋','宋诗','song-poetry','','[]','焚香提起經來讀，便是拈華付囑心。',32,'全唐诗/poet.song.63000.json','["焚香提起經來讀，便是拈華付囑心。", "此外別求玄妙解，悠悠千古少知音。"]'),
('5579c938-6121-4296-9c54-c68afe7de268','偈六十九首  其三六','釋道寧','宋','宋诗','song-poetry','','[]','選得幽居愜野情，終年無送復無迎。',32,'全唐诗/poet.song.63000.json','["選得幽居愜野情，終年無送復無迎。", "有時直上孤峰頂，月下披雲嘯一聲。"]'),
('e8e83172-b509-47a9-ac32-181d086fc43b','偈六十九首  其三七','釋道寧','宋','宋诗','song-poetry','','[]','摩竭掩室，非是通方。',40,'全唐诗/poet.song.63000.json','["摩竭掩室，非是通方。", "浄名杜詞，未爲作略。", "總不恁麽，罕遇知音。", "方便門中，隨宜舉唱。"]'),
('fa9e03bf-73ee-48b7-8675-3e6dd62572be','偈六十九首  其三八','釋道寧','宋','宋诗','song-poetry','','[]','蘇州有，常州有。',46,'全唐诗/poet.song.63000.json','["蘇州有，常州有。", "月白風清，天長地久。", "路著舊鄉關，金毛善哮吼。", "父慈子孝少人知，回首面南看北斗。"]'),
('1a64d7eb-c3e0-4b92-bf22-b0040213662a','偈六十九首  其三九','釋道寧','宋','宋诗','song-poetry','','[]','丈夫兒，自家斷，日用無私休計算。',112,'全唐诗/poet.song.63000.json','["丈夫兒，自家斷，日用無私休計算。", "被他指點謾商量，到底死生打不辨。", "長生路上少人行，輪轉脩途空懊嘆。", "萬境中，須這漢。", "出沒卷舒無繫縛，淺種深耕誰委知，溈山水牯騎來慣。", "頭角分明在目前，五湖衲子擡眸看。", "玉笛一聲風雨寒，萬兩黄金終不換。"]'),
('dfc9a7a5-42df-4acf-b4e7-6cf8e1d75acb','偈六十九首  其四○','釋道寧','宋','宋诗','song-poetry','','[]','釋主拈花，强生枝節。',56,'全唐诗/poet.song.63000.json','["釋主拈花，强生枝節。", "頭陀微笑，眼裏添塵。", "目擊道存，翻成途轍。", "隔江招扇，早涉崎嶇。", "勸君不用鎸頑石，路上行人口似碑。"]'),
('39704221-ddd9-4d40-bcc6-b462c77c75d2','偈六十九首  其四一','釋道寧','宋','宋诗','song-poetry','','[]','宗門奧旨，祖室玄樞。',20,'全唐诗/poet.song.63000.json','["宗門奧旨，祖室玄樞。", "不遇當人，翻成影響。"]'),
('f4e70e59-de21-4211-ac18-6ee66aa1985f','偈六十九首  其四二','釋道寧','宋','宋诗','song-poetry','','[]','著眼看，休比擬。',24,'全唐诗/poet.song.63000.json','["著眼看，休比擬。", "幾回拋向衆人前，八臂那吒提不起。"]'),
('bf661fd8-07aa-4938-a3b8-5a4a71e11855','偈六十九首  其四三','釋道寧','宋','宋诗','song-poetry','','[]','衲僧蹊徑，千眼莫窺。',82,'全唐诗/poet.song.63000.json','["衲僧蹊徑，千眼莫窺。", "鳥道無私，經行豈礙。", "要關在手，通變剎那。", "一味醍醐，莫嫌淡薄。", "有時毗盧藏內，優缽華開。", "嗅之不聞，是何境界。", "靈山彷彿，少室依稀。", "抖擻提撕，人天兼濟。"]'),
('958fc478-3b0e-482c-8ece-d29d168b9a7c','偈六十九首  其四四','釋道寧','宋','宋诗','song-poetry','','[]','縱橫問答有來由，緣木求魚卒未休。',138,'全唐诗/poet.song.63000.json','["縱橫問答有來由，緣木求魚卒未休。", "若妙旨尋知見會，還同撥火覓浮漚。", "諸佛子，著眼看。", "嚴霜曉露，徹骨清寒。", "匝地普天，通同實際。", "休問得皮得髓，徒誇見淺見深。", "從來一道恩冤，何以自家退屈。", "山僧對此，忍俊不禁。", "閒引少林無孔笛，爲君吹起小陽春。", "滿眼覷不見，滿耳聽不聞。", "一堂風冷淡，千古意分明。"]'),
('98b3c7db-cca5-44fa-8940-e3a0c12b8a37','偈六十九首  其四五','釋道寧','宋','宋诗','song-poetry','','[]','秋風秋雨頗相宜，萬水千山木葉飛。',116,'全唐诗/poet.song.63000.json','["秋風秋雨頗相宜，萬水千山木葉飛。", "堪笑靈雲回首處，何須花發始忘機。", "秋風蕭索，秋山葉落。", "秋雨霖漓，秋天寥廓。", "祖師心印全彰，靈雲鼻孔穿却。", "分明一道恩光，曠劫無形寂寞。", "五湖衲子急歸來，休向途中亂穿鑿。", "莫穿鑿，體用從來非自他，作者不求無病藥。"]'),
('e926ae53-f463-4fe3-a33b-6e9faf13ba6a','偈六十九首  其四六','釋道寧','宋','宋诗','song-poetry','','[]','金烏當午，文彩全彰。',64,'全唐诗/poet.song.63000.json','["金烏當午，文彩全彰。", "玉兔沈輝，影像俱寂。", "通同實際，一體無諸。", "不落今時，識情罔測。", "混融凡聖，佛眼難窺。", "髑髏常干世界，鼻孔摩觸家風。"]'),
('c1b8a269-deaf-4e0e-9e58-e4f28a10202f','偈六十九首  其四七','釋道寧','宋','宋诗','song-poetry','','[]','靈山標榜，五指舒光。',106,'全唐诗/poet.song.63000.json','["靈山標榜，五指舒光。", "少室真規，斷肱立雪。", "塵中辨主，盤山蹤迹猶存。", "杓柄舀來，象骨家風尚在。", "流通密旨，建立法幢。", "全藉高人，方能巨濟。", "然後玄關大啟，四海一家。", "任他六臂三頭，到此也應拱手。", "須彌頂上非凡木，白藕峰前得處高。"]'),
('862f931e-bcf6-499b-bd76-dfc3c432d833','偈六十九首  其四八','釋道寧','宋','宋诗','song-poetry','','[]','全提正令，匝地風生。',96,'全唐诗/poet.song.63000.json','["全提正令，匝地風生。", "把定要津，孰分優劣。", "三玄料簡，未稱衲僧。", "五位君臣，殊乖道體。", "平實無事，誑謼閭閻。", "入理深談，黏皮带骨。", "纖毫不動，空劫已前。", "數量難該，憑何話會。", "幾回拋向衆人前，千眼大悲覷不見。"]'),
('9528f4d5-5256-4d66-abcd-ee5a5b191e01','偈六十九首  其四九','釋道寧','宋','宋诗','song-poetry','','[]','正法眼藏，十聖那知。',186,'全唐诗/poet.song.63000.json','["正法眼藏，十聖那知。", "祕密玄風，三賢罔測。", "靈機湛寂，體妙希夷。", "不落今時，豈該數量。", "撈籠品類，陶鑄群情。", "三世諸佛，異口同宣。", "六代祖師，亞肩垂示。", "琅函玉偈，徧滿龍宮。", "海角天涯，潛敷奧義。", "或瞻或禮，迥脫根塵。", "若見若聞，俱成種智。", "回光照徹，契本幽微。", "印古印今，非前非後。", "圓伊獨露，方號流通。", "超出化門，是真常住。", "衲僧孔竅，放過一著。", "檀那分上，又且如何。", "壽山隠隠侵雲際，福海滔滔似鏡平。"]'),
('809d3a2b-df35-48fd-983a-0cc9dc8224f4','偈六十九首  其五○','釋道寧','宋','宋诗','song-poetry','','[]','祖師妙旨，覿面無私。',42,'全唐诗/poet.song.63000.json','["祖師妙旨，覿面無私。", "該括古今，何嘗欠少。", "自是根機不等，見有差殊。", "方便門開，爲君舉唱。"]'),
('dd06d698-b522-4d58-a190-92932f6b65d0','偈六十九首  其五一','釋道寧','宋','宋诗','song-poetry','','[]','有利無利，不離行市。',34,'全唐诗/poet.song.63000.json','["有利無利，不離行市。", "師子嚬呻，象王游戲。", "洎乎檢點將來，未是衲僧巴鼻。"]'),
('3ecdfd99-24b9-4a20-aed6-2809a10c46e1','偈六十九首  其五二','釋道寧','宋','宋诗','song-poetry','','[]','此生西天，斯晨禁足。',70,'全唐诗/poet.song.63000.json','["此生西天，斯晨禁足。", "依舊夜短晝長，是處山青水淥。", "都來一個虛空，不用强生節目。", "爭如攃手便歸來，六六元來三十六。", "殷勤爲報道中人，戀著玄關即拘束。"]'),
('32efbcf3-9a5c-40ba-8102-411b8051c46a','偈六十九首  其五三','釋道寧','宋','宋诗','song-poetry','','[]','毗盧影裏，般若光中。',94,'全唐诗/poet.song.63000.json','["毗盧影裏，般若光中。", "互爲主伴，法界融通。", "白雲片片，帝網重重。", "形分萬派，月印寒空。", "道人活計，古佛家風。", "自他兼濟，無功之功。", "高著眼，莫狐疑。", "卷舒自在，今正是時。", "路逢劍客須呈劍，不是詩人莫獻詩。"]'),
('eb000c48-050f-4d19-b0e6-b3b636ba4013','偈六十九首  其五四','釋道寧','宋','宋诗','song-poetry','','[]','雲容靉靆，舒卷長空。',76,'全唐诗/poet.song.63000.json','["雲容靉靆，舒卷長空。", "乍雨乍晴，爲祥爲瑞。", "敷榮萬物，積翠千山。", "大事皎然，輝騰今古。", "英靈衲子，使合知時。", "懞懂禪人，云何話會。", "數片白雲生宇宙，普天無處不垂陰。"]'),
('f7037953-5db3-45b8-98b6-a1b4a1ce343a','偈六十九首  其五五','釋道寧','宋','宋诗','song-poetry','','[]','出家佛子，物外高流。',91,'全唐诗/poet.song.63000.json','["出家佛子，物外高流。", "挈錫携缾，訪尋知識。", "須是踏著自己穩實田地，方解茆菴石室折脚鐺兒。", "煮粥煎茶，接待往來，隨家豐儉。", "未到如斯境界，不可虛延歲月。", "二六時中，收視返聽。", "子細揣摩，是何面目。"]'),
('ad3f9bae-3500-4b66-8324-78b0a299052d','偈六十九首  其五六','釋道寧','宋','宋诗','song-poetry','','[]','曠劫洞然，孤光皎潔。',46,'全唐诗/poet.song.63000.json','["曠劫洞然，孤光皎潔。", "不涉功勳，是何時節。", "布袋癡憨，豐干饒舌。", "大悲千眼覓無蹤，體妙虛玄百非絕。"]'),
('a9861552-b45e-419f-9802-ab2a477b1ac8','偈六十九首  其五七','釋道寧','宋','宋诗','song-poetry','','[]','涅槃城裏，求是安身。',108,'全唐诗/poet.song.63000.json','["涅槃城裏，求是安身。", "十字街頭，何妨出手。", "放行把住，通變由人。", "五位君臣，徒誇作略。", "三玄賓主，謾逞鋒機。", "直截無私，殊乖妙用。", "設使四十九年，三百餘會。", "琅函玉偈，海藏龍宮。", "檢點將來，呼爲切脚。", "儒門弟子無人識，碧眼胡僧笑點頭。"]'),
('19ff5ec4-db91-4d76-acac-b11ec87f01fa','偈六十九首  其五八','釋道寧','宋','宋诗','song-poetry','','[]','白藕峰前，纖塵不立。',48,'全唐诗/poet.song.63000.json','["白藕峰前，纖塵不立。", "報慈門下，水泄難通。", "既是纖塵不立，水泄不通。", "五葉一華分布後，寥寥千古散清風。"]'),
('5c284542-823b-487f-8469-f90fc04ffea2','偈六十九首  其五九','釋道寧','宋','宋诗','song-poetry','','[]','永嘉一宿，道播寰區。',106,'全唐诗/poet.song.63000.json','["永嘉一宿，道播寰區。", "招扇隔江，法流四海。", "乾坤未剖，誰是知音。", "空劫已前，何人印可。", "向上一路，千聖不傳。", "透脫斯關，方能妙用。", "慈雲靉靆，舒卷湘江。", "不假風雷，滂沛甘澤。", "三艸二木，并獲敷榮。", "青山不鎖長飛勢，滄海合知來處高。"]'),
('4cdb398c-adeb-4e6a-8ed8-f51c610c7e17','偈六十九首  其六○','釋道寧','宋','宋诗','song-poetry','','[]','全提密印，千聖迷蹤。',91,'全唐诗/poet.song.63000.json','["全提密印，千聖迷蹤。", "肘後靈符，三賢結舌。", "平高就下，乃可宣揚。", "略露風規，急須著眼。", "雪峰父子，或舒或卷，今古無倫。", "或抑或揚，凡聖罔測。", "重關壁立，誰解流通。", "龍向洞中銜雨出，鳳從花裏带香歸。"]'),
('4b04b17f-4195-4e78-b841-71dd9b20ecb0','偈六十九首  其六一','釋道寧','宋','宋诗','song-poetry','','[]','從前日月，依舊山川。',46,'全唐诗/poet.song.63000.json','["從前日月，依舊山川。", "瀉碧堆青，輝騰今古。", "曾無間斷，豈有虧盈。", "幾般雲色出峰頂，一樣泉聲落檻前。"]'),
('3af9f141-91d1-4b11-a10c-7cf2c0151787','偈六十九首  其六二','釋道寧','宋','宋诗','song-poetry','','[]','歷歷分明，堂堂顯露。',36,'全唐诗/poet.song.63000.json','["歷歷分明，堂堂顯露。", "師子翻身，象王回顧。", "若能這裏會觀瞻，瞥轉玄關無別事。"]'),
('0ddec7c4-b082-4d2c-9b9e-90a7b0e305f8','偈六十九首  其六三','釋道寧','宋','宋诗','song-poetry','','[]','報慈一隔，佛祖命脈。',44,'全唐诗/poet.song.63000.json','["報慈一隔，佛祖命脈。", "放去收來，聖凡罔測。", "隔不隔，若爲陳。", "擔取詩書歸舊隠，野花啼鳥一般春。"]'),
('771681b4-8618-43d9-83f0-cdd12677f757','偈六十九首  其六四','釋道寧','宋','宋诗','song-poetry','','[]','千尺絲綸直下浮，蘆灣深處浪花麤。',52,'全唐诗/poet.song.63000.json','["千尺絲綸直下浮，蘆灣深處浪花麤。", "撈蝦樚蜆無心戀，還有金鱗上釣無。", "搖頭擺尾，躍浪衝波。", "不顧絲綸，便請吞鈎。"]'),
('388e2c80-df7e-4760-b8a0-f37c61a80764','偈六十九首  其六五','釋道寧','宋','宋诗','song-poetry','','[]','摩竭正令，未免崎嶇。',104,'全唐诗/poet.song.63000.json','["摩竭正令，未免崎嶇。", "少室垂慈，早傷風骨。", "腰囊挈錫，辜負平生。", "煉行灰心，遞相鈍致。", "爭似春雨晴，春山青。", "白雲三片五片，黄鳥一聲兩聲。", "千眼大悲看不足，王維雖巧畫難成。", "直饒便恁麽，猶是涉途程。", "人從卞州來，不得東京信。"]'),
('9bc6a08c-d4aa-4111-856d-50daee5d4e46','偈六十九首  其六六','釋道寧','宋','宋诗','song-poetry','','[]','長老未離方丈裏，鼓聲先爲剖圓音。',32,'全唐诗/poet.song.63000.json','["長老未離方丈裏，鼓聲先爲剖圓音。", "眼聞耳見非他事，何必驅馳向外尋。"]'),
('c9516d37-159d-4c08-a5da-287f01baa22c','偈六十九首  其六七','釋道寧','宋','宋诗','song-poetry','','[]','靈山瞬目，早是周遮。',142,'全唐诗/poet.song.63000.json','["靈山瞬目，早是周遮。", "良馬窺鞭，豈爲英俊。", "巖間宴坐，天帝散花。", "無說無聞，藏頭露影。", "少林面壁，計較未成。", "立雪斷肱，辜他衲子。", "黄梅呈頌，勝負偏枯。", "半夜傳衣，瞞人不少。", "從上來事，合作麽生。", "豈假人天衆前搖唇鼓舌，競銳爭鋒。", "互立主賓，交參問答。", "檢點將來，彌天過犯。", "不因檀信方敲唱，爭見龍華會裏人。"]'),
('0c109710-9be7-4e8a-af05-fe4bb840f662','偈六十九首  其六八','釋道寧','宋','宋诗','song-poetry','','[]','行脚高士，撥草瞻風。',22,'全唐诗/poet.song.63000.json','["行脚高士，撥草瞻風。", "未透目前關，難明心地印。"]'),
('c9699c21-d2e4-4146-8c4a-92af553a588a','偈六十三首  其一','釋道寧','宋','宋诗','song-poetry','','[]','春風習習，春日熙熙。',106,'全唐诗/poet.song.63000.json','["春風習習，春日熙熙。", "鳥啼東嶺上，花發樹南枝。", "園林并紫陌，賞翫頗相宜。", "行人半醉半醒，游客似憨似癡。", "或歌或舞，或笑或悲。", "頭頭盡是吾家事，處處全彰妙總持。", "因甚把住，特地生疑。", "辜他古德，努力披陳。", "不省這個意，脩行徒苦辛。"]'),
('955c4e77-0282-4820-9e74-a587d9f5a2a8','偈六十三首  其二','釋道寧','宋','宋诗','song-poetry','','[]','不是風動，不是幡動，仁者心動。',52,'全唐诗/poet.song.63000.json','["不是風動，不是幡動，仁者心動。", "大小老盧，好與三十棒。", "只知穿靴，不覺袴綻。", "鳥啼處處皆相似，花落不聞流水聲。"]'),
('8ef16dbf-9f59-4f9e-b292-5de90bff7d37','偈六十三首  其三','釋道寧','宋','宋诗','song-poetry','','[]','未透祖師關，時光如箭急。',24,'全唐诗/poet.song.63000.json','["未透祖師關，時光如箭急。", "白髮皓然生，新年又五日。"]'),
('10808c77-7957-4ae4-ad3c-98031a7b345a','偈六十三首  其四','釋道寧','宋','宋诗','song-poetry','','[]','等閒垂手去，八面清風生。',24,'全唐诗/poet.song.63000.json','["等閒垂手去，八面清風生。", "大悲不展手，通身是眼睛。"]'),
('ec1dd151-f843-4e1f-aeb2-6803191a5362','偈六十三首  其五','釋道寧','宋','宋诗','song-poetry','','[]','開門待知識，知識不來過。',38,'全唐诗/poet.song.63000.json','["開門待知識，知識不來過。", "知識既過，憑何施設。", "金果早朝猨摘去，玉花晚後鳳銜來。"]'),
('40300b4e-806e-4b3c-af12-3ab589968beb','偈六十三首  其六','釋道寧','宋','宋诗','song-poetry','','[]','南北東西萬萬千，趙州待客豈徒然。',32,'全唐诗/poet.song.63000.json','["南北東西萬萬千，趙州待客豈徒然。", "莫嫌冷淡無滋味，慣把脂麻一例煎。"]'),
('cb683ef8-9c84-4536-af38-d6a21f44b6ee','偈六十三首  其七','釋道寧','宋','宋诗','song-poetry','','[]','報慈家風，淡薄厨堂。',104,'全唐诗/poet.song.63000.json','["報慈家風，淡薄厨堂。", "諸事蕭索，唯有金剛。", "眼睛四海，禪人齩嚼。", "齩得破，曠劫無明。", "須臾銷鑠，天上人間，自在快樂。", "齩不破，成結縛。", "六用門頭，塵緣競作。", "你齩嚼，閒處著。", "燦爛無瑕，光明閃爍。", "幾回覿面相呈，自是諸人諱却。"]'),
('c95dc8e6-4f34-4a85-b1b3-0f9732715118','偈六十三首  其八','釋道寧','宋','宋诗','song-poetry','','[]','真不掩僞，曲不藏直。',40,'全唐诗/poet.song.63000.json','["真不掩僞，曲不藏直。", "句裏明人，言中辨的。", "處處總持，頭頭彌勒。", "擬議思量，當門荆棘。"]'),
('99f7914c-0cb1-4f72-a6a8-eb5f7bebe64b','偈六十三首  其九','釋道寧','宋','宋诗','song-poetry','','[]','禪人莫莽鹵，二月又初五。',130,'全唐诗/poet.song.63000.json','["禪人莫莽鹵，二月又初五。", "透徹祖師關，一句該今古。", "春色無高下，園林花木紅。", "總持門大啟，何處覓圓通。", "休問迷逢達磨，須知垂手塵中。", "踏翻厚地，刺破虛空。", "人天牓樣，佛祖家風。", "敢與龍王鬭富，自他兼濟何窮。", "翻身不露迹，直上妙高峰。", "渠無面目，三界爲家。", "解把過頭杖，逢春點異花。"]'),
('45964ff0-d5c3-45c4-a8bd-0da901e186ec','偈六十三首  其一○','釋道寧','宋','宋诗','song-poetry','','[]','時光迅速，不與人期。',56,'全唐诗/poet.song.63000.json','["時光迅速，不與人期。", "剎那異世，早見歲除。", "未明心地，難免狐疑。", "設使問似百川競注，答如大海吞流。", "古佛堂中，都用不著。"]'),
('367e25d4-18c2-4d7b-bb76-b92fa7d957b7','偈六十三首  其一一','釋道寧','宋','宋诗','song-poetry','','[]','問答尖新逞峻機，如將畫餠要充饑。',48,'全唐诗/poet.song.63000.json','["問答尖新逞峻機，如將畫餠要充饑。", "縱經塵劫空勞力，爭似忘言合大虛。", "萬古碧潭空界月，再三撈摝始應知。"]'),
('1b596042-7633-4947-a836-e5a62fefa003','偈六十三首  其一二','釋道寧','宋','宋诗','song-poetry','','[]','熙熙風景不相饒，免見丹霞把佛燒。',128,'全唐诗/poet.song.63000.json','["熙熙風景不相饒，免見丹霞把佛燒。", "莫謂開爐無一事，汾陽扇子手中搖。", "祖師密旨，杳絕纖埃。", "應用無私，匪虧時節。", "寒時寒，熱時熱。", "木佛放光明，院主生忻悅。", "絹扇足風凉，衲僧搖不徹。", "分明漏泄天機，底事因何不瞥。", "若也玄關撥轉，自然心眼豁開。", "方信普通年遠事，豈從葱嶺带將來。"]'),
('22b06b57-ff8e-4dc0-991f-89d925734a8f','偈六十三首  其一三','釋道寧','宋','宋诗','song-poetry','','[]','兵隨印轉，將逐符行。',20,'全唐诗/poet.song.63000.json','["兵隨印轉，將逐符行。", "把斷要關，不通音信。"]'),
('0adad299-1fb1-4b9c-9a28-5688f4779f62','偈六十三首  其一四','釋道寧','宋','宋诗','song-poetry','','[]','以字不是八不成，無言童子笑忻忻。',44,'全唐诗/poet.song.63000.json','["以字不是八不成，無言童子笑忻忻。", "優曇華現人間瑞，鼻孔通天嗅不聞。", "日月不到處，特地好乾坤。"]'),
('1030f8e0-e7bb-42db-bd96-105b9897cd15','偈六十三首  其一五','釋道寧','宋','宋诗','song-poetry','','[]','湘山青，湘水碧。',38,'全唐诗/poet.song.63000.json','["湘山青，湘水碧。", "上下四維，東西南北。", "處處釋迦，頭頭彌勒。", "啐啄同時，無勞外覓。"]'),
('2598927e-c067-48ae-aa06-bbbf8042e8a0','偈六十三首  其一六','釋道寧','宋','宋诗','song-poetry','','[]','此方真教體，清浄在音聲。',24,'全唐诗/poet.song.63000.json','["此方真教體，清浄在音聲。", "欲入三摩提，實從聞中證。"]'),
('9b540232-771b-406a-b105-d7f499db9f83','偈六十三首  其一七','釋道寧','宋','宋诗','song-poetry','','[]','滂沱天際雨，嘹喨寺亭鐘。',24,'全唐诗/poet.song.63000.json','["滂沱天際雨，嘹喨寺亭鐘。", "耳目不到處，翻憐面壁翁。"]'),
('a72c9b7f-3096-4e4d-93ae-adcab956f775','偈六十三首  其一八','釋道寧','宋','宋诗','song-poetry','','[]','暗裏抽橫骨，明中坐舌頭。',24,'全唐诗/poet.song.63000.json','["暗裏抽橫骨，明中坐舌頭。", "偏圓不到處，萬古及千秋。"]'),
('2fe48131-bc65-460b-9819-012aa9525aff','偈六十三首  其一九','釋道寧','宋','宋诗','song-poetry','','[]','先賢垂範，流落人間。',56,'全唐诗/poet.song.63000.json','["先賢垂範，流落人間。", "日久歲深，禪人不顧。", "語非玄妙，直透重關。", "畫缾打破，淥水青山。", "莫訝報慈多冷淡，得盤桓處且盤桓。"]'),
('0d1ca16b-a535-41c7-9f8d-434a31c8b690','偈六十三首  其二○','釋道寧','宋','宋诗','song-poetry','','[]','凜凜玄風，塵塵三昧。',40,'全唐诗/poet.song.63000.json','["凜凜玄風，塵塵三昧。", "信手拈來，曾無障礙。", "不用安排，素非憎愛。", "透過斯關，逍遥自在。"]'),
('3a247b98-6c79-42e8-b585-3025c05dc56a','偈六十三首  其二一','釋道寧','宋','宋诗','song-poetry','','[]','先賢垂範，巧妙臨時。',44,'全唐诗/poet.song.63000.json','["先賢垂範，巧妙臨時。", "解烹露地白牛，慣炊黍米香飯。", "煮野菜羹，唱邨田樂。", "更深夜靜，與衆分冬。"]'),
('3e600876-c1db-454e-b6c8-88a2ee4c4afa','偈六十三首  其二二','釋道寧','宋','宋诗','song-poetry','','[]','大家東齩西齩，忽然齩著一個。',62,'全唐诗/poet.song.63000.json','["大家東齩西齩，忽然齩著一個。", "始知是處綠楊堪繫馬，家家門庭透長安。", "坐斷千聖舌頭，露出平生光彩。", "莫嫌冷淡無滋味，一飽能忘萬劫饑。"]'),
('c96d1bdc-31a4-4d98-ae71-82bb09e71d5a','偈六十三首  其二三','釋道寧','宋','宋诗','song-poetry','','[]','藥山老漢慎初護末，佛眼難窺。',38,'全唐诗/poet.song.63000.json','["藥山老漢慎初護末，佛眼難窺。", "院主狹路相逢，等閒蹉過。", "至今千古之下，掛人齒牙。"]'),
('b57a0a4f-187d-4078-b86a-04aa55d1c697','偈六十三首  其二四','釋道寧','宋','宋诗','song-poetry','','[]','三八念誦，五日一參。',66,'全唐诗/poet.song.63000.json','["三八念誦，五日一參。", "古佛標牓，今人可觀。", "通方上士，不用顢頇。", "如石含玉，似地擎山。", "直下會得，也大無端。", "明暗一條今古路，依俙屈曲隔煙嵐。"]'),
('d002296b-f0ee-4c61-9446-3c620da73fed','偈六十三首  其二五','釋道寧','宋','宋诗','song-poetry','','[]','祖師門下，妙旨無私。',118,'全唐诗/poet.song.63000.json','["祖師門下，妙旨無私。", "不墮物機，混融凡聖。", "所以涅槃城裏，作者猶嗤。", "明月堂前，道人不顧。", "灰身滅智，豈是丈夫。", "避色逃聲，何名作者。", "撈龍打鳳，須信男兒。", "露刃藏鋒，還他開士。", "化城抹過，寶所非遥。", "獨步坤維，何人境界。", "打破畫缾歸去後，南山下雨北山雲。"]'),
('5ed665e3-bd6c-41fe-9d94-ef7f8dc44284','偈六十三首  其二六','釋道寧','宋','宋诗','song-poetry','','[]','漏泄春消息，梅花徧界開。',60,'全唐诗/poet.song.63000.json','["漏泄春消息，梅花徧界開。", "千峰無異色，平地絕纖埃。", "莫謂白牛無覓處，普賢招手待君來。", "急回首，不須猜。", "乾坤都一片，何用更徘徊。"]'),
('6247c82a-f776-4d5d-9e27-73004eaf412c','偈六十三首  其二七','釋道寧','宋','宋诗','song-poetry','','[]','大道無私，遇緣展縮。',119,'全唐诗/poet.song.63000.json','["大道無私，遇緣展縮。", "年年四月，今朝普請，方來禁足。", "寒山嚲袖舞三臺，拾得橫琴彈一曲。", "一二三，四五六。", "夏雨布長空，清聲發幽谷。", "直饒不墮宮商，也是强生節目。", "爭如野外農夫，擊壤高歌鼓腹。", "不學禪律威儀，免見蠟人隨逐。", "丹鳳不棲無影樹，直透煙霄意自殊。"]'),
('71b494a1-c4ad-4149-953e-1bf9c18e842b','偈六十三首  其二八','釋道寧','宋','宋诗','song-poetry','','[]','乾坤之內，宇宙之中。',52,'全唐诗/poet.song.63000.json','["乾坤之內，宇宙之中。", "高懸舜日，大扇堯風。", "祝一人之壽算，祈萬世之穹隆。", "唯吾家佛子受賜頗多，物外優游憑何祝。"]'),
('2487a270-0c55-4733-ab8a-664825359aa7','偈六十三首  其二九','釋道寧','宋','宋诗','song-poetry','','[]','是法住法位，世間相常住。',82,'全唐诗/poet.song.63000.json','["是法住法位，世間相常住。", "南山靉靆生雲，北山滂沱下雨。", "通身是口，阿師比擬。", "徒誇唇觜，把定放行。", "目前火急便還家，莫認殊鄉爲故里。", "官不容鍼，私通車馬。", "幸對人天，何妨詰問。"]'),
('63d45357-5251-4f16-a654-5a613fead1c6','偈六十三首  其三○','釋道寧','宋','宋诗','song-poetry','','[]','浩浩塵中，善能垂手。',57,'全唐诗/poet.song.63000.json','["浩浩塵中，善能垂手。", "悲智冥符，古今希有。", "深入總持門，氣宇衝斗牛。", "目連鶖子，攢眉妙德，空生緘口。", "一句無私，掃際窠臼。"]'),
('aa036ac1-70d3-4a65-b3fe-c9f28e6c1c13','偈六十三首  其三一','釋道寧','宋','宋诗','song-poetry','','[]','徧界不曾藏，通身無影像。',52,'全唐诗/poet.song.63000.json','["徧界不曾藏，通身無影像。", "相逢莫訝太愚癡，曠劫至今無伎倆。", "無伎倆，少人知。", "大體還他肌骨好，何須照鏡畫娥眉。"]'),
('90409c14-bb2b-40bd-a385-d304cd93c7e9','偈六十三首  其三二','釋道寧','宋','宋诗','song-poetry','','[]','經入藏，禪歸海。',48,'全唐诗/poet.song.63000.json','["經入藏，禪歸海。", "未足衲僧親道底，拂袖前行歸去來，擊碎重關門大啟。", "長安夜夜家家月，幾處笙歌幾處愁。"]'),
('60143b86-8dcf-460e-b625-1ed9f6965441','偈六十三首  其三三','釋道寧','宋','宋诗','song-poetry','','[]','空王門下，法令當行。',106,'全唐诗/poet.song.63000.json','["空王門下，法令當行。", "列局分司，利生爲務。", "無明海內，駕起慈舟。", "入我山中，盛栽忍草。", "伶俜遊子，誘引還家。", "直指衣中，久懷至寶。", "獲解脫道，證本圓常。", "報佛深恩，方名垂手。", "不傷風化，物義兩全。", "金殿玉堂留不住，披毛戴角又重來。"]'),
('b2265984-2456-4e66-885a-8f7165fbb3ae','偈六十三首  其三四','釋道寧','宋','宋诗','song-poetry','','[]','人天普集，龍象交參。',64,'全唐诗/poet.song.63000.json','["人天普集，龍象交參。", "大事全彰，云何不顧。", "須待提綱舉要，鼓唱玄風。", "蔟錦攢花，以爲諦當。", "都無所益，枉費心機。", "奈緣中下之流，無由湊泊。"]'),
('2500d44b-6696-41bd-9a7d-6e22096f5d40','偈六十三首  其三五','釋道寧','宋','宋诗','song-poetry','','[]','全提要妙，三藏絕詮。',165,'全唐诗/poet.song.63000.json','["全提要妙，三藏絕詮。", "海印舒光，該羅法界。", "有情無情，炳然應現。", "有時南州北郡，買賣交關。", "有時看風把柁，順水行船。", "有時酒肆茶坊，迎賓待客。", "有時投壺走馬，歌笑圍棋。", "種種多般，要源流出。", "玄關瞥轉，大用現前。", "一槩無私，平等大道。", "始知諸佛轉法輪，群生解差別。", "目擊便歸來，秤鎚渾是鐵。", "如斯告報，正屬化門，不犯鋒楞。", "善吉巖前草不生，僑尸謾把天花散。"]'),
('1e3a78c4-4c3b-439b-a459-96d259766d93','偈六十三首  其三六','釋道寧','宋','宋诗','song-poetry','','[]','空空至理，杳絕纖埃。',52,'全唐诗/poet.song.63000.json','["空空至理，杳絕纖埃。", "功勳不到，妙葉難該。", "不落是非中，有無爭敢和。", "何勞指註，便請承當。", "過後追風，徒誇好手。"]'),
('b58bfefc-7ab1-4efc-a455-714cd6986143','偈六十三首  其三七','釋道寧','宋','宋诗','song-poetry','','[]','應機不妙，展事難諧。',20,'全唐诗/poet.song.63000.json','["應機不妙，展事難諧。", "檢點將來，弄巧成拙。"]'),
('8c768c8d-f3a3-4bf1-b1ce-e15e67f46a94','偈六十三首  其三八','釋道寧','宋','宋诗','song-poetry','','[]','禪家流，勿忌諱。',94,'全唐诗/poet.song.63000.json','["禪家流，勿忌諱。", "干木隨身，逢場作戲。", "有時高卧白雲，有時持盂鬧市。", "有時愛撫沒絃琴，有時善宣無量義。", "有時似癡似騃，有時爲祥爲瑞。", "不是碧眼胡，亦非傅大士。", "住，住，他年自有知音知，何必清風動天地。"]'),
('3a11629d-233b-47ab-b209-bdad188d047e','偈六十三首  其三九','釋道寧','宋','宋诗','song-poetry','','[]','秋日耀長空，秋江浸虛碧。',48,'全唐诗/poet.song.63000.json','["秋日耀長空，秋江浸虛碧。", "傷嗟門外人，處處尋彌勒。", "驀路忽抬頭，相逢不相識。", "剪盡霜前竹，臨谿不化龍。"]'),
('b51b92f2-d743-4783-b9e1-2d836791cf99','偈六十三首  其四○','釋道寧','宋','宋诗','song-poetry','','[]','萬里無雲，長天一色。',67,'全唐诗/poet.song.63000.json','["萬里無雲，長天一色。", "不落古今，那該彼此。", "要津把斷，風骨旋生。", "設使靈山密付，謾說拈華少室，親傳徒誇得髓。", "師子窟中無異獸，象王行處絕狐蹤。"]'),
('76e7ab05-33db-4d5b-8182-d1d26b0757e0','偈六十三首  其四一','釋道寧','宋','宋诗','song-poetry','','[]','薄𠜱明月碎清風，淺種深耕莫大功。',32,'全唐诗/poet.song.63000.json','["薄𠜱明月碎清風，淺種深耕莫大功。", "破二作三橫豎算，四方八面用無窮。"]'),
('3b03c155-318b-44c0-ac95-40586f11b332','偈六十三首  其四二','釋道寧','宋','宋诗','song-poetry','','[]','諸佛放光明，助發實相義。',24,'全唐诗/poet.song.63000.json','["諸佛放光明，助發實相義。", "言下合無生，爲祥復爲瑞。"]'),
('030f8931-b520-4882-b1e6-7ac7bb73061c','偈六十三首  其四三','釋道寧','宋','宋诗','song-poetry','','[]','靈山顧視，迦葉親聞。',82,'全唐诗/poet.song.63000.json','["靈山顧視，迦葉親聞。", "白藕峰前，盧公契旨。", "直饒鍼芥相投，未免隨波逐浪。", "俱成勝負，猶涉驅馳。", "爭似青天爲幕，夜月爲鈎。", "卧藤蘿下，塊石枕頭。", "踏得故關田地穩，不風流處也風流。"]'),
('8d3ce6aa-bc47-4800-9dda-039f505ec2ba','偈六十三首  其四四','釋道寧','宋','宋诗','song-poetry','','[]','雲收天際，霧捲長空。',56,'全唐诗/poet.song.63000.json','["雲收天際，霧捲長空。", "坐立儼然，誰家風月。", "這裏薦得，早涉崎嶇。", "更待商量，般雪填井。", "不許夜行剛把火，直須當道與人看。"]'),
('ac0634d3-6aa5-4602-85b6-32dbc3a647e8','偈六十三首  其四五','釋道寧','宋','宋诗','song-poetry','','[]','先賢垂範，語真如弦。',36,'全唐诗/poet.song.63000.json','["先賢垂範，語真如弦。", "衲子奔波，剛然不顧。", "粉骨碎身未足酬，一句了然超百億。"]'),
('1bfc4c77-9887-41b4-82be-eb45ad29633d','偈六十三首  其四六','釋道寧','宋','宋诗','song-poetry','','[]','田中稻子已焦黄，顆粒圓成不并常。',48,'全唐诗/poet.song.63000.json','["田中稻子已焦黄，顆粒圓成不并常。", "妙手及時收拾後，五湖龍象濟饑瘡。", "劍爲不平離寶匣，藥因救病出金缾。"]'),
('938ed3ba-2f8b-4215-968c-a1d628bc1829','偈六十三首  其四七','釋道寧','宋','宋诗','song-poetry','','[]','一人發真歸源，十方虛空，悉皆銷殞。',33,'全唐诗/poet.song.63000.json','["一人發真歸源，十方虛空，悉皆銷殞。", "渾家不是不進步，無奈當門荆棘生。"]'),
('c8a91bf0-169f-43c3-92a1-e7a99a031e52','偈六十三首  其四八','釋道寧','宋','宋诗','song-poetry','','[]','高提祖印，獨耀寰區。',123,'全唐诗/poet.song.63000.json','["高提祖印，獨耀寰區。", "坐却舌頭，聖凡罔測。", "聲前要旨，妙葉難該。", "句後玄關，金鍼雙鎖。", "通人分上，肯受提撕。", "懞懂禪流，徒誇作略。", "設使五湖衲子，四海高人。", "問似龍飛鳳舞，答如玉轉珠回。", "向本分事中，白雲萬里。", "諸緣不涉，豈落今時。", "混沌未分全體現，乾坤纔剖失便宜。"]'),
('1fb3f8dd-9c29-4919-b8e9-42c6e48c33df','偈六十三首  其四九','釋道寧','宋','宋诗','song-poetry','','[]','妙孤峰頂，竟日不逢。',36,'全唐诗/poet.song.63000.json','["妙孤峰頂，竟日不逢。", "菩提場中，隨處合會。", "孰謂祖師關棙險，等閒拈出與人看。"]'),
('263ac4bb-a0fe-4b66-8877-b6514d423a5e','偈六十三首  其五○','釋道寧','宋','宋诗','song-poetry','','[]','兔走烏飛，暗移時節。',92,'全唐诗/poet.song.63000.json','["兔走烏飛，暗移時節。", "入夏早三旬，衲僧徹未徹。", "休尋向上關，莫問西來訣。", "健則松徑閒行，困則堂中便歇。", "恩光一道皎然，曠劫未嘗生滅。", "無物可并雌黄，教我云何剖說。", "回頭踏著自家鄉，始信秤鎚渾是鐵。"]'),
('583cbf78-cf0a-4301-8a1e-97f9760c77f0','偈六十三首  其五一','釋道寧','宋','宋诗','song-poetry','','[]','形名未兆，早涉戈矛。',60,'全唐诗/poet.song.63000.json','["形名未兆，早涉戈矛。", "是非鋒起，徹底風流。", "左旋右轉，海印全收。", "枯木堂前，徒話會無。", "明山上，任優游。", "君不見，一葉落時天下秋。"]'),
('4d16cc01-b982-4d7d-8085-d804203d5bcd','偈六十三首  其五二','釋道寧','宋','宋诗','song-poetry','','[]','門外春將暮，園林華木殘。',90,'全唐诗/poet.song.63000.json','["門外春將暮，園林華木殘。", "靈雲消息在，遊子莫顢頇。", "雲舒四野，雨瀉長空。", "花落花開，春來春去。", "往復本非移易，迷悟豈有差殊。", "急回首，不須疑。", "嫩竹抽新笋，寒松長舊枝。", "靈雲親悟處，眉上更安眉。"]'),
('e058f83f-7bfd-4cf5-9381-35128f535de3','偈六十三首  其五三','釋道寧','宋','宋诗','song-poetry','','[]','生也不知，死也不會。',46,'全唐诗/poet.song.63000.json','["生也不知，死也不會。", "不知不會，逍遥自在。", "南北東西，曾無罣礙。", "露地白牛無覓處，火裏蝍蟟飛上天。"]'),
('b9f17d2c-b95a-4baa-8aa1-10cff93c2c13','偈六十三首  其五四','釋道寧','宋','宋诗','song-poetry','','[]','古今不異，達者同歸。',78,'全唐诗/poet.song.63000.json','["古今不異，達者同歸。", "踏著斯關，自他兼濟。", "山僧不惜眉毛，重爲諸人指註。", "休，休，大丈夫兒合自由。", "急急脩，莫悠悠，看看便是結交頭。", "莫學陵田栽晚稻，一陣霜風無可收。"]'),
('f73835bd-711b-4fbd-9fc5-6a659988c647','偈六十三首  其五五','釋道寧','宋','宋诗','song-poetry','','[]','大道皎然，本無迷悟。',50,'全唐诗/poet.song.63000.json','["大道皎然，本無迷悟。", "杳忘三際，超越上乘。", "透古透今，非玄非妙。", "通同法界，一種平懷。", "古路無私，何人措足。"]'),
('0c2d1517-4ef7-402f-ae45-95fcf3a19e4c','偈六十三首  其五六','釋道寧','宋','宋诗','song-poetry','','[]','趙州老漢，大似因風吹火。',72,'全唐诗/poet.song.63000.json','["趙州老漢，大似因風吹火。", "順水颺帆，擊碎斯關。", "塵中物外，凡則全凡，聖則全聖。", "若能如是解，通達事理竟。", "其或涯際未分，路逢死蛇莫打殺，沒底籃子盛將歸。"]'),
('05e5c9d8-632b-4abf-9ad5-5603e1975520','偈六十三首  其五七','釋道寧','宋','宋诗','song-poetry','','[]','滔滔法海，清濁混流。',148,'全唐诗/poet.song.63000.json','["滔滔法海，清濁混流。", "湛湛禪河，魚龍變化。", "杳杳無涯際，澄澄徹底寒。", "短棹孤舟，徒誇好手。", "長竿畫舫，方稱男兒。", "風浪掀天，雲雷匝界。", "絲綸便擲，不顧危亡。", "靈鰲錦尾上鈎來，跛鼈盲龜隨浪去。", "滿船裝載，月渚蘆灣。", "共樂昇平，同歌道泰。", "從前祖業，豈假外求。", "截流到岸之人，且道是何面目。", "須彌頂上非凡木，白藕峰前得處高。"]'),
('7fe04661-7fa7-495a-acb8-b54a2ea4cce5','偈六十三首  其五八','釋道寧','宋','宋诗','song-poetry','','[]','未離兜率，已降王宮。',52,'全唐诗/poet.song.63000.json','["未離兜率，已降王宮。", "未出母胎，度人已畢。", "日日日從東畔出，朝朝鷄向五更啼。", "雖然不是桃源洞，春至桃花亦滿蹊。"]'),
('8a40553d-0da2-48ba-9f36-123be70aaf4e','偈六十三首  其五九','釋道寧','宋','宋诗','song-poetry','','[]','毗藍園內，右脇降生。',60,'全唐诗/poet.song.63000.json','["毗藍園內，右脇降生。", "七步周行，四方目顧。", "天上天下，唯我獨尊。", "大似貪觀天上月，失却掌中珠。", "天生伎倆能奇怪，末上輸他弄一場。"]'),
('35f99494-e90e-4938-a12b-7821d7e7342d','偈六十三首  其六○','釋道寧','宋','宋诗','song-poetry','','[]','靈山密旨，迦葉非聞。',94,'全唐诗/poet.song.63000.json','["靈山密旨，迦葉非聞。", "少室玄言，神光道聽。", "拈華得髓，盡是虛名。", "妙用無私，匪從外有。", "放行也，皇風蕩蕩，帝道平平。", "收來也，海晏河清，民歌率土。", "不收不放，共樂昇平。", "金輪統御三千界，山嶽齊呼萬歲聲。"]'),
('4461135f-056e-4666-88f2-2224b3681e50','偈六十三首  其六一','釋道寧','宋','宋诗','song-poetry','','[]','露地白牛烹却了，清風細切亦虛傳。',48,'全唐诗/poet.song.63000.json','["露地白牛烹却了，清風細切亦虛傳。", "報慈此夜憑何獻，一碗麤湯直萬千。", "兩手持來如得用，不須辛苦走山川。"]'),
('55a33133-193c-472d-8a4e-2bf5bc04806e','偈六十三首  其六二','釋道寧','宋','宋诗','song-poetry','','[]','要行便行，要住即住。',42,'全唐诗/poet.song.63000.json','["要行便行，要住即住。", "翻身踏破太虛空，推倒妙峰無影樹。", "古佛位中留不住，夜來和雨宿寒谿。"]'),
('001dc1d9-5f01-42de-9110-c2c34a4bc610','偈六十三首  其六三','釋道寧','宋','宋诗','song-poetry','','[]','見月休觀指，還家罷問程。',74,'全唐诗/poet.song.63000.json','["見月休觀指，還家罷問程。", "此是古人語，丹青畫不成。", "只如一夜風雷，連宵春雨。", "三方及四維，上下亦復爾。", "慈門大啟，今古歷然。", "踏得故關田地穩，始知千聖不曾傳。"]'),
('f1ab6bf8-f5a2-47f8-9e07-bfcf256dec72','頌古十六首  其一','釋道寧','宋','宋诗','song-poetry','','[]','前箭猶輕後箭深，行人何事苦沉吟。',32,'全唐诗/poet.song.63000.json','["前箭猶輕後箭深，行人何事苦沉吟。", "翻身若解看方便，始信真鍮不博金。"]'),
('33136155-c8c6-452c-b9ea-f1b4c6a2106d','頌古十六首  其二','釋道寧','宋','宋诗','song-poetry','','[]','抹粉塗坯恰似獃，神頭鬼面舞三臺。',32,'全唐诗/poet.song.63000.json','["抹粉塗坯恰似獃，神頭鬼面舞三臺。", "千千萬萬人窺看，子細不知誰見來。"]'),
('a1a79f8b-d7d4-424a-92a7-4d9f62c0423c','頌古十六首  其三','釋道寧','宋','宋诗','song-poetry','','[]','一片虛空亙古今，鱗龍頭角競疏親。',32,'全唐诗/poet.song.63000.json','["一片虛空亙古今，鱗龍頭角競疏親。", "坐亡立脫知多少，鐵樹花開別是春。"]'),
('6870d51d-af0b-48ef-a6a7-b7440b8c963d','頌古十六首  其四','釋道寧','宋','宋诗','song-poetry','','[]','春去復春來，桃花依舊開。',28,'全唐诗/poet.song.63000.json','["春去復春來，桃花依舊開。", "東風浩浩曾無間，剛地靈雲道不猜。"]'),
('1913cfa7-9cbd-4719-b670-c611a8bd47df','頌古十六首  其五','釋道寧','宋','宋诗','song-poetry','','[]','百煉精金大冶中，任他騰焰亙大紅。',32,'全唐诗/poet.song.63000.json','["百煉精金大冶中，任他騰焰亙大紅。", "須臾拈出教人看，添得行家價轉豐。"]'),
('058e901d-d43f-4ca6-bec5-132ffcce07da','頌古十六首  其六','釋道寧','宋','宋诗','song-poetry','','[]','遊山翫水事尋常，早晚歸來鬢欲霜。',32,'全唐诗/poet.song.63000.json','["遊山翫水事尋常，早晚歸來鬢欲霜。", "踏破草鞋回首看，數聲猨叫白雲鄉。"]'),
('1bc78f38-3914-4494-b394-accc4e8720db','頌古十六首  其七','釋道寧','宋','宋诗','song-poetry','','[]','風頭坐斷進還難，衲子相將不易看。',32,'全唐诗/poet.song.63000.json','["風頭坐斷進還難，衲子相將不易看。", "不到潼關天已曉，不堪回首望長安。"]'),
('cd17de6e-819a-4a60-8541-58798db494a3','頌古十六首  其八','釋道寧','宋','宋诗','song-poetry','','[]','叢林乍入問來由，喫粥無過洗缽休。',32,'全唐诗/poet.song.63000.json','["叢林乍入問來由，喫粥無過洗缽休。", "有意氣時添意氣，不風流處也風流。"]'),
('bb68d81e-ffe8-4f16-aee1-c29834efa5c5','頌古十六首  其九','釋道寧','宋','宋诗','song-poetry','','[]','非風幡動唯心動，猶涉廉纖强指陳。',32,'全唐诗/poet.song.63000.json','["非風幡動唯心動，猶涉廉纖强指陳。", "大地未曾添寸土，不知誰是點頭人。"]'),
('7495d224-7a46-4203-867b-4c7d4af4f05e','頌古十六首  其一○','釋道寧','宋','宋诗','song-poetry','','[]','火號更深喝道來，普門關棙一時開。',32,'全唐诗/poet.song.63000.json','["火號更深喝道來，普門關棙一時開。", "圓通大師呵呵笑，不是峨嵋與五臺。"]'),
('2ae5b61c-634c-4d83-8623-39b707866c6d','頌古十六首  其一一','釋道寧','宋','宋诗','song-poetry','','[]','妙體本如如，無勞待卷舒。',24,'全唐诗/poet.song.63000.json','["妙體本如如，無勞待卷舒。", "直饒恁麽去，未免草菴居。"]'),
('7f9bdd37-1d97-4347-923c-04b2ca9b463a','頌古十六首  其一二','釋道寧','宋','宋诗','song-poetry','','[]','思量有個悟因由，萬疊雲山障路頭。',32,'全唐诗/poet.song.63000.json','["思量有個悟因由，萬疊雲山障路頭。", "更話煎茶并掃地，泥中洗土轉添愁。"]'),
('3f8c1f08-e176-4c1f-8de2-bccbd1a58e5a','頌古十六首  其一三','釋道寧','宋','宋诗','song-poetry','','[]','煎茶掃地事如麻，若了如麻理不差。',32,'全唐诗/poet.song.63000.json','["煎茶掃地事如麻，若了如麻理不差。", "打破畫缾歸去後，始知凡聖眼中花。"]'),
('b805e96d-6efc-49ad-bfa8-c6353d19d20d','頌古十六首  其一四','釋道寧','宋','宋诗','song-poetry','','[]','工巧諸伎藝，頭頭迸出真祥瑞。',30,'全唐诗/poet.song.63000.json','["工巧諸伎藝，頭頭迸出真祥瑞。", "瞥然端坐到家鄉，堪笑維摩談不二。"]'),
('6bf81207-a7c0-436e-b1ac-1bd1106e1eb0','頌古十六首  其一五','釋道寧','宋','宋诗','song-poetry','','[]','盡現行此事，一段光明照天地。',30,'全唐诗/poet.song.63000.json','["盡現行此事，一段光明照天地。", "體用從來非自他，何須更覓錐頭利。"]'),
('ef3a9b2f-62b2-4c06-b080-c404232a98eb','頌古十六首  其一六','釋道寧','宋','宋诗','song-poetry','','[]','諸佛非道父非親，格外殷勤强指陳。',32,'全唐诗/poet.song.63000.json','["諸佛非道父非親，格外殷勤强指陳。", "朕兆未分全體露，不知誰識個中人。"]'),
('f9140cc1-63db-4d2a-bb33-a7533498117a','頌古十六首  其一七','釋道寧','宋','宋诗','song-poetry','','[]','法王嚴父是真依，二臂三頭轉背伊。',32,'全唐诗/poet.song.63000.json','["法王嚴父是真依，二臂三頭轉背伊。", "要會祖師端的旨，不勞瞬目又揚眉。"]'),
('03961e0d-38b4-482f-974b-18fcbf5592fe','新笋竹','釋道寧','宋','宋诗','song-poetry','','[]','迸破莓苔地，亭亭出短籬。',48,'全唐诗/poet.song.63000.json','["迸破莓苔地，亭亭出短籬。", "籜隨風雨解，根有歲寒期。", "鳳管終須奏，漁竿莫可窺。", "儻容常守節，定見化龍時。"]'),
('f98cae67-f141-467a-a9e5-1f228a8c9b73','寄希饒閒堂','釋道寧','宋','宋诗','song-poetry','','[]','浮名浮利懶躋攀，聞搆茆堂杳靄間。',32,'全唐诗/poet.song.63000.json','["浮名浮利懶躋攀，聞搆茆堂杳靄間。", "搔首凭欄人不會，落花啼鳥蘚痕斑。"]'),
('0c6258a5-4cb3-4762-81c8-d4f1003f3bff','十六夜對月和十五夜無月','釋道寧','宋','宋诗','song-poetry','','[]','四面陰雲旋旋舒，冰輪一片耀昏衢。',64,'全唐诗/poet.song.63000.json','["四面陰雲旋旋舒，冰輪一片耀昏衢。", "影分萬派曾無異，光照千門豈有殊。", "境寂風清思至友，香殘玉篆倦加趺。", "寥寥廓徹瑠璃界，心月圓明德不孤。"]'),
('161bec7d-b040-4cc1-916c-9550ef4a1ac3','辯禪人五羊作丐寫師真求贊','釋道寧','宋','宋诗','song-poetry','','[]','非幻非真，僧繇難寫。',72,'全唐诗/poet.song.63000.json','["非幻非真，僧繇難寫。", "貌不驚人，權衡保社。", "畫虎作貓，指馿爲馬。", "月彩分輝，風清大夏。", "五羊城裏舊知音，覿面相呈那辯也。", "慇懃寄語莫狐疑，便是蔣山寧道者。"]'),
('4ef52f4d-5807-4bca-9303-2c2bfbbb00d4','送僧歸華藏','釋道寧','宋','宋诗','song-poetry','','[]','禪人告別欲南歸，卷衲和雲伴錫飛。',32,'全唐诗/poet.song.63000.json','["禪人告別欲南歸，卷衲和雲伴錫飛。", "脚下路穿華藏界，何須待叩吉祥機。"]'),
('a2e7667d-bb7b-4bb0-9c12-0872cc5d503f','偈  其一','僧某','宋','宋诗','song-poetry','','[]','荏苒光陰歲月寒，禪家贏得共盤桓。',32,'全唐诗/poet.song.63000.json','["荏苒光陰歲月寒，禪家贏得共盤桓。", "個中消息無人會，願聞提唱祖師關。"]'),
('c703df12-d3c9-45ae-8a8e-d1d1c821c9bc','偈  其二','僧某','宋','宋诗','song-poetry','','[]','彌勒真彌勒，分身千百億。',24,'全唐诗/poet.song.63000.json','["彌勒真彌勒，分身千百億。", "時時示世人，世人俱不識。"]'),
('490fa9b7-5d4f-4266-915b-ce7cdca7de18','接花','游酢','宋','宋诗','song-poetry','','[]','色紅可使紫，葉單可使千。',144,'全唐诗/poet.song.63000.json','["色紅可使紫，葉單可使千。", "花小可使大，子小可使繁。", "天賦有定質，我力能使遷。", "自矜接花手，可奪造化權。", "衆聞悉驚詫，爲我屢嘆吁。", "用智固巧矣，天時可易歟。", "我欲春採菊，我欲冬賞桃。", "汝不能栽接，汝巧亦徒勞。", "雨露草必生，霜雪松不死。", "有本性必生，亦時雨與之。", "所遭有變易，是亦時所爲。", "時乎不可違，何物可違時。"]'),
('f7849838-afa1-412b-be0a-f9d368cd8852','韓魏公讀書堂','游酢','宋','宋诗','song-poetry','','[]','去郡五里安國寺，斷蓬荒蓧成邱墟。',96,'全唐诗/poet.song.63000.json','["去郡五里安國寺，斷蓬荒蓧成邱墟。", "郡人不置瓜李嫌，公亦甘與泉石居。", "想憎俗事敗人意，獨願燈火勤三餘。", "今人不出如處女，陋室暗屋跖不如。", "聞君讀書胡乃爾，政恐心地怠芟鋤。", "前輩渾厚應有此，難弟難兄俱可書。"]'),
('e3b92b29-96f0-4169-a547-d9c7bb9d3cd5','餞賀方回分韵得歸字','游酢','宋','宋诗','song-poetry','','[]','邀客十分飲，送君千里歸。',48,'全唐诗/poet.song.63000.json','["邀客十分飲，送君千里歸。", "情隨綠水去，目斷白鷗飛。", "松菊今應在，風塵昔已非。", "維舟待夜月，能不重依依。"]'),
('847b3d4b-0ee0-4386-b2a2-f15771b8f277','歸雁','游酢','宋','宋诗','song-poetry','','[]','天末驚風急，江湖野思長。',48,'全唐诗/poet.song.63000.json','["天末驚風急，江湖野思長。", "悲鳴愁絕塞，接翼冒風霜。", "澤岸多矰弋，雲間乏稻粱。", "茫然棲息地，飲啄欲何鄉。"]'),
('b6c521ab-1377-4fe8-98b9-f61eabffd758','感事','游酢','宋','宋诗','song-poetry','','[]','世事浮雲薄，勞生一夢長。',48,'全唐诗/poet.song.63000.json','["世事浮雲薄，勞生一夢長。", "散材依櫟社，幽意慕濠梁。", "風急鷹鸇迅，霜殘草木黄。", "投閒如有約，早晚問耕桑。"]'),
('a7daea81-38c0-4390-b7ea-165983c6df9a','春日山行有感','游酢','宋','宋诗','song-poetry','','[]','十里橋西別有天，青山欲斷翠雲連。',64,'全唐诗/poet.song.63000.json','["十里橋西別有天，青山欲斷翠雲連。", "園林寂寂鹿爲友，野服翩翩儒亦仙。", "風詠舞雩正此日，雪飄伊洛是何年。", "追尋往事頓成夢，回首春光倍黯然。"]'),
('b9442c6a-5455-4615-8332-0167d75744ff','游寶應寺','游酢','宋','宋诗','song-poetry','','[]','崒嵂三峰带白灣，誰開蘭若翠微間。',64,'全唐诗/poet.song.63000.json','["崒嵂三峰带白灣，誰開蘭若翠微間。", "竹林雲懶禪心定，草徑苔荒屐齒斑。", "天入碧嵐成玉宇，鳥飛青嶂出塵寰。", "此中即是蘂珠境，遮莫閒吟一解顔。"]'),
('a64d3c4e-df0c-4815-8d1f-25d1b74be6d3','寶應寺讀書堂成因懷明道先生','游酢','宋','宋诗','song-poetry','','[]','橋西積雪度新晴，卜築茅堂快落成。',64,'全唐诗/poet.song.63000.json','["橋西積雪度新晴，卜築茅堂快落成。", "郁郁奇花鋪野趣，關關好鳥和書聲。", "春濃嵐色無邊景，水浄天光徹底清。", "記得程門窗草綠，至今遐想每馳情。"]'),
('8b62b96c-2e43-4d2e-9bcd-41866a33d161','山中即景','游酢','宋','宋诗','song-poetry','','[]','翠靄光風世界，青松綠竹人家。',28,'全唐诗/poet.song.63000.json','["翠靄光風世界，青松綠竹人家。", "天外飛來野鳥，澗中流出桃花。"]'),
('be25c8f8-1ca6-42c0-8f3d-630a64f7be10','題河清縣廨','游酢','宋','宋诗','song-poetry','','[]','小院閑亭長薜蘿，鹿來穿徑晚經過。',32,'全唐诗/poet.song.63000.json','["小院閑亭長薜蘿，鹿來穿徑晚經過。", "夕陽蕭散簿書少，窗裏南山明月多。"]'),
('044e9ff8-b8ae-4104-8293-3fa044efe28a','水亭','游酢','宋','宋诗','song-poetry','','[]','清溪一曲繞朱樓，荷密風稠咽斷流。',32,'全唐诗/poet.song.63000.json','["清溪一曲繞朱樓，荷密風稠咽斷流。", "夾岸垂楊烟細細，小橋流水即滄洲。"]'),
('ab336ba7-97d4-4c4b-a3ef-d6b477424c29','在潁昌寄中立  其一','游酢','宋','宋诗','song-poetry','','[]','絳帷燕侍每從容，一聽微言萬慮空。',32,'全唐诗/poet.song.63000.json','["絳帷燕侍每從容，一聽微言萬慮空。", "却愧猶懸三釜樂，未能終此挹清風。"]'),
('e39bb6ee-206e-4afb-b004-2a050f6d2572','在潁昌寄中立  其二','游酢','宋','宋诗','song-poetry','','[]','蕭條清潁一茅廬，魂夢長懷與子居。',32,'全唐诗/poet.song.63000.json','["蕭條清潁一茅廬，魂夢長懷與子居。", "五里橋西楊柳路，至今車馬往來疏。"]'),
('21abae26-fcc7-425d-922d-21112ce00d2d','登歸宗巖','游酢','宋','宋诗','song-poetry','','[]','奇冠南閩此最奇，歸宗千古是誰歸。',32,'全唐诗/poet.song.63000.json','["奇冠南閩此最奇，歸宗千古是誰歸。", "至今來訪誰先至，知是曹劉先我知。"]'),
('1930b1c3-e8b4-4177-8124-cc4f49d94ca6','誨子','游酢','宋','宋诗','song-poetry','','[]','三十年前宿草廬，五年三第世間無。',32,'全唐诗/poet.song.63000.json','["三十年前宿草廬，五年三第世間無。", "門前獬豸公裳在，只恐兒孫不讀書。"]'),
('6ac36772-7912-48c6-98b1-4d2c7dc7ab20','贈陳仲循','游酢','宋','宋诗','song-poetry','','[]','即今年纔五十餘，脫去簪紱弊屣如。',64,'全唐诗/poet.song.63000.json','["即今年纔五十餘，脫去簪紱弊屣如。", "聖時搜選動空谷，策足要路爭先趨。", "廟堂故人握重柄，僵者可植瘦可腴。", "惓惓風義數寄語，掉頭不顧甘如愚。"]'),
('39cbb5c6-5da1-4d7a-a865-41ba564c4a4f','韋氏獨樂堂','游酢','宋','宋诗','song-poetry','','[]','林下徜徉得至游，高情不與世情謀。',64,'全唐诗/poet.song.63000.json','["林下徜徉得至游，高情不與世情謀。", "羲和叱馭日逾永，猿鶴尋盟山更幽。", "踽踽凉凉還自哂，休休莫莫復何求。", "應門穉子非無意，客至蕭蕭已百憂。"]'),
('54654302-945c-4ca4-9919-4db238e68848','韋深道寄傲軒','游酢','宋','宋诗','song-poetry','','[]','早付閒身老故鄉，青松成徑菊成行。',64,'全唐诗/poet.song.63000.json','["早付閒身老故鄉，青松成徑菊成行。", "搘頤獨坐心遺念，坦腹高吟興欲狂。", "甕下却應嗤畢卓，籬根遥想對羲皇。", "乘風破浪門前客，試問浮家有底忙。"]'),
('e744aa51-fcd9-4095-a895-956237fd021f','金陵野外廢寺','游酢','宋','宋诗','song-poetry','','[]','寒花窈嫋蔓頹牆，古寺蒼苔晝掩房。',64,'全唐诗/poet.song.63000.json','["寒花窈嫋蔓頹牆，古寺蒼苔晝掩房。", "犬吠屋頭山杳杳，蟲鳴階隙草荒荒。", "池塘澹月蒹葭冷，籬落西風橘柚香。", "六代江山金碧地，斷碑留得管興亡。"]'),
('5bddfa7b-8b96-49e9-aabc-d884988e1554','句','游酢','宋','宋诗','song-poetry','','[]','青山控野雙門壯，白浪排空萬馬來。',16,'全唐诗/poet.song.63000.json','["青山控野雙門壯，白浪排空萬馬來。"]'),
('0353cda4-4a2c-4701-b9a8-23887734f744','常州問東坡疾','釋維琳','宋','宋诗','song-poetry','','[]','扁舟駕蘭陵，自愞舊風物。',48,'全唐诗/poet.song.63000.json','["扁舟駕蘭陵，自愞舊風物。", "君家有天人，雄雄維摩詰。", "我口吞文殊，千里來問疾。", "若以默相酬，露柱皆笑出。"]'),
('8d56d94b-3ec5-4404-8fa3-22d93e693b96','白雲堂','釋維琳','宋','宋诗','song-poetry','','[]','堂與碧山對，白雲長作鄰。',24,'全唐诗/poet.song.63000.json','["堂與碧山對，白雲長作鄰。", "日暮白雲合，誰見白雲心。"]'),
('90e52028-90c2-4738-91ce-40e679ed0eea','有司欲取寺松供朝用感賦','釋維琳','宋','宋诗','song-poetry','','[]','大夫去作棟梁材，無復清陰覆綠苔。',32,'全唐诗/poet.song.63000.json','["大夫去作棟梁材，無復清陰覆綠苔。", "今夜月明風露冷，誤他千里鶴飛來。"]'),
('a7c26035-aa35-483f-8b37-5cd93bc5db08','句','釋維琳','宋','宋诗','song-poetry','','[]','甌面乳花誰共看。',8,'全唐诗/poet.song.63000.json','["甌面乳花誰共看。"]'),
('15b70392-d23b-4ef5-bdcb-ea508da51ebf','頌','魏二翁','宋','宋诗','song-poetry','','[]','我今入山，避此囂煩。',70,'全唐诗/poet.song.63000.json','["我今入山，避此囂煩。", "衛以卒史，聘以達官。", "豈易我樂，物外清閑。", "養真存氣，七返九還。", "金丹既就，遂陟仙壇。", "蓬萊絳闕，玉戶金關。", "有能學我，雲路非難。"]'),
('43c504d2-c96c-49d0-adc8-54b4fdd0dbea','藏頭詩','魏二翁','宋','宋诗','song-poetry','','[]','火田心主須防慎，慎行方成後世傳。',48,'全唐诗/poet.song.63000.json','["火田心主須防慎，慎行方成後世傳。", "傳守坎離爲要妙，妙趨名利作憂煎。", "前程若識丹霞法，法路應歸紫府仙。"]'),
('5476d072-f7f9-4d70-a2d4-8a6a588cc155','賦新繁周表權如詔亭','錢詠','宋','宋诗','song-poetry','','[]','選構人皆事宴逢，獨君教子襲良弓。',64,'全唐诗/poet.song.63000.json','["選構人皆事宴逢，獨君教子襲良弓。", "因聞詩禮家題舊，及寵絲綸語命同。", "几杖已尊賢老外，龜魚爭煥綵衣中。", "新來更喜增榮觀，青鎖才臣贈古風。"]'),
('9db94c93-d944-4dc6-96d9-0f5f62c2502a','仙巖即事','沈躬行','宋','宋诗','song-poetry','','[]','孟月攝提指，春遊初服成。',48,'全唐诗/poet.song.63000.json','["孟月攝提指，春遊初服成。", "招尋追舊蹟，涉歷憩孤情。", "暫爾諧心賞，相從念友聲。", "丹房探不遠，吾欲悟無生。"]'),
('fbbf27e9-2c4f-48df-92b6-8c66f2eadc77','觀潮閣','沈琪','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','疑是飛來白鷺洲，登高□□憶□流。',64,'全唐诗/poet.song.63000.json','["疑是飛來白鷺洲，登高□□憶□流。", "雲間春色連蓬島，風裏江聲繞畫樓。", "孤鶩落霞裝晚景，淡烟微雨識歸舟。", "醉鄉便是華胥國，底用乘槎犯斗牛。"]'),
('25ab0801-091a-4a75-93cb-c807945be2cc','此日不再得示同學','楊時','宋','宋诗','song-poetry','','[]','此日不再得，頹波注扶桑。',288,'全唐诗/poet.song.63000.json','["此日不再得，頹波注扶桑。", "躚躚黄小羣，毛髮忽已蒼。", "願言績學子，共惜此日光。", "術業貴及時，勉之在青陽。", "行己慎所之，戒哉畏迷方。", "舜跖善利間，所差亦毫芒。", "富貴如浮雲，苟得非所臧。", "貧賤豈吾羞，逐物乃自戕。", "胼胝奏艱食，一瓢甘糟糠。", "所逢義適然，未殊行與藏。", "斯人已云沒，簡編有遺芳。", "希顔亦顔徒，要在用心剛。", "譬猶適千里，駕言勿徊徨。", "驅馬日云遠，誰謂阻且長。", "末流學多岐，倚門誦韓莊。", "出入方寸間，雕鎸事辭章。", "學成欲何用，奔趨利名場。", "挾策博塞游，異趣均亡羊。", "我懶心意衰，撫事多遺忘。", "念子方妙齡，壯圖宜自彊。", "至寶在高深，不憚勤梯航。", "茫茫定何求，所得安能常。", "萬物備吾身，求得舍即亡。", "鷄犬猶知尋，自棄良可傷。"]'),
('330e2b35-f518-4a5c-8aeb-a35f81132689','嚴陵釣臺','楊時','宋','宋诗','song-poetry','','[]','漢綱久陵遲，國柄授權室。',156,'全唐诗/poet.song.63000.json','["漢綱久陵遲，國柄授權室。", "中興得英主，威明戒前失。", "三公經邦手，吏事困精覈。", "功臣欲圖全，猶不任以職。", "矧茲故人分，義等天倫戚。", "卓哉子陵心，秉哲固前識。", "投身豢名爵，豈得枉尋尺。", "萬鍾雖云富，樊雉非予匹。", "石瀨清且泚，蒼崖聳而直。", "投竿事幽尋，釣水鮮可食。", "羊裘御冬溫，衮繡未云益。", "三旌屠羊肆，義在不吾易。", "用舍各有趣，高風亙今昔。"]'),
('c7ffaa02-7295-499c-af1e-82d21793a5a7','冬至日聞雷','楊時','宋','宋诗','song-poetry','','[]','土圭日已南，百年生有期。',84,'全唐诗/poet.song.63000.json','["土圭日已南，百年生有期。", "新陽潜地脈，慘慘羣陰微。", "尚覺雲氣昏，嚴飈弄寒威。", "狂雷與驟雨，奔逐如喧鼙。", "百蟲誤驚蟄，生理亦已虧。", "向晚怒聲息，霰雪交餘輝。", "凌寒山驛孤，持盃空自疑。"]'),
('e2bbf718-3398-44e8-b46e-0ff16793db2f','土屋','楊時','宋','宋诗','song-poetry','','[]','土屋枕荒陂，周回僅容席。',108,'全唐诗/poet.song.63000.json','["土屋枕荒陂，周回僅容席。", "環堵異營窟，猶遺古風質。", "功雖勞版築，身自有餘力。", "依戶鑿圓竇，寒光度如璧。", "戶開迎溫風，冬墐可棲息。", "胡爲棟宇麗，但免風雨阨。", "安居自寬暇，見者徒逼仄。", "寄言鄰舍翁，各自適汝適。", "慎勿慕華屋，澆漓非至德。"]'),
('c1b5e24d-2e0b-49a0-863c-d388be98e336','久不得家書','楊時','宋','宋诗','song-poetry','','[]','鴥彼晨風飛，日暮歸鬰林。',120,'全唐诗/poet.song.63000.json','["鴥彼晨風飛，日暮歸鬰林。", "游子尚何得，但寄千里心。", "庭闈斑白親，憶念我亦深。", "云何彼無耗，徒役夢寐尋。", "有如在空谷，歲久想足音。", "竹篇一行書，貴可抵萬金。", "踟躕步前庭，復坐口欲瘖。", "淚墮不自知，便覺盈衣襟。", "人生本無待，豈受外物侵。", "歸當卧牛衣，竹籜橫荆簪。"]'),
('d5810bb5-3eb9-45b3-b25a-561c6c45c87c','藏春峽 詠歸堂','楊時','宋','宋诗','song-poetry','','[]','結廬東山阿，屹然俯全閩。',132,'全唐诗/poet.song.63000.json','["結廬東山阿，屹然俯全閩。", "下有黄龍淵，浮光抱層雲。", "彼美谷口翁，杖策來往頻。", "明月自爲友，顧影相爲鄰。", "擷芷佩芳蘭，不與麋鹿羣。", "虛堂發輝素，黄卷日相親。", "采薇芼晨羹，弋鳬侑清樽。", "曝日負巖竇，爲童浴溪濆。", "微吟曳雙屐，踏破青苔紋。", "歸與自樂只，此意將誰論。", "點狂聖所與，聊欲繼餘芬。"]'),
('f3e3fb2c-1970-4267-8c5d-961ecf27fb82','藏春峽 老圃亭','楊時','宋','宋诗','song-poetry','','[]','昔君居隠鱗，投竿拂珊瑚。',156,'全唐诗/poet.song.63000.json','["昔君居隠鱗，投竿拂珊瑚。", "今來寓谷口，結亭事春鋤。", "亭下十餘畦，蔚蔚富嘉蔬。", "野果銜朱蕤，蔓實垂青桴。", "籬根有蹲鴟，晨炊勝彫胡。", "豈惟充君腹，鄰里亦厭餘。", "疏泉動地脈，磽确成膏腴。", "諒彼漢陰人，假脩匪吾徒。", "避俗柴桑翁，不復嘆荒蕪。", "卷懷經綸手，治此一畝居。", "知子非隠淪，聊以寓壯圖。", "人生出處分，禮義安可踰。", "茲謀異樊須，甘事小人儒。"]'),
('c129529a-a0b8-4fd4-8098-49b708e8edf3','送虔守楚大夫','楊時','宋','宋诗','song-poetry','','[]','象緯辰心次，雄都水濁時。',264,'全唐诗/poet.song.63000.json','["象緯辰心次，雄都水濁時。", "經天浮瑞彩，絕代出英姿。", "厚德千金璧，虛懷萬頃陂。", "霜蹄來漢苑，雲翮上天池。", "籍籍才猷美，皇皇使節馳。", "飛書騰衆吻，橫穽寘通逵。", "剖竹章流遠，還車蜀道巇。", "秦庭徒被指，趙璧本無虧。", "黄霸初勤細，裴公可範規。", "惠流三郡俗，名掩四賢祠。", "大厦資梁棟，承祧頼鼎彝。", "會須紆衮繡，寧久駐旌麾。", "畫航行空挽，甘棠去益思。", "烟波迎棹急，江柳拂牆低。", "賤士行藏拙，參軍秩序卑。", "生涯惟蠹簡，事業付毛錐。", "懶惰文園病，伶仃曼倩饑。", "自甘同跛鼈，未忍舍靈龜。", "朽質難雕繪，餘生辱品題。", "寒荄回暖律，陰壑得晴曦。", "終愧麞頭賤，難酬國士知。", "兩行淵客淚，感激自沾頤。"]'),
('255e0b70-37ff-4980-85f7-3d3c8fe421af','縣齋書事寄張世賢','楊時','宋','宋诗','song-poetry','','[]','朝衙羣吏集，戢戢同隊魚。',108,'全唐诗/poet.song.63000.json','["朝衙羣吏集，戢戢同隊魚。", "暮衙羣吏散，翩翩若驚鳬。", "歸來坐虛室，開編對璠璵。", "啟戶闃無人，清風入吾廬。", "持盃邀明月，大嚼時與俱。", "跰躚步松陰，對影聊相娛。", "嗟予懶惰久，闊略與世疏。", "故人隔清湘，懷抱何由舒。", "爲問魯山翁，此意今何如。"]'),
('23b4227d-c313-49ca-90ad-7d872a39be1e','黄彥昭時思閣','楊時','宋','宋诗','song-poetry','','[]','孤丘鎖千岑，層閣跨雲起。',84,'全唐诗/poet.song.63000.json','["孤丘鎖千岑，層閣跨雲起。", "永懷霜露思，時未薦醪醴。", "欽宗貴收族，蟄蟄神亦喜。", "故令傲霜根，駢枝復連理。", "黄侯渥洼種，一躍不容擬。", "慶源如歸墟，萬壑自奔止。", "終見君子鄉，乃是鳴珂里。"]'),
('c3b4d2bf-862d-4cf3-b4a3-2d92ebc03860','江陵令張景常萬卷堂','楊時','宋','宋诗','song-poetry','','[]','民生結繩初，異宇本同體。',132,'全唐诗/poet.song.63000.json','["民生結繩初，異宇本同體。", "誰令四目翁，破肉作瘡痏。", "龍龜出河洛，茲理固天啟。", "張侯瑚璉姿，高步軼前軌。", "買書費千金，充屋未云已。", "六經滀溟渤，百家雜原委。", "中流湧千波，舉體惟一水。", "參前有真趣，萬古一憑几。", "毫端吐奇芬，溢目麗紈綺。", "微言窺聖域，妙應期得髓。", "默坐筌蹄忘，斯文亦糠粃。"]'),
('d34ea89b-185c-4ab7-ae1b-8fd589abe3b0','送蔡安禮','楊時','宋','宋诗','song-poetry','','[]','眷言與君違，寤寐念往昔。',132,'全唐诗/poet.song.63000.json','["眷言與君違，寤寐念往昔。", "結歡自童稚，分比膠投漆。", "乖離成參商，出沒俱齊汨。", "羲和鞭日御，過眼飛鳥疾。", "五載一相逢，俯仰如昨日。", "論情方繾綣，念子又何適。", "行矣不可留，惝恍心若失。", "人生惟所遇，行止或使尼。", "况復各宦遊，聚散何可一。", "嚶嚶黄鳥聲，上下求其匹。", "俛首聽遺音，飄零淚橫臆。"]'),
('510f04b0-fd29-495a-bb83-ace08899b33e','題愚齋','楊時','宋','宋诗','song-poetry','','[]','結廬依林丘，回峰爭盤紆。',180,'全唐诗/poet.song.63000.json','["結廬依林丘，回峰爭盤紆。", "下闞清池淵，憑軒數游魚。", "飛閣出雲表，浮烟襲簪裾。", "中有傲世士，脫略自謂愚。", "高義輕籯金，貽謀有詩書。", "青編富充宇，散秩羅瓊琚。", "鱗鱗壁間題，一一露珊瑚。", "嗟予久昏塞，荒蹊少耘鋤。", "昌黎已隔世，將焉問夷塗。", "道逢北山公，荷鍤時與俱。", "皎皎河曲叟，朋儕共欷歔。", "高齋一來遊，豁然心神舒。", "籬東有餘址，誰能薙榛蕪。", "結茅可容席，一瓢來此居。", "寄謝陶彭澤，何必愛吾廬。"]'),
('beb27d3a-4339-427c-b8f6-b233771fb783','童氏必大亭','楊時','宋','宋诗','song-poetry','','[]','迢遥武夷翁，霞衣爛朝日。',120,'全唐诗/poet.song.63000.json','["迢遥武夷翁，霞衣爛朝日。", "作亭依雲根，曠望茲焉息。", "仙游去不返，孤丘已陳迹。", "身雖隸編齊，貽謀有遺則。", "慶流終必大，名亭以爲識。", "伊昔晉公堂，三槐手親植。", "扶疏滿庭陰，貂蟬映圭璧。", "默視天人際，召應齊呂律。", "閭門容軒車，茲理固可必。", "終見童氏里，鳴珂聲赫奕。"]'),
('ba590c8d-b33a-49c5-87d7-21063da2d7c1','江上晚步','楊時','宋','宋诗','song-poetry','','[]','鏡潭磨青空，璧月侵江淥。',84,'全唐诗/poet.song.63000.json','["鏡潭磨青空，璧月侵江淥。", "攬衣弄清泚，烱烱月在掬。", "泠然適我口，肝膈貯冰玉。", "流光頃百變，一玩不可復。", "歸來盡餘樽，醉卧媚幽獨。", "羲娥偶相憐，歲往如破竹。", "餘生枕中付，勿問黄粱熟。"]'),
('404a5dcc-5e4e-4163-83ec-ba7afb3de8d2','荆州偶作','楊時','宋','宋诗','song-poetry','','[]','鄭公嵇阮流，野性本麋鹿。',180,'全唐诗/poet.song.63000.json','["鄭公嵇阮流，野性本麋鹿。", "平生傲羲皇，白首就羈束。", "大寒客無氈，官冷飯不足。", "顧予支離人，攘臂受餘粟。", "江魚尾盈尺，飽食勝粱肉。", "荆山富樵蘇，丈室有餘燠。", "頑疏愧前哲，所得踰往躅。", "談經追時好，俯仰負愧忸。", "流光逝不反，愁鬢日改綠。", "世道劫火燃，不燔乃良玉。", "晚交定難恃，雲雨手翻覆。", "官居真蘧廬，束擔聊託宿。", "求田意雖鄙，此計正宜速。", "歸尋谷口耕，勝賣成都卜。", "坐想带經鋤，倚耒聽布穀。"]'),
('1e3c2eb2-978a-4289-9a2c-107abf5247f5','送鄭季常赴大學正','楊時','宋','宋诗','song-poetry','','[]','驅車出西城，眷言與君違。',84,'全唐诗/poet.song.63000.json','["驅車出西城，眷言與君違。", "北顧臨康衢，問子將焉之。", "赤驥度渥洼，終當飲瑶池。", "成都九軌道，一躍不可追。", "浮塵暗荆棘，捷徑行多迷。", "長風戰秋林，零露沾人衣。", "青松不改柯，期子清霜時。"]'),
('b128164e-bc2a-4ba4-a822-48b03e5231ff','次韵何吉老遊金鑾寺','楊時','宋','宋诗','song-poetry','','[]','榮名嗟何爲，病木自生癭。',288,'全唐诗/poet.song.63000.json','["榮名嗟何爲，病木自生癭。", "彭殤一夢覺，烏用論久頃。", "寄身淵明廬，翛然在人境。", "衛生鄙樊雉，放浪任流梗。", "相忘到形影，世累不須屏。", "剉鍼聊自營，寧復事干請。", "負暄有餘燠，蓬鬢亂垂頸。", "客來坐無氈，誰顧廣文冷。", "忽聞過吾門，冠屨不暇整。", "邀我招提游，並轡相與騁。", "僧關叩禪寂，未語心已領。", "並游皆韓徒，辭刃淬鋒穎。", "多聞富如坻，吾方拾遺秉。", "顧慚管窺陋，未睹豹文炳。", "謬追俊游後，如渴得甘井。", "願從借金篦，爲割眼中眚。", "鼻端堊墁久，妙質愧非郢。", "賡酬困詩律，恐坐杜陵㾪。", "相携上層崗，出戶畏深穽。", "每虞參也魯，跬步輒三省。", "遲回月初上，雲間掛金餠。", "昏鴉鳴相呼，更覺林逾靜。", "湖光湛星漢，渺渺天水永。", "歸蹊暗塵土，回首失清景。"]'),
('6fff3c69-388b-4ddd-9175-d3bc3922e7f6','送趙循道赴都講','楊時','宋','宋诗','song-poetry','','[]','鳳山鬰崔嵬，下有千頃陂。',132,'全唐诗/poet.song.63000.json','["鳳山鬰崔嵬，下有千頃陂。", "峻極不可攀，浮光亙長鬐。", "晦冥滴風雨，澄淡含瓌奇。", "吸呼入君懷，萬態羅心脾。", "吐辭麗金雘，煥若星斗垂。", "朅來荆渚游，紅蕖照清漪。", "故宮久零落，一洒增余輝。", "惇族貴老成，堯言下丹墀。", "浮驂駕雲帆，眷然成仳離。", "長裾曳王門，豈比困鹽虀。", "驊騮踏長坂，萬里誰能羈。"]'),
('1707fdbb-b00f-488e-9cc4-f6541de50961','送胡康侯使湖南','楊時','宋','宋诗','song-poetry','','[]','北溟有潜鱗，其廣數千里。',144,'全唐诗/poet.song.63000.json','["北溟有潜鱗，其廣數千里。", "揚鬐厲東海，汎汎等蜉蟻。", "百川競奔注，漫不見涯涘。", "寄之天地間，大澤礨空耳。", "胡侯荆山資，妙質久礱砥。", "飛聲動旒冕，持節照湘水。", "功名與時會，事道從此始。", "驊騮駕輕車，夷路道九軌。", "朝燕暮騰越，快意未爲喜。", "聖門學須彊，一簣虧可耻。", "擴之天地寬，於道乃云邇。", "爲士貴弘毅，無忘味斯旨。"]'),
('72d40e75-58e4-4888-b0e2-cdd7cbb9f47a','寄題趙貫道後樂亭','楊時','宋','宋诗','song-poetry','','[]','叢祠有狐鳴，羣雛滿東州。',228,'全唐诗/poet.song.63000.json','["叢祠有狐鳴，羣雛滿東州。", "彬彬齊魯郊，不復論軻丘。", "鼓刀販繒翁，衮衮封公侯。", "風流日凋弊，世久俗益偷。", "昔時戴經人，輟耕仍佩牛。", "椎埋晝行盜，閭里更相讎。", "趙子尉平陽，始止惟民憂。", "百花爛成圍，幽禽哢春柔。", "問子胡不樂，我心殊未休。", "威明揉彊梗，驕鷹化爲鳩。", "買犢解吳鈎，束身自鋤耰。", "田廬戶無樞，長物棄不收。", "結亭自樂只，開編玩前修。", "誰云酸寒吏，憂樂非身謀。", "乃知君子懷，與世異沉浮。", "嗟予一漫叟，放浪猶虛舟。", "舞雩有清風，遺迹今在不。", "君乎去此矣，欲往將誰儔。", "寄言春服成，尚覬一來游。"]'),
('49c73f71-089a-490a-a8f9-ff345a90a985','謝詹司業送酒','楊時','宋','宋诗','song-poetry','','[]','鄭公負才名，流落四十年。',168,'全唐诗/poet.song.63000.json','["鄭公負才名，流落四十年。", "高視隘八荒，天寒坐無氈。", "忘形頼司業，時與送酒錢。", "嗟予樗櫟材，臃腫世所捐。", "云何附青雲，拜賜追前賢。", "開壺對青樽，內愧顔靦然。", "公乎廊廟姿，直幹上參天。", "袨服羣娃宮，不虞姑爭妍。", "驊騮誤一蹶，萬里終騰騫。", "朝燕暮刷越，駑馬安能先。", "玉瑩本無瑕，寧須事磨鎸。", "宣室久虛席，茲行定詳延。", "陋儒氣填臆，感慨聊自宣。", "辱惠不知報，强歌成短篇。"]'),
('5f4eed22-6c28-41cb-b153-c79001bd9bab','戲贈詹安世','楊時','宋','宋诗','song-poetry','','[]','綵舟駐閶門，初與子相識。',168,'全唐诗/poet.song.63000.json','["綵舟駐閶門，初與子相識。", "長空翥秋隼，爽氣橫八極。", "摛辭鏤圭璋，吐論森劍戟。", "鄧侯不願仕，志在書竹帛。", "長纓係單于，落落藴奇策。", "氣吞流沙外，意無燕然北。", "虎牙有餘勇，戎虜非彊敵。", "會當朔風勁，仗鉞控鳴鏑。", "老夫慚衰謝，見子徒感激。", "平生謬經綸，此意已寥寂。", "信哉功名會，事道古難必。", "窮通付時命，未足爲悅戚。", "餘生如鼴鼠，滿腹微分畢。", "行矣脫簪纓，翛然適吾適。"]'),
('cf2e3ac1-81b1-4ba5-82e7-3954841ee544','隠几','楊時','宋','宋诗','song-poetry','','[]','上天不殞霜，萬木正鮮澤。',72,'全唐诗/poet.song.63000.json','["上天不殞霜，萬木正鮮澤。", "青蒿與長松，各挺歲寒節。", "朔風吹沙寒，高嶺凍積雪。", "萬木已摧落，長松獨清潔。", "人生無艱危，君子竟何別。", "隠几試澄思，行藏易差轍。"]'),
('3bf42152-5e97-4c76-bfc4-9ecb750a0f9a','留別富宣德','楊時','宋','宋诗','song-poetry','','[]','富侯荆山姿，落落混燕石。',96,'全唐诗/poet.song.63000.json','["富侯荆山姿，落落混燕石。", "鎸磨經世故，不磷乃天質。", "軒裳儻來寄，既去寧須戚。", "驊騮走長坂，一跌未爲失。", "秦庭謬瑕疵，睨柱終完璧。", "君子有遠懷，事道先器識。", "千鈞等鴻毛，始見烏獲力。", "行矣各勉旃，他時頼三益。"]'),
('c6c27adf-58d6-4e39-8a76-553330703f9a','別西齋諸友','楊時','宋','宋诗','song-poetry','','[]','浮雲如積酥，凉飈勁弦疾。',60,'全唐诗/poet.song.63000.json','["浮雲如積酥，凉飈勁弦疾。", "溶溶渺天末，飄忽易相失。", "懸弧四方志，匏繫非予匹。", "平生結歡久，始願膠投漆。", "別離傷素懷，此身任萍迹。"]'),
('f85c06ef-acad-424c-aaca-c865c1a48d4b','遣懷','楊時','宋','宋诗','song-poetry','','[]','君子雖自嚴，至潔宜若汙。',60,'全唐诗/poet.song.63000.json','["君子雖自嚴，至潔宜若汙。", "昭昭揭日月，所向將蝟如。", "天地一穽中，逼仄身亦孤。", "游世在虛己，浩蕩與時俱。", "靈府有天游，環中真道樞。"]'),
('b41b62f6-3f38-4379-b5f6-d3fe615fdf49','元豐壬戌歲暮書事','楊時','宋','宋诗','song-poetry','','[]','閩陬地力盡，種藝被山谷。',132,'全唐诗/poet.song.63000.json','["閩陬地力盡，種藝被山谷。", "涵濡一雨潤，鬰鬰原野綠。", "春風忽云徂，舒景變炎燠。", "凉飈動地軸，揫斂何神速。", "坐愁林巒空，俯視萬木禿。", "凝霜借風力，摧折到松竹。", "嗟予閉門人，感此亦愁蹙。", "幽庭有萱草，采采不盈掬。", "如聞糟床注，取醉須百斛。", "沉酣樂時運，天關不須觸。", "萬物一芻狗，蒼蒼自高目。"]'),
('be7b20de-7acb-40f9-85b7-df525f744d1f','綠漪軒','楊時','宋','宋诗','song-poetry','','[]','開池傍清軒，環除種蘭芷。',60,'全唐诗/poet.song.63000.json','["開池傍清軒，環除種蘭芷。", "虛明淡星漢，疏影薦鳬履。", "君乎試憑軒，鑑此亭下水。", "盪風生微瀾，風定還泚泚。", "悠然得真趣，吉祥來止止。"]'),
('c9a82ef3-dbd8-4843-a53e-89679305a290','迂疏堂','楊時','宋','宋诗','song-poetry','','[]','終南有捷徑，屈蠖終當伸。',60,'全唐诗/poet.song.63000.json','["終南有捷徑，屈蠖終當伸。", "君獨耻不蹈，安得與世親。", "結廬寄人寰，獨往寧問津。", "形影廢酬贈，相忘誰與鄰。", "寄謝漢陰叟，抱甕良非真。"]'),
('60429427-3209-4e4d-a418-7d1bfebcd988','鄱陽湖觀打魚','楊時','宋','宋诗','song-poetry','','[]','秋高水初落，鱗介滿沙脊。',132,'全唐诗/poet.song.63000.json','["秋高水初落，鱗介滿沙脊。", "浩如太倉粟，寧復數以粒。", "紛紛漁舟子，疑若俛可拾。", "橫湖沉密網，脫漏百無十。", "蟲蝦雜魴鯉，駢首吐微濕。", "小人利口實，刀机汙鱗鬣。", "鯤鯨亦狼狽，風雨移窟宅。", "玉淵有神祠，變化在噓吸。", "胡寧飽羶香，忍視萬魚急。", "幽潜不足恃，感嘆百憂集。", "寄謝漆園吏，於計未爲得。"]'),
('39a72881-72d6-457c-a760-f012101d4d52','送嚴尉','楊時','宋','宋诗','song-poetry','','[]','世路久艱棘，青冥翳妖氛。',60,'全唐诗/poet.song.63000.json','["世路久艱棘，青冥翳妖氛。", "孤鳥叢祠中，豺虎填城闉。", "君能摘姦伏，竭澤無潜鱗。", "勿云功未酬，屈蠖終當伸。", "飛黄駕輕車，一躍窮無垠。"]'),
('7497107a-c169-4036-8c4d-ed1289bb694c','檢田','楊時','宋','宋诗','song-poetry','','[]','尋崙上層崗，隨衝出高原。',72,'全唐诗/poet.song.63000.json','["尋崙上層崗，隨衝出高原。", "烟火一里餘，雞犬遥相聞。", "瘠壤僅容席，訟牒徒紛綸。", "齊魏兩蝸角，况復三家村。", "舉世競豪末，薄俗寧足論。", "吾衰過元亮，欲辨已忘言。"]'),
('e43d7cbe-0617-4a8a-a004-7065378fb587','送向和卿還京','楊時','宋','宋诗','song-poetry','','[]','江湖多秋風，惝恍夜不眠。',132,'全唐诗/poet.song.63000.json','["江湖多秋風，惝恍夜不眠。", "念子將北歸，起視明星懸。", "君平翠虯姿，聳身蒼梧淵。", "高步隘八區，凌風上青天。", "妙質藴荆璞，寧須事磨鎸。", "贈言以爲別，妄意追前賢。", "聖言乃常珍，含咀真味全。", "奇辭暫時好，過眼如飛烟。", "潔身忌廉潔，觸物冥虛船。", "吾方病羸苶，市藥還自憐。", "明日隔長陂，相望空惘然。"]'),
('5de9e289-9657-46d6-bc6d-b07f2c490e81','酬林志寧','楊時','宋','宋诗','song-poetry','','[]','君不見昔時卜年公，坼龜食墨瀍澗東。',273,'全唐诗/poet.song.63000.json','["君不見昔時卜年公，坼龜食墨瀍澗東。", "伊流洛水環紫宮，廣輪千里天地中。", "真人一往不復見，鼎湖弓劍空遺蹤。", "陰陽所交風雨會，和氣自古生英雄。", "邇來百千歲，零落多奇窮。", "鳴皋少室崢嶸倚天闕，下有回淵萬仞蟠雙龍，蒸雲結雨氣濛濛。", "惟有蒼髯紫頷包玄珠，時發光燄凌烟虹。", "成周太平鬰餘策，但令洙泗生清風。", "羨君妙齡有仙骨，乘槎暗與天潢通。", "萬里不一息，去若孤征鴻。", "决開銀河浪，分出一派懸秋空。", "顧予山野姿，未老心已慵。", "謬從君子游，營道術偶同。", "有如退之與東野，自慚青蒿倚長松。", "感君惠然抵山谷，開談冰雪清吾胸。", "高堂黑髮顔如童，未須念此心忡忡。", "幸有山前清泉冷可酌，與君啜甘茹草忘春冬。"]'),
('4597cba0-e07c-4ef8-9a2b-8d2e1b748232','題贈吳國華釣臺','楊時','宋','宋诗','song-poetry','','[]','君不見釣璜溪上白髮翁，一竿西去追冥鴻。',214,'全唐诗/poet.song.63000.json','["君不見釣璜溪上白髮翁，一竿西去追冥鴻。", "田車同載非羆熊，鷹揚烈飛如飄風。", "又不見羊裘石瀨垂綸叟，爽槩凌天動星斗。", "萬乘故人親訪求，卧對鑾輿忍回首。", "聖賢遇合自有時，潔身亂倫非所知。", "高風寥寥古已往，較然得失知者誰。", "君有釣臺臨橘水，橘溪不與桐溪比。", "收身欲攝渭老蹤，笑撫長髯照清泚。", "澄潭夜月秋光浮，撇波短艇沿汀洲。", "長繩巨石不能繫，飛帆片席歸蓬丘。", "巨鈎沉餌牽九牛，一釣直掣金鰲頭。", "脩鱗擺鬣浪山起，雲鵬飛翻忽千里。", "跨雲憑翼上青冥，一點孤光厠箕尾。"]'),
('ce473598-6d53-490a-a69e-c790d463b44e','贈別蔡武子被誣得釋赴泉州錄參','楊時','宋','宋诗','song-poetry','','[]','君不見馬伏波，後車薏苡珠璣多。',170,'全唐诗/poet.song.63000.json','["君不見馬伏波，後車薏苡珠璣多。", "又不見章臺秦璧非有疵，相如謬使秦人疑。", "匡章不孝通國非，世無孟子知者誰。", "惜君高材兼衆美，完德從來速招毀。", "含沙怒欲陰中之，剛引涇流汙清泚。", "輕雲捲盡天日明，容光竅穴無潜形。", "刮磨玉瑩冰雪凝，楚人謾費塗丹青。", "齊庭有鳥久不鳴，會須一舉天衢亨。", "北溟欻起風雷驚，修鱗巨鬣隨波輕，不須回首顧潜鯨。", "好乘扶搖九萬里，奮迅六翮飛南溟。"]'),
('b73163a7-3fb7-4b6d-bbec-92099a591e86','入山行','楊時','宋','宋诗','song-poetry','','[]','蒼崖峭立青天涯，古徑蕪沒沿清溪。',66,'全唐诗/poet.song.63000.json','["蒼崖峭立青天涯，古徑蕪沒沿清溪。", "深林四合晝亦暝，寂寂惟有哀猿啼。", "野人心形灰死如槁木，山禽見之猶驚飛。", "因嗟太古不可復，我無機械胡相疑。"]'),
('6288e770-4a76-4048-89fc-06114ca5268b','假山','楊時','宋','宋诗','song-poetry','','[]','衡湘側南二千里，清淑之氣常蜿蜒。',256,'全唐诗/poet.song.63000.json','["衡湘側南二千里，清淑之氣常蜿蜒。", "丹沙玉石氣所感，融結萬狀非磨鎸。", "窮源荒蹊異岱畎，不逢禹績輕棄捐。", "苔封土蝕誰復問，嶙峋僵卧當市廛。", "龜山老叟見之喜，鳩徒輦置羅前軒。", "岧嶢孤峰露仙掌，屹若太華青摩天。", "傾崖斷壑坐中見，葱蒨似玉生雲烟。", "初疑祖龍未死日，浮梁擬跨咸池淵。", "神號鬼怒驅不前，捶繫刓磷成枅圈。", "又疑巨人出龍伯，揭竿來自崑崙巔。", "連鼇合負雲濤翻，蓬壺簸蕩留平川。", "繄予竟日倚欄檻，矯首便欲追靈仙。", "尻輪神馬自足駕，已覺兩腋風泠然。", "瓊臺浮游與世隔，醉傲笑拊洪崖肩。", "山間草木即靈餌，含英茹實資長年。", "悠悠廣息變今古，坐看溟渤成桑田。"]'),
('111c3078-686c-458f-be60-6cfd3093145b','寄練子安教授','楊時','宋','宋诗','song-poetry','','[]','憶昨吾子客上都，我獨奔走天南隅。',298,'全唐诗/poet.song.63000.json','["憶昨吾子客上都，我獨奔走天南隅。", "各年未壯已多累，誤投世網身攣拘。", "飄零今日偶相值，乃復咫尺不得與子俱。", "人生委質金在爐，大冶鼓鑄誰號呼。", "惟愁踆踆走塵土，舊業已廢成荒蕪。", "惜君高才卓犖與世畸，雄文洒落珠陸離。", "雷驚電赫轉坤軸，風號浪擊飛天池。", "珊瑚挺幹滄海竭，麒麟超軼不可羈。", "經綸有道世莫知，櫝中良璧始自奇。", "君不見扶藜隘巷蓬蓽居，短褐甕牖桑爲樞。", "擁門軒蓋何所慕，藜羹自飽非癯如。", "又不見揚雄寂寞守太玄，棄捐覆瓿真可憐。", "折腰小吏昔所恥，田園須賦歸來篇。", "終當結屋蒼崖巔，期子相與臨清泉。", "投簪解带謝人世，拂塵披蠹親遺編。", "松皴檜老生青烟，雨餘風弄鳴哀弦。", "低回野興有真意，浮名鸛雀過吾前。", "結歡膠漆常連連，從游鹿豕終長年。"]'),
('b09b7944-eb8e-40a5-9a86-6bdd36a23853','送富朝奉還闕','楊時','宋','宋诗','song-poetry','','[]','君不見慶曆承平道如砥，馳車八荒同一軌。',198,'全唐诗/poet.song.63000.json','["君不見慶曆承平道如砥，馳車八荒同一軌。", "虜人鴟張怒螳臂，百萬雲屯若封豕。", "又不見朔方橫流漲天起，腐麥蛾飛木生耳。", "扶携道路雜老幼，操瓢溝中半爲鬼。", "關河日夜刁斗驚，嫚書乘駟來渝平。", "兵間持節得英傑，談笑坐使羈長纓。", "青社環城萬區屋，發廩分曹具饘粥。", "饑羸枯頰陡生光，叢塚不聞新鬼哭。", "臧孫有後天匪親，閭門容車何足論。", "朅來濉上見猶子，雄姿宛有典型存。", "驊騮已渡渥洼水，朝燕暮越應千里。", "行看玉勒駕鑾輿，濯足瑶池從此始。"]'),
('aa6d22e3-02f4-491a-949a-3997e3fc94c1','南康值雨','楊時','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','平沙漲雪清江濆，水花照日紅生鱗。',176,'全唐诗/poet.song.63000.json','["平沙漲雪清江濆，水花照日紅生鱗。", "軒然五老出城表，雕玉萬仞窺長身。", "雲巾星弁覆華頂，飛泉漱瀑垂天紳。", "平生未識廬山面，碧巘橫雲望中見。", "江頭一夜雨銜天，奔浪號風作悲健。", "朝來淤泥沒牛馬，咫尺坐論千里遠。", "芒鞋拄杖掛塵屋，神馬尻輪欻飛轉。", "卧龍菴前碧眼翁，日飲山淥餐溪松。", "神融氣合八荒外，此心烱烱宜先通。", "未須勒移却俗駕，會應一洗塵寰空。", "寄言歸侍壺丘子，他日來游當御風。"]'),
('44431ab9-cba1-463f-9746-b567cd0d76e3','遊武夷','楊時','宋','宋诗','song-poetry','','[]','函關崎嶔走秦鹿，天下並逐爭羣雄。',224,'全唐诗/poet.song.63000.json','["函關崎嶔走秦鹿，天下並逐爭羣雄。", "抉雲翻空鰲足折，黔黎竄伏如寒蛩。", "武夷山深水清泚，避世猶有高人蹤。", "龍泓東注海波涌，玉女翠擁秋雲鬆。", "赤霄真骨寫虛壁，通泉凡筆慚非工。", "藏舟浮梁跨絕壑，隠見似與天潢通。", "當時雞犬不復見，窠巖依舊烟霞籠。", "我來秋杪月既望，尚有幽菊埋榛叢。", "天容洗浄雨新霽，雲幕四卷清無風。", "掀篷進棹窮異境，注目想見流殘紅。", "回船杖屨躡幽徑，松竹窈窕環琳宮。", "翠琬溫辭耀華衮，金榜大字纏交龍。", "自憐病骨掛塵網，幔亭高會何由逢。", "解衣歸卧玉瑣碎，仰看明月穿疏篷。"]'),
('ff09b3df-8152-4e5f-85ec-cadb168cf1bf','向和卿覽余詩見贈次韵奉酬','楊時','宋','宋诗','song-poetry','','[]','杜陵頭白長昏昏，海圖舊繡冬不溫。',128,'全唐诗/poet.song.63000.json','["杜陵頭白長昏昏，海圖舊繡冬不溫。", "更遭惡卧布衾裂，盡室受凍憂黎元。", "詩人窮愁自古爾，豈若種藝依青門。", "嗟予老懶世不用，窮巷久雨無高軒。", "蟲鳴鳥噪感時節，嫠不恤緯羞前言。", "殘章斷簡棄不錄，自愧潢潦無根源。", "君胡衮字富褒飾，三復妙語將誰論。", "知君獨負青雲器，欲使饑者名長存。"]'),
('8b5fe6f3-f34b-4b7e-ae70-6707d696592a','贈程舍人近侍入閩','楊時','宋','宋诗','song-poetry','','[]','路公溪上鶴髮翁，眼光照日顔如童。',96,'全唐诗/poet.song.63000.json','["路公溪上鶴髮翁，眼光照日顔如童。", "厖眉垂鬢有仙骨，駢集五福天所鍾。", "螭頭暫輟三長手，杖節扶輿入閩嶠。", "弧南一夜晶輝浮，海隅草木俱榮耀。", "朱金拜後古所稀，繡紱全勝衣綵衣。", "玉觴薦壽須珍奇，更待蟠桃結子時。"]'),
('4ba432de-b849-448d-86fa-f4921185d2ae','岳陽書事','楊時','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭水落洲渚出，疊翠疏峰遠烟沒。',192,'全唐诗/poet.song.63000.json','["洞庭水落洲渚出，疊翠疏峰遠烟沒。", "重樓百尺壓高城，畫棟沉沉倚天闕。", "湖光上下天水融，中以日月分西東。", "氣凌雲夢吞八九，欲與溟渤爭雌雄。", "澄瀾無風雨新霽，一日萬頃磨青銅。", "琉璃夜影貯星漢，騎鯨已在銀河中。", "湘妃帝子昔何許，但有林壑青浮空。", "蒼梧雲深不可見，遺恨千古嗟何窮。", "須臾晦冥各異色，風怒濤翻際天黑。", "乘陵瀨壑走魑魅，渟滀百怪誰能測。", "忽看舟子玩行險，更欲飛帆借風力。", "安得晴雲萬里開，依舊寒光浸虛碧。"]'),
('61592a29-46a1-42ea-9139-2ba1c2120ffd','遣興','楊時','宋','宋诗','song-poetry','','[]','嵩華千仞立，不礙天地寬。',40,'全唐诗/poet.song.63000.json','["嵩華千仞立，不礙天地寬。", "涇渭清濁流，不離海波瀾。", "人生過眼萬事役，記憶細故真童頑。"]'),
('39ed6ed0-2337-483b-931d-04649b4ed222','寄游定夫','楊時','宋','宋诗','song-poetry','','[]','憶昨相逢鳳山趾，駒隙駸駸餘半紀。',176,'全唐诗/poet.song.63000.json','["憶昨相逢鳳山趾，駒隙駸駸餘半紀。", "君趨烏府近清光，陸海驚濤漲天起。", "雲帆大舸半摧溺，艤岸得全誠偶爾。", "我時捧檄赴京渚，放浪江湖一浮蟻。", "談書考古老無用，哺啜糟醨咀糠粃。", "東歸雖復有民社，爲米折腰良可恥。", "市朝紛紛真羿彀，朔幹燕弧不容擬。", "投身中地竟誰免，未信棘端能捍矢。", "重樓百尺卧玄德，問舍求田不須鄙。", "早歲結鄰初有約，齒豁頭童今老矣。", "築田預想傍田廬，負耒耦耕何日始。"]'),
('505ed348-8f9a-402d-96e4-3aa4b8eacd27','過錢塘江迎潮','楊時','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','銀潢翻空際天白，鯤怒鵬鶱海波擊。',112,'全唐诗/poet.song.63000.json','["銀潢翻空際天白，鯤怒鵬鶱海波擊。", "湧雲噫氣聲怒號，萬馬馳車隨霹靂。", "低昂上下如桔槹，頃刻性命輕鴻毛。", "賫囊負笈有夷路，一日何事常千艘。", "因思羊腸盤九坂，攀援蜀道愁狖猱。", "人生觸處有萬險，豈必此地多風濤。", "願言夷險不須問，莫負對酒持霜螯。"]'),
('738f4c11-1ee4-4b7e-b2dd-32ed9aed7e56','觀獵','楊時','宋','宋诗','song-poetry','','[]','貂裘白馬誰家子，擁戟弦弧囊勁矢。',128,'全唐诗/poet.song.63000.json','["貂裘白馬誰家子，擁戟弦弧囊勁矢。", "褰身欲與鳥爭飛，觸處塵埃雲四起。", "長繩驅逐狐兔驚，驕鷹掣臂流雙睛。", "飛揚雲間電光閃，旋復草際無遺生。", "鷙腸久厭鮮肥餌，顧盼方能伺人意。", "但矜鼎俎有餘甘，貪餐誰憐殄生類。", "安得淑氣回嚴秋，徐令困拙同鳴鳩。", "林間百鳥恣孳乳，雖欲擊搏知無由。"]'),
('c62a43e9-7ab5-4915-a4c9-d738992601d7','寄范正甫','楊時','宋','宋诗','song-poetry','','[]','羈窮莫厭如牢圈，從古功名出屠販。',147,'全唐诗/poet.song.63000.json','["羈窮莫厭如牢圈，從古功名出屠販。", "男兒不負懸弧心，馬革裹尸猶足願。", "君不見淮陰寄食饑貧叟，胯下英風亦何有。", "逢時吐氣雷電奔，金印纍纍大如斗。", "玉門晝夜羽檄驚，睥睨欲塹天都城。", "叩關虎士鬰餘怒，科頭奮戟如鵰鷹。", "君從壯年藴奇策，未宜縮首藏柴荆。", "昔人投筆真豪英，慨然萬里終成名。", "南山白額雖欲老，百獸遭之猶裂腦。"]'),
('84c76eec-6805-4f07-8947-b65b8c04d047','吳子正招飲時權酒局不赴作詩戲之','楊時','宋','宋诗','song-poetry','','[]','寒爐火冷浮青烟，勁風刮面如戈鋋。',128,'全唐诗/poet.song.63000.json','["寒爐火冷浮青烟，勁風刮面如戈鋋。", "凝陰不動天欲雪，竟日兀兀成拘攣。", "廣文才名四十年，天寒坐客猶無氈。", "參軍官小技能薄，寂寞冷坐誠宜然。", "忘形杜老偶相覓，傳呼歌舞開華筵。", "嗟予簡書固可畏，不得對飲簷花前。", "謾有糟漿逆人鼻，汝陽口角空流涎。", "可能更似蘇司業，只與時時送酒錢。"]'),
('27a01cbb-de3a-435c-a317-7ca2e6304176','寄題環翠樓','楊時','宋','宋诗','song-poetry','','[]','方壺七萬神鼇連，瓊臺縹緲居靈仙。',224,'全唐诗/poet.song.63000.json','["方壺七萬神鼇連，瓊臺縹緲居靈仙。", "鯨翻海運成桑田，異境誰使夸娥遷。", "銛鋒四面蒼圭圓，巨靈巧以青瑶鎸。", "揉風洗雨凈娟娟，修眉浮空秀爭妍。", "清溪回旋瀉幽泉，下有澄瀾湛洄淵。", "繡楣雕欄欲飛翻，凌切漢道摩星躔。", "恍如直跨須彌巔，琉璃凝光圍四天。", "喜君妙齡謝世喧，萱堂慈顔白盈顛。", "兒童牽衣戲蹁躚，優哉此樂誰與先。", "嗟予昔以三釜懸，投身世網百慮煎。", "今乎老矣誠可憐，狙猿何用簪纓纏。", "子雲終須守一廛，誅茅結屋纔數椽。", "薜衣雜佩紉蘭荃，手披白蟫玩青編。", "春暉不報常欿然，雖有至樂安能全。"]'),
('06b81083-00b0-4628-9034-7265ccf519d6','晚雨','楊時','宋','宋诗','song-poetry','','[]','斷霞明滅天日黝，雨意晴暉爭好醜。',98,'全唐诗/poet.song.63000.json','["斷霞明滅天日黝，雨意晴暉爭好醜。", "浮雲冉冉無定姿，白衣忽變如蒼狗。", "悲風激烈河漢翻，雨脚如麻飛霰寒。", "山深氣腥豺虎亂，乾坤四合誰云寬。", "將溪溪上野客懶成癖，怯寒手攣面如墨。", "把盃强吞僵立歌，閉門獨愁天已黑。"]'),
('df374cb8-e764-4d30-91a3-aa6498b8384a','贈醫者鄧獻匡','楊時','宋','宋诗','song-poetry','','[]','天地一氣猶冶甄，埏埴萬彙隨方圓。',160,'全唐诗/poet.song.63000.json','["天地一氣猶冶甄，埏埴萬彙隨方圓。", "神形九藏通九野，八風中物如戈鋋。", "天元玉冊有遺義，探索始自三皇前。", "桑君越人不世出，鑱石鍼灸誰能傳。", "賤工增餘損不足，往往橫夭殘天年。", "羨君妙齡踵其學，至理隠賾常精研。", "聞陰得陽以神遇，反視方術猶蹄筌。", "道隅併虀即爲餌，車上已有長蛇懸。", "嗟予羸苶苦多病，維摩丈室方蕭然。", "願君速已天下疾，爲予一洗沉痾痊。"]'),
('081b0bd5-0433-46c3-b790-4149998abd5e','與將樂令會飲揖仙亭','楊時','宋','宋诗','song-poetry','','[]','灘流斗落惟璠璵，雕欄照水光如濡。',128,'全唐诗/poet.song.63000.json','["灘流斗落惟璠璵，雕欄照水光如濡。", "層巒疊巘爭蟠紆，翠岩百尺蹲於菟。", "何年巨人出歸墟，揭竿合負神鰲趨。", "飄流人間峙蓬壺，至今猶爲仙聖居。", "飛軿往來誰與俱，下有馴雉隨雙鳬。", "英風爽氣凌清虛，楣間新詩露珊瑚。", "顧余老懶與世疏，欲往勾漏嗟無徒。", "會須策轡追雲車，無使吃口嗤癯儒。"]'),
('392c2734-4387-4f89-96d0-be5209138520','離家作二首  其一','楊時','宋','宋诗','song-poetry','','[]','敗葉辭故枝，驚飈送微雨。',48,'全唐诗/poet.song.63000.json','["敗葉辭故枝，驚飈送微雨。", "田廬向收穫，城中亟完補。", "游子欲何之，道路修且阻。", "俛首謝田父，予生厭羈旅。"]'),
('e399b49f-5970-453d-92e8-c35155e07158','離家作二首  其二','楊時','宋','宋诗','song-poetry','','[]','胡雁依朔風，羣飛逐南翔。',48,'全唐诗/poet.song.63000.json','["胡雁依朔風，羣飛逐南翔。", "游子方北征，朔風吹我裳。", "攬轡望雲間，夜色正蒼蒼。", "空羨南歸翼，幽懷增感傷。"]'),
('e1ae7c9a-c8db-434f-9dbf-17c9968995b7','過漢江','楊時','宋','宋诗','song-poetry','','[]','西極鰲足折，東南地維傾。',48,'全唐诗/poet.song.63000.json','["西極鰲足折，東南地維傾。", "衆流競趨下，洶洶歸滄溟。", "誰能跨明河，挽此經天行。", "世難乘槎翁，此意終冥冥。"]'),
('020efad7-20cb-43b9-8fb4-0f5a2769d759','新湖夜行','楊時','宋','宋诗','song-poetry','','[]','平湖浄無瀾，天容水中煥。',48,'全唐诗/poet.song.63000.json','["平湖浄無瀾，天容水中煥。", "浮舟跨雲行，冉冉躐星漢。", "烟昏山光淡，桅動林鴉散。", "夜深宿荒陂，獨與雁爲伴。"]'),
('cd7d6151-3f4b-4a0c-87ea-cb900237bcc3','哀鴻','楊時','宋','宋诗','song-poetry','','[]','哀鴻常苦饑，悲鳴垂其翼。',48,'全唐诗/poet.song.63000.json','["哀鴻常苦饑，悲鳴垂其翼。", "朔漠曉霜寒，江湖晚烟羃。", "乾坤一網罟，高飛亦何益。", "日暮無與羣，驚風暗沙磧。"]'),
('0f01e4a3-8386-4084-b96e-f720dfb6563f','枕上','楊時','宋','宋诗','song-poetry','','[]','小智好自私，小德常自足。',48,'全唐诗/poet.song.63000.json','["小智好自私，小德常自足。", "自私開人賊，自足心有目。", "瑕瑜不相掩，君子比良玉。", "默默枕上思，戒之在深篤。"]'),
('91252b99-5aab-476c-88b9-77f036c7d349','別游定夫','楊時','宋','宋诗','song-poetry','','[]','黽勉吾將仕，謀身力已分。',48,'全唐诗/poet.song.63000.json','["黽勉吾將仕，謀身力已分。", "漆雕慚未信，子夏又離羣。", "慘淡交情重，間關道路勤。", "至言宜遠寄，孤陋願頻聞。"]'),
('6e2b0a32-d231-4e78-8f4b-49458f060bcb','過金山','楊時','宋','宋诗','song-poetry','','[]','環望荆吳坼，清江日夜流。',48,'全唐诗/poet.song.63000.json','["環望荆吳坼，清江日夜流。", "飛騰潮汐浪，漂泊利名舟。", "山湧鰲番出，樓噓蜃氣浮。", "僧窗千古意，出沒看輕漚。"]'),
('7de5e4cf-b50a-4b16-aec4-32b0c5fea68b','冬曉','楊時','宋','宋诗','song-poetry','','[]','著瓦霜華冷，暝空曉霧均。',48,'全唐诗/poet.song.63000.json','["著瓦霜華冷，暝空曉霧均。", "氣昏難見日，風過易生塵。", "洗硯冰紋破，憑鑪火色春。", "莫嫌寒尚薄，雨雪更愁人。"]'),
('aca02d03-47a2-482c-a2aa-9faa9b4bedec','雨寒','楊時','宋','宋诗','song-poetry','','[]','天幕陰雲積，蕭蕭雨正霪。',48,'全唐诗/poet.song.63000.json','["天幕陰雲積，蕭蕭雨正霪。", "泥污關市寂，水入御溝深。", "破屋寒侵骨，哀弦凍絕音。", "更愁風力健，瘦怯不能禁。"]'),
('b0ac963e-87a3-45ac-a151-365b8120cb4c','歸雁','楊時','宋','宋诗','song-poetry','','[]','天末驚風急，江湖夜思長。',48,'全唐诗/poet.song.63000.json','["天末驚風急，江湖夜思長。", "悲鳴愁絕塞，接翼冒清霜。", "澤岸多繒弋，雲間乏稻粱。", "茫然栖息地，飲啄欲何傷。"]'),
('75f6262a-f553-4f8b-973e-6c14b0f3a577','感事','楊時','宋','宋诗','song-poetry','','[]','世事浮雲薄，勞生一夢長。',48,'全唐诗/poet.song.63000.json','["世事浮雲薄，勞生一夢長。", "散材依櫟社，幽意慕濠梁。", "風激鷹鸇迅，霜殘草木黄。", "投閒如有約，早晚問耕桑。"]'),
('60accad4-48df-43e5-9046-a5e07b43652b','過關山  其一','楊時','宋','宋诗','song-poetry','','[]','牢落關山路，年來倦往還。',48,'全唐诗/poet.song.63000.json','["牢落關山路，年來倦往還。", "長隨流梗泛，有愧白雲閒。", "親遠江天外，魂勞夢想間。", "泫然遊子淚，挹盡復汍瀾。"]'),
('50edf499-23eb-4587-91fa-e67a6047be2b','過關山  其二','楊時','宋','宋诗','song-poetry','','[]','歲律行將暮，飈風凌九垓。',48,'全唐诗/poet.song.63000.json','["歲律行將暮，飈風凌九垓。", "山深人寂寞，路遠馬虺隤。", "幽意從誰展，愁懷殢酒開。", "衰遲仍惜日，投晚獨徘徊。"]'),
('8b46782c-b047-4e4f-8f32-3a417768de92','晚泊遇雪  其一','楊時','宋','宋诗','song-poetry','','[]','向晚驚風急，飄零雪滿坰。',48,'全唐诗/poet.song.63000.json','["向晚驚風急，飄零雪滿坰。", "氣升雲羃羃，天遠月冥冥。", "寒色終無頼，豐年漫寄聲。", "餔糟吾不慣，彊醉復還醒。"]'),
('ba55c338-383d-4302-aedd-c0b805ac70ba','晚泊遇雪  其二','楊時','宋','宋诗','song-poetry','','[]','寒逼歸鴻急，悲鳴聲更哀。',48,'全唐诗/poet.song.63000.json','["寒逼歸鴻急，悲鳴聲更哀。", "舞風斜翳日，带月暗欺梅。", "平野光初合，陰雲凍不開。", "無聊還殢酒，顛倒盡餘盃。"]'),
('73a95c1f-3358-450e-a9e4-018dfe55a9f0','偶成','楊時','宋','宋诗','song-poetry','','[]','天遠何須問，勞生聽若何。',48,'全唐诗/poet.song.63000.json','["天遠何須問，勞生聽若何。", "犂鋤三畝足，栖息一枝多。", "白雪寧堪冒，清時只浪過。", "好尋明月影，醉舞自婆娑。"]'),
('3deb2da7-341d-4e8a-a9c1-c21a6347186e','臨川驛偶成','楊時','宋','宋诗','song-poetry','','[]','冉冉朝仍暮，蕭條官舍幽。',48,'全唐诗/poet.song.63000.json','["冉冉朝仍暮，蕭條官舍幽。", "閉門三尺雪，觸物一虛舟。", "蟲蠹生涯盡，萍漂世事浮。", "尚思方技學，多病未能休。"]'),
('5a642be9-5451-428b-a6d9-6b36b3a4e8bb','除夜感懷  其一','楊時','宋','宋诗','song-poetry','','[]','歲律已云盡，思家日日深。',48,'全唐诗/poet.song.63000.json','["歲律已云盡，思家日日深。", "二年爲客恨，千里倚門心。", "節物羅樽俎，兒童學語音。", "眩然如在目，恍惚夢難尋。"]'),
('80fbbeff-d471-4102-a3c0-4fdac56b824c','除夜感懷  其二','楊時','宋','宋诗','song-poetry','','[]','愛日乖予願，親顔長在心。',48,'全唐诗/poet.song.63000.json','["愛日乖予願，親顔長在心。", "遠遊仍換歲，華髮想盈簪。", "永夜誰同席，殘盃憶共斟。", "相思空有淚，揮洒滿衣襟。"]'),
('d5e7d941-4a6c-4028-985b-c3a76fb1732d','臨川道上','楊時','宋','宋诗','song-poetry','','[]','風雨離山驛，斷橋危欲顛。',48,'全唐诗/poet.song.63000.json','["風雨離山驛，斷橋危欲顛。", "去心奔逸驥，行路上青天。", "雁序江湖樂，雲歸島嶼連。", "悠悠遠征客，千里獨茫然。"]'),
('5e77ca10-4393-46ec-ba09-ed3e40f27cd5','旅舍書事','楊時','宋','宋诗','song-poetry','','[]','懶拙乖時尚，支離與世殊。',48,'全唐诗/poet.song.63000.json','["懶拙乖時尚，支離與世殊。", "饋漿驚御寇，避席愧陽居。", "觸事紛難解，忘形色易鋤。", "不須修混沌，機械本來無。"]'),
('7d617b61-86dc-4aa6-aee5-dca1e2cf24c0','過清溪渡','楊時','宋','宋诗','song-poetry','','[]','天闊江銜雨，冥冥上客衣。',48,'全唐诗/poet.song.63000.json','["天闊江銜雨，冥冥上客衣。", "潭清魚可數，沙晚雁爭飛。", "川谷留雲氣，鵜鶘傍釣磯。", "飄零滄海客，期到一帆歸。"]'),
('00d81491-7808-4773-b5b6-ceb0caae5145','泛江至土坊','楊時','宋','宋诗','song-poetry','','[]','萬頃江湖遠，孤乘一葉船。',48,'全唐诗/poet.song.63000.json','["萬頃江湖遠，孤乘一葉船。", "雁飛雲外字，篷掩水中天。", "波靜櫓聲息，風微帆影偏。", "回環聊注目，浩蕩接清烟。"]'),
('7146a47b-5461-4e68-8d44-5ad5f045d0a4','秋日有懷寄從弟表民','楊時','宋','宋诗','song-poetry','','[]','羈旅吾方困，哀思汝正煩。',48,'全唐诗/poet.song.63000.json','["羈旅吾方困，哀思汝正煩。", "望雲愁雁序，回首憶鴒原。", "北圃蔬還盛，東軒菊想繁。", "飄零不相見，沾灑獨忘言。"]'),
('eb322679-111c-4150-b6e7-ad2c4aac4389','和潭倅張朝請行縣言懷','楊時','宋','宋诗','song-poetry','','[]','夾道旌麾動，陰霾萬里開。',48,'全唐诗/poet.song.63000.json','["夾道旌麾動，陰霾萬里開。", "霜迎威令肅，春逐馬蹄來。", "幽壑光初滿，寒荄暖自回。", "仰窺嵩華質，曾未施纖埃。"]'),
('8339062b-41ed-40d0-aa6a-039dd270cee7','又用前韵和早梅二首  其一','楊時','宋','宋诗','song-poetry','','[]','楚國春歸早，寒梅處處開。',48,'全唐诗/poet.song.63000.json','["楚國春歸早，寒梅處處開。", "月和清艷冷，天與靚粧來。", "東閣詩魂動，南枝歲律回。", "蕭然冰雪態，無處覓輕埃。"]'),
('4be9ff30-3394-400f-bbb8-54d112540fe0','又用前韵和早梅二首  其二','楊時','宋','宋诗','song-poetry','','[]','星馭經行處，梅花忽已開。',48,'全唐诗/poet.song.63000.json','["星馭經行處，梅花忽已開。", "只疑春信早，先擁使旌來。", "嫩萼紅初破，寒柯綠未回。", "凌霜半含月，皎皎絕纖埃。"]'),
('22c80a03-6750-4678-ad73-3bc39e783e1c','感事  其一','楊時','宋','宋诗','song-poetry','','[]','邊徼無虞日，王師討弗庭。',48,'全唐诗/poet.song.63000.json','["邊徼無虞日，王師討弗庭。", "收功誇廟算，行險毒生靈。", "川谷旌麾暗，風塵戰血腥。", "寂寥歸馬日，目斷華陽坰。"]'),
('140beea4-f94d-469a-be8e-f9887ba00a64','感事  其二','楊時','宋','宋诗','song-poetry','','[]','虎士冰河側，日聞刁斗驚。',48,'全唐诗/poet.song.63000.json','["虎士冰河側，日聞刁斗驚。", "氣吞沙漠盡，風蕩賊巢傾。", "關塞長年戍，邊塵幾日清。", "太平陳朽富，一旅百夫耕。"]'),
('0cfec262-1331-481a-9b61-bea837ea7526','泗上  其一','楊時','宋','宋诗','song-poetry','','[]','淮口平沙漲，檣烏向日斜。',48,'全唐诗/poet.song.63000.json','["淮口平沙漲，檣烏向日斜。", "微雲變蒼狗，輕浪蹙浮花。", "風勁回飛雁，林喧集暝鴉。", "河流應未閉，遲我到京華。"]'),
('20d6019d-26b4-4040-b8bf-b9d1c845aaa4','泗上  其二','楊時','宋','宋诗','song-poetry','','[]','鬢蓬凋欲盡，岸幘任敧斜。',48,'全唐诗/poet.song.63000.json','["鬢蓬凋欲盡，岸幘任敧斜。", "病覺寒裘重，慵嫌細字花。", "凍雲穿曉日，晴樹繞飛鴉。", "老大驚遲暮，飄零惜歲華。"]'),
('2c99b46f-dfee-4644-8254-dac17eb1922e','泗上  其三','楊時','宋','宋诗','song-poetry','','[]','聞道河流閉，逢人每問津。',48,'全唐诗/poet.song.63000.json','["聞道河流閉，逢人每問津。", "天高雲羃羃，風細水鱗鱗。", "未種江陵橘，空思千里蓴。", "且邀明月伴，相對解綸巾。"]'),
('8639da15-383f-4bfa-9a26-22b392d88d4a','出京','楊時','宋','宋诗','song-poetry','','[]','旅泊驚秋意，塵沙變客衣。',48,'全唐诗/poet.song.63000.json','["旅泊驚秋意，塵沙變客衣。", "明星爛河漢，殘月暗簾帷。", "風柳斜斜轉，雲帆片片飛。", "窮愁添別病，衰晚意多違。"]'),
('e0af0fdd-9045-483d-84d8-2a64bd4f2e35','言溪早起','楊時','宋','宋诗','song-poetry','','[]','短日催征轡，聽雞踏曉霜。',48,'全唐诗/poet.song.63000.json','["短日催征轡，聽雞踏曉霜。", "遠山頻入望，薄酒漫搜腸。", "湘浦蓴絲滑，吳淞鱠縷長。", "何時一疏放，把釣卧滄浪。"]'),
('60c8fb6e-afbc-4d15-a8a0-535d067c00bb','漢坂舟行','楊時','宋','宋诗','song-poetry','','[]','曲岸通幽徑，疏籬映竹斜。',48,'全唐诗/poet.song.63000.json','["曲岸通幽徑，疏籬映竹斜。", "塢深藏吠犬，林薄露人家。", "石瀨魚偏美，鄰村酒易賒。", "祇應雲水富，自是一生涯。"]'),
('61d95858-1123-4d17-b49a-27ebd1ef1499','席太君挽辭二首  其一','楊時','宋','宋诗','song-poetry','','[]','賢配無前古，傳家有子賢。',48,'全唐诗/poet.song.63000.json','["賢配無前古，傳家有子賢。", "四靈來薦瑞，一鶚已摩天。", "蒿里迷長夜，悲笳慘暮烟。", "蕭蕭原上路，猶想駕雲軿。"]'),
('6855cbc8-08cd-4c5d-8c4c-51463d3b017a','席太君挽辭二首  其二','楊時','宋','宋诗','song-poetry','','[]','稟粹猗蘭秀，來嬪洛水濱。',48,'全唐诗/poet.song.63000.json','["稟粹猗蘭秀，來嬪洛水濱。", "一窺識公輔，三徙得儒真。", "畫翣流雲氣，松阡卧石麟。", "哀榮今日事，誰復繼前塵。"]'),
('01fc4a03-591a-4c85-a338-3e56d0cde20a','湘君祠','楊時','宋','宋诗','song-poetry','','[]','鳥鼠荒庭暮，秋花覆短牆。',48,'全唐诗/poet.song.63000.json','["鳥鼠荒庭暮，秋花覆短牆。", "蒼梧雲不斷，湘水意何長。", "澤岸蒹葭綠，籬根草樹黄。", "蕭蕭竹間淚，千古一悲傷。"]'),
('d6012c45-21bc-4f8e-a168-38e683b8a7e5','鄒公輓辭二首  其一','楊時','宋','宋诗','song-poetry','','[]','一伏青蒲上，三年瘴海濱。',48,'全唐诗/poet.song.63000.json','["一伏青蒲上，三年瘴海濱。", "泉甘不出戶，客醉豈無神。", "報國心長在，知恩志未伸。", "追懷垂絕語，空有淚盈巾。"]'),
('9d32db65-1184-441a-8f7d-f88b84921b52','鄒公輓辭二首  其二','楊時','宋','宋诗','song-poetry','','[]','舊德今誰在，凋零已不多。',48,'全唐诗/poet.song.63000.json','["舊德今誰在，凋零已不多。", "雲天開日月，陸海自風波。", "空歎與齡夢，難留曳杖歌。", "平生濟川意，無處問施羅。"]'),
('d85809dc-8a44-46e6-a9c9-1cb85cd8338e','登桐君祠堂','楊時','宋','宋诗','song-poetry','','[]','霜染溪楓葉葉丹，翠鱗浮動汐波閒。',64,'全唐诗/poet.song.63000.json','["霜染溪楓葉葉丹，翠鱗浮動汐波閒。", "盤盤路轉千峰表，冉冉雲扶兩腋間。", "掠水輕鷗晴自戲，凌風飛雁暮爭還。", "結廬姓字無人會，靜對庭陰一解顔。"]'),
('46aa71e2-f746-4e82-a972-3d0f4d23c015','巖松','楊時','宋','宋诗','song-poetry','','[]','婆娑千尺倚巖巔，隠隠虬姿拂遠烟。',64,'全唐诗/poet.song.63000.json','["婆娑千尺倚巖巔，隠隠虬姿拂遠烟。", "尤喜地靈泉脈潤，獨愁天闊晝陰偏。", "孤根礙石盤彌固，直幹凌霜老益堅。", "臃腫不須逢匠伯，散材終得盡天年。"]'),
('635bfc56-5883-4db3-8dda-80bc627d651e','和鄭商老下第','楊時','宋','宋诗','song-poetry','','[]','雨餘新惹一番愁，展轉衾寒客思悠。',64,'全唐诗/poet.song.63000.json','["雨餘新惹一番愁，展轉衾寒客思悠。", "獻璞又添今日恨，登科空負昔人羞。", "林泉水石君先到，京國風塵我尚留。", "若爲浮名苦憔悴，前春行釣巨鰲頭。"]'),
('2f2c6d30-8e56-424d-9048-e9a8e05b4003','潁昌西湖泛舟  其一','楊時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','扁舟乘興漫追尋，路轉河回入柳陰。',64,'全唐诗/poet.song.63000.json','["扁舟乘興漫追尋，路轉河回入柳陰。", "拂面落花春事盡，避人幽鳥野情深。", "慚無健思供吟筆，頼有寒光映客心。", "日暮倚風歸棹急，一鈎新月掛瑶岑。"]'),
('059ecadf-3119-4f41-8212-b178ecc56e24','潁昌西湖泛舟  其二','楊時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春過鶑花無處尋，移舟行近古城陰。',64,'全唐诗/poet.song.63000.json','["春過鶑花無處尋，移舟行近古城陰。", "褰衣水上收殘片，傾耳枝間覓好音。", "山隔曲堤迷遠近，魚跳文藻亂浮沉。", "飄然自得江湖趣，陡起歸與萬里心。"]'),
('70dceea4-69c3-4ddf-b403-7b52808206cf','送丁季深','楊時','宋','宋诗','song-poetry','','[]','烟含疏柳綠蒙茸，杏頰桃英入眼紅。',64,'全唐诗/poet.song.63000.json','["烟含疏柳綠蒙茸，杏頰桃英入眼紅。", "邂逅與君逢臘雪，飄零獨我過春風。", "空愁轉轂音塵遠，且寄離懷笑語中。", "後夜月明人寂寂，相思那復一樽同。"]'),
('d8b17df9-0f22-4f04-8daa-02a02f90a74f','蘄州早起','楊時','宋','宋诗','song-poetry','','[]','城頭雷動角聲哀，似共行人怨落梅。',64,'全唐诗/poet.song.63000.json','["城頭雷動角聲哀，似共行人怨落梅。", "欲報晨炊粱未熟，喚回殘夢眼驚開。", "霜清暗覺貂裘冷，月淡空令邑犬猜。", "倚杖起看風正慘，紫薇繚繞俯三台。"]'),
('80cb0eb9-8eb2-4eaf-90ca-0f941dd0c4b2','合江亭晚眺','楊時','宋','宋诗','song-poetry','','[]','倚杖鈎簾兩水間，晴光飛影上雕欄。',64,'全唐诗/poet.song.63000.json','["倚杖鈎簾兩水間，晴光飛影上雕欄。", "帆催畫鷁摶風去，雪吐銛鋒作劍攢。", "平野烟浮迷遠目，晚溪潮漲失前灘。", "騎鯨一往扶桑近，休問人間行路難。"]'),
('0f3ae290-cb63-4f4c-8f06-f0f83823d992','含雲晚歸寄真師','楊時','宋','宋诗','song-poetry','','[]','每扣禪關即晚歸，塵中回首萬緣非。',64,'全唐诗/poet.song.63000.json','["每扣禪關即晚歸，塵中回首萬緣非。", "不愁幻翳迷心地，且聽潮音振祖衣。", "歸路往來無別徑，夜光清徹有餘輝。", "虎溪舊社知重約，陶令如今已息機。"]'),
('21b7a314-8e74-42ac-bd85-46e3468b6982','遊玉華洞','楊時','宋','宋诗','song-poetry','','[]','蒼藤秀木遶空庭，疊石層巒擁畫屏。',64,'全唐诗/poet.song.63000.json','["蒼藤秀木遶空庭，疊石層巒擁畫屏。", "混沌鑿開幽竅遠，巨靈分破兩峰青。", "雲藏野色春長在，風入衣襟酒易醒。", "採玉遺蹤無處問，擬投簪紱學仙經。"]'),
('7795f74e-3d33-479c-a3c0-3885418c1f41','次韵思睿見寄','楊時','宋','宋诗','song-poetry','','[]','聖賢千古愧難攀，力學方憂敢自閒。',64,'全唐诗/poet.song.63000.json','["聖賢千古愧難攀，力學方憂敢自閒。", "顧我久拋聲迹外，慚君猶掛齒牙間。", "平生拙計心長在，解带高風志未還。", "捧檄于今非得已，漫勞魂夢遶溪山。"]'),
('566ecc95-98cd-4661-b2c9-3c7f0d8dee43','次韵蔡武子書懷','楊時','宋','宋诗','song-poetry','','[]','放形鋤色恐成光，斲堊能令鼻不傷。',64,'全唐诗/poet.song.63000.json','["放形鋤色恐成光，斲堊能令鼻不傷。", "自信放魚真得計，却憐挾策亦亡羊。", "刃投有間多餘地，語到無言輒自忘。", "擾擾世紛何足問，松窗終日獨彷徨。"]'),
('b44aaffd-e85b-478f-83f6-7c8a7aeba013','感懷寄鄉友','楊時','宋','宋诗','song-poetry','','[]','漫浪人間已十年，簿書擾擾日羈纏。',64,'全唐诗/poet.song.63000.json','["漫浪人間已十年，簿書擾擾日羈纏。", "朱公漫有千金璧，季子初無二頃田。", "籬下蹲鴟餘晚實，雲間紫鼈奮新拳。", "淹留寸祿空回首，一望鄉關一悵然。"]'),
('a0cebaae-0598-4c7a-bb5c-752c276cfd90','贈致政楊孟堅宣德  其一','楊時','宋','宋诗','song-poetry','','[]','子雲論薦有王音，陸賈年來老境侵。',64,'全唐诗/poet.song.63000.json','["子雲論薦有王音，陸賈年來老境侵。", "自守一官歷三世，退令諸子分千金。", "平生器業成幽夢，白首功名負壯心。", "頼有新詩輕萬戶，未須投紱嘆堙沉。"]'),
('7d0ebaa1-0c89-4ea6-a434-6d2081b5eda0','贈致政楊孟堅宣德  其二','楊時','宋','宋诗','song-poetry','','[]','廣文官冷竟誰憐，空負才名四十年。',64,'全唐诗/poet.song.63000.json','["廣文官冷竟誰憐，空負才名四十年。", "蕭散欲尋濠上侶，飛揚還作酒中仙。", "龍章繡紱榮何在，鶴氅綸巾靜自便。", "遥憶瀨溪風物好，勝遊應不愧斜川。"]'),
('ebf674db-ea0c-4c7f-94ae-f7c91ce25841','寄湘鄉令張世賢','楊時','宋','宋诗','song-poetry','','[]','身游羿彀偶相逢，安得初終若駏蛩。',64,'全唐诗/poet.song.63000.json','["身游羿彀偶相逢，安得初終若駏蛩。", "道學未容窺閫奧，吏師應許叩鄰封。", "蕭條此意君誰問，落拓微官我更慵。", "盧白回旋真戲事，傍觀無用氣填胸。"]'),
('39cce179-0e26-4aac-a2a1-487e56575508','縣齋書事','楊時','宋','宋诗','song-poetry','','[]','朱顔凋盡鬢䰐鬖，世路低回老益慚。',64,'全唐诗/poet.song.63000.json','["朱顔凋盡鬢䰐鬖，世路低回老益慚。", "偶影獨游聊自適，談書不輟竟何堪。", "神爐默默金徒踴，螘蛭紛紛夢正酣。", "誤把此身攖世網，自纏徽纆信如蠶。"]'),
('87f55c22-9416-40f1-80f6-7b15795a44ee','次韵錢帳計','楊時','宋','宋诗','song-poetry','','[]','駸駸羲馭定難羈，過隙跳丸日夜馳。',64,'全唐诗/poet.song.63000.json','["駸駸羲馭定難羈，過隙跳丸日夜馳。", "但見光陰如掣電，却尋稽覽已當期。", "飛黄汗血宜千里，秋鶚乘風此一時。", "芝草鳳凰真美瑞，清名應有退之知。"]'),
('ac30fdab-541e-465f-b2b6-e6d9c5a58e0e','和張倅行縣','楊時','宋','宋诗','song-poetry','','[]','江浮疊巘弄清輝，雲外冥鴻江上歸。',64,'全唐诗/poet.song.63000.json','["江浮疊巘弄清輝，雲外冥鴻江上歸。", "擊目自多幽興在，揮毫時見彩牋飛。", "應愁零雨侵星駕，好爲援戈却晚暉。", "帝室正須調鼎鼐，勒移寄語不須譏。"]'),
('0c60f8e6-bd75-4479-8312-8c2a05fce041','遊光大寺示犀老','楊時','宋','宋诗','song-poetry','','[]','山橫杳靄有無中，疊觀層臺一梵宮。',64,'全唐诗/poet.song.63000.json','["山橫杳靄有無中，疊觀層臺一梵宮。", "萬軸琅函方杜口，數聲啼鳥正談空。", "溪雲抱影侵行屐，香篆飛烟襲晚風。", "薄宦羈人如接摺，自慚來往苦匆匆。"]'),
('f8b7519b-56b8-4901-abc4-2212577690ea','王簿清輝亭','楊時','宋','宋诗','song-poetry','','[]','黛染烟螺拂檻低，抱城流水綠逶迤。',64,'全唐诗/poet.song.63000.json','["黛染烟螺拂檻低，抱城流水綠逶迤。", "澄瀾碎影搖青鏡，斜日流峰隠半規。", "坐上盈樽無俗客，壁間照夜有新詩。", "登臨已動忘歸興，况復清談足解頤。"]'),
('689ea6fc-cfe4-49d5-9e45-975552021490','寄長沙簿孫昭遠','楊時','宋','宋诗','song-poetry','','[]','陽城衰晚拙催科，闔寢空慚罪亦多。',64,'全唐诗/poet.song.63000.json','["陽城衰晚拙催科，闔寢空慚罪亦多。", "祭竈請鄰君自適，載醪祛惑我誰過。", "猗猗庭有蘭堪佩，寂寂門無雀可羅。", "歸去好尋溪上侶，爲投纓紱換漁簑。"]'),
('3680b203-7c60-4f0a-961e-1a12bcf2d15e','安禮以宏詞見勉奉寄','楊時','宋','宋诗','song-poetry','','[]','吏部文章世所珍，終慚無補費精神。',64,'全唐诗/poet.song.63000.json','["吏部文章世所珍，終慚無補費精神。", "浮名膚外增餘贅，薄宦戈頭寄此身。", "養志吾方同邴曼，談書誰復問山賓。", "自憐坐頃三遺矢，衰晚那能用楚人。"]'),
('34c9d084-5b08-4927-aa7d-223e570e3723','秋晚偶成二首  其一','楊時','宋','宋诗','song-poetry','','[]','纖纖晚雨洗秋容，庭樹蕭然策策風。',64,'全唐诗/poet.song.63000.json','["纖纖晚雨洗秋容，庭樹蕭然策策風。", "萬籟自鳴羣物外，四時長在不言中。", "坐臨流水襟懷冷，卧對浮雲世慮空。", "寂寞一廛吾自適，客嘲從更議揚雄。"]'),
('0738091c-db2a-4ee0-bd5c-ba8a02b29d07','秋晚偶成二首  其二','楊時','宋','宋诗','song-poetry','','[]','風飄淅瀝鬧諸鄰，却掃衡門溷世塵。',64,'全唐诗/poet.song.63000.json','["風飄淅瀝鬧諸鄰，却掃衡門溷世塵。", "天氣清明秋意態，夜光浮動月精神。", "流年漸覺侵雙鬢，生理從來付大鈞。", "臨水便同濠濮趣，翛然魚鳥自親人。"]'),
('878cc104-e0bc-432d-a414-9f8f8bdadab0','席上別蔡安禮','楊時','宋','宋诗','song-poetry','','[]','故里相看眼暫明，一尊聊此話平生。',64,'全唐诗/poet.song.63000.json','["故里相看眼暫明，一尊聊此話平生。", "杜陵苦被微官縛，元亮今爲世網攖。", "長路關山吾北去，春風梅嶺子南征。", "結鄰莫負當時約，早晚滄浪共濯纓。"]');
